window.__ARXIV_DATA__ = {"papers":[{"id":"2606.19341v1","title":"Native Active Perception as Reasoning for Omni-Modal Understanding","abstract":"Passive models for long video understanding typically rely on a \"watch-it-all\" paradigm, processing frames uniformly regardless of query difficulty, causing computational cost to grow with video duration. Although interactive frameworks have emerged, they often rely on global pre-scanning, and their context cost still scales with video length. We propose OmniAgent, the first native omni-modal agent that formulates video understanding as a POMDP-based iterative Observation-Thought-Action cycle. OmniAgent executes on-demand actions to selectively distill audio-visual cues into a persistent textual memory, effectively decoupling reasoning complexity from raw video duration. To operationalize this, we introduce (1) Agentic Supervised Fine-Tuning to bootstrap native active perception via best-of-N trajectory synthesis with dual-stage quality control, and (2) Agentic Reinforcement Learning with TAURA (Turn-aware Adaptive Uncertainty Rescaled Advantage), which leverages turn-level entropy to steer credit assignment toward pivotal discovery turns. Crucially, OmniAgent exhibits positive test-time scaling, where performance improves as the number of reasoning turns increases, validating the efficacy of active perception. Empirical results across ten benchmarks (e.g., VideoMME, LVBench) demonstrate that OmniAgent achieves state-of-the-art performance among open-source models. Notably, on LVBench, our 7B agent outperforms the 10$\\times$ larger Qwen2.5-VL-72B (50.5% vs. 47.3%).","authors":["Zhenghao Xing","Ruiyang Xu","Yuxuan Wang","Jinzheng He","Ziyang Ma","Qize Yang","Yunfei Chu","Jin Xu","Junyang Lin","Chi-Wing Fu","Pheng-Ann Heng"],"published":"2026-06-17T17:59:56Z","updated":"2026-06-17T17:59:56Z","abstract_url":"https://arxiv.org/abs/2606.19341v1","html_url":"https://arxiv.org/html/2606.19341v1","pdf_url":"https://arxiv.org/pdf/2606.19341v1.pdf","matched_keywords":["video","agent"],"source_used":"html","source_text_chars":90455,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent 相关；摘要显示其主要贡献为：Passive models for long video understanding typically rely on a \"watch-it-all\" paradigm, processing frames uniformly regardless of query difficulty, causing computational cost to grow with video duration. Although interactive frameworks have emerged, they oft...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:52+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19338v1","title":"Beyond the Current Observation: Evaluating Multimodal Large Language Models in Controllable Non-Markov Games","abstract":"Deploying multimodal foundation models as closed-loop policies increasingly requires conditioning actions on observations that are no longer visible. However, existing benchmarks either expose the full state, conflate hidden-state reconstruction with other agent skills, or test recall only after an episode has ended. We introduce RNG-Bench (Reconstructive Non-Markov Games), a benchmark suite designed to isolate a base model's ability to reconstruct past observations and act on them during multi-step interaction. RNG-Bench includes two complementary games: Matching Pairs, where card identities briefly revealed at specific locations must later be recalled, and 3D Maze, where egocentric views must be integrated into a spatial map. Both games are evaluated under a unified harness with three controlled difficulty axes: grid size, visual pattern, and observation modality. The benchmark further introduces a head-to-head duel protocol to control for instance-level variance and a Memory Gap metric that disentangles forgetting from poor action selection. The hardest configurations require contexts of roughly 128K tokens and 350 image inputs per episode, and remain far from saturated by frontier MLLMs. Memory Gap analysis shows that most residual errors stem from forgetting earlier observations rather than from suboptimal decision making. Finally, fine-tuning Qwen3.5-9B on optimal-policy rollouts and filtered model demonstrations improves performance on RNG-Bench and transfers to existing benchmarks without degrading general multimodal capability.","authors":["Shengyuan Ding","Xilin Wei","Xinyu Fang","Haodong Duan","Dahua Lin","Jiaqi Wang","Yuhang Zang"],"published":"2026-06-17T17:59:34Z","updated":"2026-06-17T17:59:34Z","abstract_url":"https://arxiv.org/abs/2606.19338v1","html_url":"https://arxiv.org/html/2606.19338v1","pdf_url":"https://arxiv.org/pdf/2606.19338v1.pdf","matched_keywords":["3d","agent","instance","multimodal"],"source_used":"html","source_text_chars":97802,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent, instance, multimodal 相关；摘要显示其主要贡献为：Deploying multimodal foundation models as closed-loop policies increasingly requires conditioning actions on observations that are no longer visible. However, existing benchmarks either expose the full state, conflate hidden-state reconstruction with other ag...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:52+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19333v1","title":"Do as I Do: Dexterous Manipulation Data from Everyday Human Videos","abstract":"How can we scalably generate data for robotic manipulation, especially on human-like platforms such as dexterous multi-fingered hands? Learning from human videos has recently emerged as a likely answer to this question. However, difficulties in estimating hand-object interaction and crossing the human-to-robot embodiment gap have hindered the adoption of abundant monocular RGB-only human videos as the primary source of robot manipulation data. In this work, we present DO AS I DO, an algorithm to reconstruct and retarget monocular RGB human videos to multi-fingered dexterous robotic hands. DO AS I DO reconstructs hand-object interactions from various egocentric and exocentric in-the-wild video sources. The algorithm then retargets these hand-object interaction estimates into a sequence of actions executable in the real world, yielding robot-complete manipulation data from disparate human videos. Overall, DO AS I DO outperforms previous state of the art in estimating hand-object interactions and extracting dexterous manipulation trajectories from RGB videos, as we show in experiments on datasets with ground truths and on a dataset of video clips collected online. Our experiments enable us to propose an efficacy playbook for practitioners collecting human data for manipulation.","authors":["Bhawna Paliwal","Haritheja Etukuru","William Liang","Pieter Abbeel","Nur Muhammad Mahi Shafiullah","Jitendra Malik"],"published":"2026-06-17T17:57:34Z","updated":"2026-06-17T17:57:34Z","abstract_url":"https://arxiv.org/abs/2606.19333v1","html_url":"https://arxiv.org/html/2606.19333v1","pdf_url":"https://arxiv.org/pdf/2606.19333v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":64866,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：How can we scalably generate data for robotic manipulation, especially on human-like platforms such as dexterous multi-fingered hands? Learning from human videos has recently emerged as a likely answer to this question. However, difficulties in estimating han...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:52+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19316v1","title":"NeuMesh++: Towards Versatile and Efficient Volumetric Editing with Disentangled Neural Mesh-based Implicit Field","abstract":"Recently neural implicit rendering techniques have evolved rapidly and demonstrated significant advantages in novel view synthesis and 3D scene reconstruction. However, existing neural rendering methods for editing purposes offer limited functionalities, e.g., rigid transformation and category-specific editing. In this paper, we present a novel mesh-based representation by encoding the neural radiance field with disentangled geometry, texture, and semantic codes on mesh vertices, which empowers a set of efficient and comprehensive editing functionalities, including mesh-guided geometry editing, designated texture editing with texture swapping, filling and painting operations, and semantic-guided editing. To this end, we develop several techniques including a novel local space parameterization to enhance rendering quality and training stability, a learnable modification color on vertex to improve the fidelity of texture editing, a spatial-aware optimization strategy to realize precise texture editing, and a semantic-aided region selection to ease the laborious annotation of implicit field editing. Extensive experiments and editing examples on both real and synthetic datasets demonstrate the superiority of our method on representation quality and editing ability. Project page: https://zju3dv.github.io/neumeshplusplus/","authors":["Chong Bao","Yuan Li","Bangbang Yang","Yujun Shen","Hujun Bao","Zhaopeng Cui","Yinda Zhang","Guofeng Zhang"],"published":"2026-06-17T17:39:21Z","updated":"2026-06-17T17:39:21Z","abstract_url":"https://arxiv.org/abs/2606.19316v1","html_url":"https://arxiv.org/html/2606.19316v1","pdf_url":"https://arxiv.org/pdf/2606.19316v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":96651,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Recently neural implicit rendering techniques have evolved rapidly and demonstrated significant advantages in novel view synthesis and 3D scene reconstruction. However, existing neural rendering methods for editing purposes offer limited functionalities, e.g....","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19277v1","title":"A Unified Framework for Efficient Remote Sensing Visual Question Answering: Adapting Dual, Hybrid, and Encoder-Decoder Architectures","abstract":"Visual Question Answering (VQA) in the Remote Sensing (RS) domain presents unique challenges due to the high resolution, multi scale object distribution, and semantic complexity of aerial imagery. While general domain Foundation Models have achieved remarkable success, their direct application to RSVQA is hindered by massive domain shifts and the computationally prohibitive nature of full fine tuning. This study presents a comparative analysis of RS Adapter, a Parameter Efficient Fine Tuning (PEFT) strategy, applied across three distinct Vision Language Model (VLM) architectures: the Dual Encoder CLIP, the Encoder Decoder BLIP, and the Hybrid FLAVA. We introduce a unified architectural surgery pipeline that injects lightweight bottleneck adapters into the attention and MLP layers of frozen backbones, enabling rapid adaptation with less than 5 percent of trainable parameters. Experimental results on the high resolution RSVQA x dataset demonstrate that while all adapted models achieve convergence, the Hybrid FLAVA architecture offers a superior balance of multimodal reasoning and retrieval capabilities compared to its unimodal counterparts. Our findings establish a new baseline for resource efficient VQA in disaster assessment and urban monitoring.","authors":["Timothy Agboada","Shikha Chandel","Yadav Raj Ghimire","Leila Hashemi-Beni"],"published":"2026-06-17T16:52:26Z","updated":"2026-06-17T16:52:26Z","abstract_url":"https://arxiv.org/abs/2606.19277v1","html_url":"https://arxiv.org/html/2606.19277v1","pdf_url":"https://arxiv.org/pdf/2606.19277v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"html","source_text_chars":23606,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, multimodal 相关；摘要显示其主要贡献为：Visual Question Answering (VQA) in the Remote Sensing (RS) domain presents unique challenges due to the high resolution, multi scale object distribution, and semantic complexity of aerial imagery. While general domain Foundation Models have achieved remarkabl...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19259v1","title":"A Multi-Domain Benchmark for Detecting AI-Generated Text-Rich Images from GPT-Image-2","abstract":"Text-rich images often contain privacy-sensitive, transactional, or decision-relevant information. As recent multimodal image generation models become increasingly capable of synthesizing realistic textual content and structured visual designs, detecting AI-generated text-rich images has become an important challenge for digital trust and content authenticity. Existing benchmarks, however, largely focus on object-centric images and provide limited coverage of scenarios where textual semantics and layout organization are central. In this paper, we introduce a multi-domain benchmark for detecting text-rich images generated by OpenAI's GPT Image 2. The benchmark contains 8,602 images across six representative categories: commercial posters, infographics, academic posters, receipts, tables, and UI screenshots. Using this benchmark, we evaluate five representative AI-generated image detectors in a zero-shot setting and analyze their overall, category-wise, and post-processing robustness. Our results show that detector performance is highly domain-dependent: methods that perform well in some categories often fail on others, and even the strongest conventional detector exhibits severe sensitivity to JPEG compression. We further conduct an exploratory evaluation with a multimodal vision-language model, revealing both its promise and its limitations on structured formats. These findings highlight the need for text- and layout-aware detection methods for modern AI-generated images. Our dataset is released at XXX.","authors":["Yijin Wang","Shuyi Wang","Wenhan Zhang","Yuqi Ouyang"],"published":"2026-06-17T16:37:16Z","updated":"2026-06-17T16:37:16Z","abstract_url":"https://arxiv.org/abs/2606.19259v1","html_url":"https://arxiv.org/html/2606.19259v1","pdf_url":"https://arxiv.org/pdf/2606.19259v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":44268,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Text-rich images often contain privacy-sensitive, transactional, or decision-relevant information. As recent multimodal image generation models become increasingly capable of synthesizing realistic textual content and structured visual designs, detecting AI-g...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19258v1","title":"CABLE: Cloud-Assisted Bandwidth-efficient LMM-based Encoding for V2X Systems","abstract":"Cloud-hosted large multimodal models (LMMs) can provide strong open-vocabulary perception for Vehicle-to-Everything systems, but naively transmitting full-resolution frames from edge to cloud causes severe communication overhead and high cloud-side prefill latency. We present CABLE, a cloud-assisted bandwidth-efficient LMM-based encoding framework for edge-cloud perception. CABLE propagates the previous cloud segmentation mask on the edge using ego-motion compensation, refines it with residual-motion cues, and consolidates disconnected regions via a corridor envelope to form a robust region of interest (ROI). Only ROI-masked images are uploaded, while the cloud segmentation output is fed back as the prior for the next frame, forming a mask-to-ROI-to-LMM feedback loop. Experiments on five datasets (nuScenes, WOD-ZB, Waymo, KITTI, and CADC) show consistent communication savings while largely preserving perception, achieving $73$--$87\\%$ ROI pixel-coverage reduction with $5$--$8\\times$ estimated LMM prefill speedup at a modest detection-quality trade-off relative to full-frame inference.","authors":["Haohua Que","Zhipeng Bao","Qianyi Wu","Handong Yao"],"published":"2026-06-17T16:35:23Z","updated":"2026-06-17T16:35:23Z","abstract_url":"https://arxiv.org/abs/2606.19258v1","html_url":"https://arxiv.org/html/2606.19258v1","pdf_url":"https://arxiv.org/pdf/2606.19258v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":46790,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Cloud-hosted large multimodal models (LMMs) can provide strong open-vocabulary perception for Vehicle-to-Everything systems, but naively transmitting full-resolution frames from edge to cloud causes severe communication overhead and high cloud-side prefill la...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19253v1","title":"OneCanvas: 3D Scene Understanding via Panoramic Reprojection","abstract":"Existing approaches to 3D scene understanding in Vision-Language Models (VLMs) either rely on complex, model-specific geometry encoders or large training budgets in pursuit of spatial reasoning. Instead, OneCanvas aggregates patch features from all views onto a single equirectangular panoramic canvas. Namely, each patch is unprojected to a 3D world coordinate using its depth and camera pose, then placed on the canvas at the continuous longitude and latitude of that point as seen from the canvas origin, with no rasterization or aggregation across overlapping views. A 3D position embedding of the patch's metric coordinates is added to its feature, restoring the depth lost when collapsing the world position to an angular canvas coordinate. Patches from all frames thus share one spatial coordinate system with no fusion or major architectural modifications of the backbone. The pretrained VLM consumes this representation as if it were an ordinary image. Because the canvas can be centered on any pose of interest, the same representation directly supports situated reasoning from a specific viewpoint, a common requirement in robotics and embodied AI. Thanks to this representation, we can also introduce a spatial pretraining curriculum: by procedurally placing patch features of objects, drawn from real images, at chosen 3D world positions on an otherwise empty canvas, we generate on-the-fly supervision spanning a broad range of spatial reasoning tasks, with answer distributions controlled to reduce spatial reasoning shortcuts. OneCanvas achieves state-of-the-art accuracy on SQA3D and VSI-Bench, and generalizes to out-of-distribution data on SPBench, using an order of magnitude less training compute than the strongest competing methods.","authors":["Bartłomiej Baranowski","Dave Zhenyu Chen","Matthias Nießner"],"published":"2026-06-17T16:29:19Z","updated":"2026-06-17T16:29:19Z","abstract_url":"https://arxiv.org/abs/2606.19253v1","html_url":"https://arxiv.org/html/2606.19253v1","pdf_url":"https://arxiv.org/pdf/2606.19253v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":67342,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Existing approaches to 3D scene understanding in Vision-Language Models (VLMs) either rely on complex, model-specific geometry encoders or large training budgets in pursuit of spatial reasoning. Instead, OneCanvas aggregates patch features from all views onto...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19249v1","title":"Transformer Geometry Observatory TGO-I: Spectral Geometry Observatory","abstract":"Despite the widespread adoption of Vision Transformers (ViTs) and their success across numerous computer vision applications, the fundamental understanding of their dimensional and representational geometry remains relatively underexplored. To address this gap, we introduce Transformer Geometry Observatory (TGO), a systematic framework of experiments and analysis pipelines designed to investigate the representational geometry and dynamics of Vision Transformers. TGO-I, the first installment of the framework, focuses on the spectral geometry of ViT representations. Using a ViT-Small/16 model trained on ImageNet-100, we analyze Effective Rank, Stable Rank, Participation Ratio, Spectral Entropy, Spectral Flatness, Spectral Anisotropy, covariance structure, eigenspectra, and singular value spectra throughout training. Our results reveal a consistent increase in dimensional utilization, accompanied by decreasing anisotropy, increasing spectral entropy, increasing participation ratio, and progressively flatter eigenspectra. Contrary to the common intuition that training should concentrate information into a small number of dominant directions, we observe a progressive redistribution of variance across representational dimensions. This phenomenon is particularly pronounced in the final CLS token representation, which exhibits the highest effective dimensionality and lowest anisotropy within the network.","authors":["Kaustubh Kapil","Kishor P. Upla"],"published":"2026-06-17T16:26:59Z","updated":"2026-06-17T16:26:59Z","abstract_url":"https://arxiv.org/abs/2606.19249v1","html_url":"https://arxiv.org/html/2606.19249v1","pdf_url":"https://arxiv.org/pdf/2606.19249v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":33638,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Despite the widespread adoption of Vision Transformers (ViTs) and their success across numerous computer vision applications, the fundamental understanding of their dimensional and representational geometry remains relatively underexplored. To address this ga...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19215v1","title":"GUMP-Net: An interpretable model-data-driven intelligent algorithm for multi-class pelvic segmentation","abstract":"Pelvic segmentation is one of the most important and fundamental research problems in precise and intelligent diagnosis and treatment, as well as surgical planning and navigation for pelvic fractures. By combining an improved geodesic active contour model with deep neural networks, we propose GUMP-Net, an interpretable model-data-driven intelligent algorithm for multi-class pelvic segmentation, in which three network modules are designed to constitute the overall segmentation framework together: the object detection module for automatic level set initialization, the edge detector module for learning an anatomy-aware edge detector function and the iteration module for deep level set evolution. Leveraging the advantages of level set representation and deep learning, GUMP-Net shows more accurate, robust and consistent segmentation performance, especially in small training data situation, compared to the state-of-the-art methods. Extensive experiments on pelvic datasets demonstrate the rationality and effectiveness of the proposed algorithm. Further experiments extended to ankle dataset indicate broader applications to other anatomies. The proposed algorithm not only provides an efficient segmentation method for complex fracture reduction, but also gives an interpretable geometric perspective for understanding deep learning segmentation.","authors":["Liheng Wang","Yinghui Zhang","Licheng Zhang","Hailin Xu","Qiyong Cao","Chong Chen"],"published":"2026-06-17T15:52:34Z","updated":"2026-06-17T15:52:34Z","abstract_url":"https://arxiv.org/abs/2606.19215v1","html_url":"https://arxiv.org/html/2606.19215v1","pdf_url":"https://arxiv.org/pdf/2606.19215v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":64519,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Pelvic segmentation is one of the most important and fundamental research problems in precise and intelligent diagnosis and treatment, as well as surgical planning and navigation for pelvic fractures. By combining an improved geodesic active contour model wit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19195v1","title":"Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance","abstract":"While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-$λ$ Mix Interaction ($LλMI$) block. Comprising Local-$λ$ and Interactive-$λ$ modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a $>15\\times$ acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.","authors":["Kangsheng Duan","Ziyang Xu","Wenyu Liu","Xiaohu Ruan","Xiaoxin Chen","Xinggang Wang"],"published":"2026-06-17T15:35:38Z","updated":"2026-06-17T15:35:38Z","abstract_url":"https://arxiv.org/abs/2606.19195v1","html_url":"https://arxiv.org/html/2606.19195v1","pdf_url":"https://arxiv.org/pdf/2606.19195v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":90871,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; howe...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19184v1","title":"When AUC Misleads: Polarization-Aware Evaluation of Deepfake Detectors under Domain Shift","abstract":"Recent advances in generative AI, such as diffusion models and face-swapping tools, have enabled the creation of highly realistic deepfakes, leading to real-world harms including financial fraud and non-consensual explicit content. In response, deepfake detection has become an active research area, with recent methods increasingly focusing on improving generalization to unseen manipulations. This is typically evaluated using the Area Under the ROC Curve (AUC) measured separately across multiple datasets. However, such an evaluation fails to reflect real-world scenarios where detectors face a mixture of data sources and varying artifact types. To address this limitation, we introduce a novel metric, Cross-dataset AUC (Cross-AUC) that averages per-domain AUCs with a measure of prediction polarization for taking into account the robustness to domain shift. The polarization extent is quantified by the Wasserstein Distance between class score distributions. Cross-AUC not only assesses the generalization capabilities of deepfake detectors under domain shifts more realistically, but it is also interpretable as it better explains the reason behind a drop in performance. Experiments performed on seven benchmark datasets demonstrate its practical relevance.","authors":["Dat Nguyen","Cosmin Radoi","Romain Hermary","Marcella Astrid","Nesryne Mejri","Enjie Ghorbel","Djamila Aouada"],"published":"2026-06-17T15:24:06Z","updated":"2026-06-17T15:24:06Z","abstract_url":"https://arxiv.org/abs/2606.19184v1","html_url":"https://arxiv.org/html/2606.19184v1","pdf_url":"https://arxiv.org/pdf/2606.19184v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":90580,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Recent advances in generative AI, such as diffusion models and face-swapping tools, have enabled the creation of highly realistic deepfakes, leading to real-world harms including financial fraud and non-consensual explicit content. In response, deepfake detec...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19162v1","title":"The Reward Was in Your Data All Along: Correcting Flow Matching with Discriminator-Guided RL","abstract":"Score- and flow-matching models often rely on preference-based reinforcement learning for two purposes: aligning with subjective preferences and, surprisingly, recovering properties such as visual realism and coherent object structure that matching-based training is intended to learn from the data itself. We argue that this reflects a structural mismatch. Matching losses measure $\\ell_2$ regression error on the velocity or score field under training-time marginals, a proxy poorly aligned with the visual and semantic properties that determine sample quality at inference. Given a reward aligned with these properties, RL sidesteps the mismatch by evaluating the model on its own samples and following the reward landscape directly. The challenge is to obtain such a reward without relying on human preferences, which are expensive and conflate data realism with annotator inclinations. We propose Discriminator-Guided RL (DRL). DRL trains a discriminator to separate data from base-model samples in a pretrained representation space and uses its logit as the reward in KL-regularized RL. The pretrained space restricts the discriminator to perceptually meaningful directions, and the logit estimates the log-likelihood ratio between data and model, which is the optimal reward for targeting the data distribution. Across SiT, JiT, REPA, and RAE, DRL reduces guidance-free FID (e.g., $9.38 \\to 2.62$ on SiT) and semantic-space FD (e.g., $88.2 \\to 19.3$ on DINOv3 for SiT), with consistent gains across all backbones, and improves human-preference rewards without training on them. It also yields a better Pareto frontier between preference reward and image fidelity under subsequent preference-based post-training, increasing alignment while reducing low-level artifacts such as oversaturation and excessive brightness.","authors":["Nicolas Beltran-Velez","Felix Friedrich","Zhang Xiaofeng","Reyhane Askari-Hemmat","Xiaochuang Han","Adriana Romero-Soriano","Michal Drozdzal"],"published":"2026-06-17T15:01:33Z","updated":"2026-06-17T15:01:33Z","abstract_url":"https://arxiv.org/abs/2606.19162v1","html_url":"https://arxiv.org/html/2606.19162v1","pdf_url":"https://arxiv.org/pdf/2606.19162v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":261555,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Score- and flow-matching models often rely on preference-based reinforcement learning for two purposes: aligning with subjective preferences and, surprisingly, recovering properties such as visual realism and coherent object structure that matching-based trai...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19156v1","title":"Hand-4DGS: Feed-Forward 3D Gaussian Splatting for 4D Hand Reconstruction from Egocentric Videos","abstract":"Dynamic 3D hand reconstruction from egocentric videos is essential for next-generation computing platforms such as AR/VR and AI glasses. Despite its importance, most prior works focus either on multi-view 3D hand reconstruction or on 4D human body reconstruction. Egocentric 4D hand reconstruction remains challenging due to fast head motion, rapid hand dynamics, severe occlusions, and inherent ambiguity from single-view observations. To address these challenges, we introduce Hand-4DGS, the first feed-forward framework for reconstructing dynamic 4D hands directly from egocentric videos, enabling both fast (~60 FPS) inference and strong generalization. Our approach incorporates a mesh-guided representation for structural priors and temporal convolutions to model dynamic motion. We evaluate our framework on two challenging egocentric datasets, H2O and ARCTIC, and demonstrate significant improvements over baselines. Our method benefits from the generalization capability of feed-forward networks and effective 2D image supervision through Gaussian splatting, without requiring expensive 3D hand pose ground-truth annotations.","authors":["Jeongmin Bae","Seoha Kim","Marc Pollefeys","Mahdi Rad","Youngjung Uh","Taein Kwon"],"published":"2026-06-17T14:58:37Z","updated":"2026-06-17T14:58:37Z","abstract_url":"https://arxiv.org/abs/2606.19156v1","html_url":"https://arxiv.org/html/2606.19156v1","pdf_url":"https://arxiv.org/pdf/2606.19156v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"html","source_text_chars":58874,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, representation 相关；摘要显示其主要贡献为：Dynamic 3D hand reconstruction from egocentric videos is essential for next-generation computing platforms such as AR/VR and AI glasses. Despite its importance, most prior works focus either on multi-view 3D hand reconstruction or on 4D human body reconstruct...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19151v1","title":"The Market in the Model: Latent Diffusion as Neural Economy","abstract":"Valuable critique of generative image models within visual culture and the humanities has emphasized the role of datasets in shaping the images they produce. Yet, close studies of the ideological positions embedded into the mechanism of the models have been neglected, leaving them imagined as \"black boxes.\" In a bid to expand, rather than replace, dataset critique, this paper examines the mechanisms of the latent diffusion model in terms of the problems they were brought in to solve on behalf of computer vision engineers, and the decisions each component was tasked with automating. I interpret that ensemble through the histories of its parts and the theory of vision the system inscribes into every generated image. Drawing on Impett and Offert's notion of neural exchange value, I offer this analysis to argue that the model operates as a neural economy: a contained symbolic system that abstracts social communication into commensurable vectors as it transfers the social sphere into parcels for sale. Tracing the training and generation pipelines component by component reveals what each operation displaces, and how it further entrenches the logics of platform and attention economies over social communication. The paper warns that any critique fixated exclusively on copyright and commodity defenses risks reaffirming the very fetishism the model produces, and argues instead for centering social exchange.","authors":["Eryk Salvaggio"],"published":"2026-06-17T14:56:42Z","updated":"2026-06-17T14:56:42Z","abstract_url":"https://arxiv.org/abs/2606.19151v1","html_url":"https://arxiv.org/html/2606.19151v1","pdf_url":"https://arxiv.org/pdf/2606.19151v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":65106,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Valuable critique of generative image models within visual culture and the humanities has emphasized the role of datasets in shaping the images they produce. Yet, close studies of the ideological positions embedded into the mechanism of the models have been n...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19120v1","title":"Seeing Before Reasoning: Decoupling Perception and Reasoning for Shortcut-Resilient Multimodal On-Policy Self-Distillation","abstract":"On-policy self-distillation (OPSD) trains a model on its own rollouts and uses a frozen copy to provide dense token-level targets conditioned on a reference target. This works well for LLM reasoning, but a direct extension to multimodal large language models (MLLMs) can create a shortcut: the privileged target may guide tokens mainly based on the text reference target rather than the image. We propose ViGOS, a visually grounded OPSD framework for MLLM post-training. The student first writes a visual description and then reasons toward the final answer. For valid rollouts, an image-only perception teacher supervises the description, while a privileged reasoning teacher supervises the reasoning and final answer on the same student prefix. A reference teacher is used only for invalid rollouts to recover the output format. Across general vision-language, expert reasoning, visual math, spatial grounding, and visual-language-prior benchmarks, ViGOS keeps the main benefits of OPSD and improves image-grounded behavior in shortcut-prone settings.","authors":["Sihan Wang","Xiyao Liu","Lianqing Liu","Zhi Han"],"published":"2026-06-17T14:33:38Z","updated":"2026-06-17T14:33:38Z","abstract_url":"https://arxiv.org/abs/2606.19120v1","html_url":"https://arxiv.org/html/2606.19120v1","pdf_url":"https://arxiv.org/pdf/2606.19120v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":82387,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：On-policy self-distillation (OPSD) trains a model on its own rollouts and uses a frozen copy to provide dense token-level targets conditioned on a reference target. This works well for LLM reasoning, but a direct extension to multimodal large language models...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19100v1","title":"AMALIA-VL: A Native European Portuguese Open-Source Vision and Language Model","abstract":"Large Vision and Language Models (LVLMs) have advanced rapidly, yet European Portuguese (pt-PT) remains systematically underserved by existing open-source multimodal models, which either conflate it with Brazilian Portuguese or severely under-represent it in their training data mixes. We introduce AMALIA-VL, the first open-source instruction-tuned LVLM built natively for pt-PT, pairing a high-resolution vision encoder with dynamic image tiling and a fully open pt-PT-optimized language model via a learned connector. We contribute with a purposefully designed three-stage training process - vision-language alignment, general visual instruction tuning, and preference optimization - together with a pt-PT-centric multimodal data mix combining curated and translated public datasets with novel datasets that address the near-total absence of European Portuguese multimodal resources. Our evaluation shows that AMALIA-VL establishes a strong baseline for open-source pt-PT LVLMs.We will release model weights, training data, and construction pipelines along with machine-translated pt-PT evaluation benchmarks to help democratize pt-PT LVLM development.","authors":["Diogo Glória-Silva","João Cardeira","Manuel Letras da Luz","Afonso Simplício","Gonçalo Vinagre","Diogo Tavares","Rafael Ferreira","Inês Calvo","Inês Vieira","David Semedo","João Magalhães"],"published":"2026-06-17T14:11:41Z","updated":"2026-06-17T14:11:41Z","abstract_url":"https://arxiv.org/abs/2606.19100v1","html_url":"https://arxiv.org/html/2606.19100v1","pdf_url":"https://arxiv.org/pdf/2606.19100v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":41743,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Large Vision and Language Models (LVLMs) have advanced rapidly, yet European Portuguese (pt-PT) remains systematically underserved by existing open-source multimodal models, which either conflate it with Brazilian Portuguese or severely under-represent it in...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19097v1","title":"DVANet: Degradation-aware Visual-prior Alignment Network for Image Restoration","abstract":"All-in-One image restoration aims to develop a unified restoration framework for handling diverse degradation types. Existing end-to-end methods usually regard the restoration process as a black-box mapping, lacking an explicit optimization interpretation. Although deep unfolding provides an interpretable iterative modeling paradigm for image restoration, existing methods mostly rely on fixed degradation assumptions or predefined degradation information, making them difficult to adapt to unified restoration requirements under complex degradations and locally damaged content. This limitation restricts their performance in degradation suppression and structural detail recovery. To address these issues, this paper proposes DVANet, a deep unfolding network inspired by the half-quadratic splitting optimization algorithm, which formulates unified image restoration under complex degradations as a collaborative unfolding process between degradation-aware observation consistency and visual-prior-guided reconstruction. Specifically, in the degradation-aware observation consistency branch, a degradation representation module is employed to extract global degradation attributes and local degradation cues, and degradation-conditioned mapping is used to enhance the model's adaptability to different degradation types. In the visual-prior-guided reconstruction branch, DINOv3 is introduced to provide structural and semantic information as hierarchical visual priors, thereby complementing the missing structural information in damaged regions and improving detail recovery. Extensive experiments demonstrate that DVANet achieves superior or competitive performance on multi-scenario degradation and cross-domain image restoration tasks, showing favorable degradation adaptability and generalization ability.","authors":["Yanjie Tu","Qingsen Yan","Axi Niu","Tao Hu","Haokui Zhang","Jiantao Zhou"],"published":"2026-06-17T14:09:39Z","updated":"2026-06-17T14:09:39Z","abstract_url":"https://arxiv.org/abs/2606.19097v1","html_url":"https://arxiv.org/html/2606.19097v1","pdf_url":"https://arxiv.org/pdf/2606.19097v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":85225,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：All-in-One image restoration aims to develop a unified restoration framework for handling diverse degradation types. Existing end-to-end methods usually regard the restoration process as a black-box mapping, lacking an explicit optimization interpretation. Al...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19073v1","title":"Taming I2V models for Image HOI Editing: A Cognitive Benchmark and Agentic Self-Correcting Framework","abstract":"Current image editing methods excel at static attributes but fail at complex Human-Object Interactions (HOI), a critical challenge unaddressed by existing benchmarks that conflate HOI with static attributes, relying on global metrics incapable of simultaneously assessing dynamic interaction validity and entangled human-object pair preservation. Thus, we first introduce HOI-Edit, a comprehensive benchmark with three progressive cognitive levels, which features an automated metric HOI-Eval that reliably evaluates instance-level interaction by letting VLM Q&A after thinking with images containing grounded Human-Object pairs. Considering the task's essence of remodeling dynamic relationships, we benchmark Image-to-Video (I2V) models, finding them inherently suited for dynamic editing due to their temporal generation capabilities. Crucially, beyond superior performance, this capability provides a \"replay of the failure process,\" offering unique diagnosability into why errors occur. We thus propose SCPE (Self-Correcting Process Editing), a novel, agentic self-correcting framework that constrains the generation of I2V models through iteratively refined prompts, enabling the generated videos to more accurately present the target HOI. Extracted frames from these videos are the final editing results. On HOI-Edit, SCPE achieves performance competitive with state-of-the-art (SOTA) editing models like Nano Banana on interaction. Code is available at https://github.com/oceanflowlab/HOI-Edit.","authors":["Jiayi Gao","Qingchao Chen","Yuxin Peng","Yang Liu"],"published":"2026-06-17T13:44:26Z","updated":"2026-06-17T13:44:26Z","abstract_url":"https://arxiv.org/abs/2606.19073v1","html_url":"https://arxiv.org/html/2606.19073v1","pdf_url":"https://arxiv.org/pdf/2606.19073v1.pdf","matched_keywords":["video","agent","instance"],"source_used":"html","source_text_chars":75750,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, instance 相关；摘要显示其主要贡献为：Current image editing methods excel at static attributes but fail at complex Human-Object Interactions (HOI), a critical challenge unaddressed by existing benchmarks that conflate HOI with static attributes, relying on global metrics incapable of simultaneous...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19067v1","title":"Sensor Configuration Matters: A Systematic Evaluation of Multimodal SLAM on Quadruped Robots","abstract":"Autonomous navigation of quadrupedal robots in diverse environments fundamentally relies on resilient Simultaneous Localization and Mapping (SLAM). While visual-inertial SLAM has matured across wheeled, handheld, and aerial platforms, a critical evaluation gap remains regarding how hardware-level sensor configurations affect performance under the aggressive dynamics of legged locomotion. Quadrupeds introduce distinct embodiment-induced sensory challenges, including foot-impact shocks, high-frequency mechanical vibrations, and rapid angular rotations, which degrade standard perception pipelines. To address this gap, we present a systematic evaluation of state-of-the-art visual, visual-inertial, and LiDAR-visual-inertial SLAM methods using the GrandTour dataset recorded on an ANYmal D quadruped. We isolate and quantify the impacts of camera modalities, shutter techniques, and inertial sensor tiers, analyzing their trade-offs across localization accuracy, algorithmic robustness, and computational resource utilization. Our empirical findings demonstrate that hardware selection has substantial influence on system resilience: stereo configurations consistently outperform monocular and RGB-D modalities, global shutter cameras significantly mitigate motion-induced tracking failures compared to rolling shutter cameras, and, crucially, standard inertial integration can degrade the performance of primarily vision-based frameworks under harsh legged locomotion. These insights additionally offer concrete design guidelines for tailoring custom sensor payloads to achieve dependable perception on agile legged systems.","authors":["Roberto Corlito","Fabian Schmidt","Nils Seibert","Markus Enzweiler","Abhinav Valada","Arne Roennau"],"published":"2026-06-17T13:41:07Z","updated":"2026-06-17T13:41:07Z","abstract_url":"https://arxiv.org/abs/2606.19067v1","html_url":"https://arxiv.org/html/2606.19067v1","pdf_url":"https://arxiv.org/pdf/2606.19067v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":47961,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Autonomous navigation of quadrupedal robots in diverse environments fundamentally relies on resilient Simultaneous Localization and Mapping (SLAM). While visual-inertial SLAM has matured across wheeled, handheld, and aerial platforms, a critical evaluation ga...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19062v1","title":"DREAM: Extending Vision-Language Models with Dual-Objective Encoding for Cross-Modal Retrieval","abstract":"In today's media-driven world, the exponential growth of video content across domains such as surveillance, education, and entertainment has made retrieving semantically relevant videos via natural language queries increasingly critical. Early video retrieval systems relied on handcrafted features or shallow cross-modal mappings, limiting their ability to capture complex semantics and temporal dynamics. While large-scale vision-language models have improved cross-modal alignment, challenges remain in modeling fine-grained temporal dependencies and nuanced linguistic structures. In this paper, we introduce DREAM: Dual-path Representation Enhancement and Alignment Model, a novel multimodal framework that addresses these limitations through enhanced visual and textual encoding. DREAM incorporates a hybrid language modeling strategy that combines masked and permuted language modeling objectives to capture both local and global linguistic semantics. On the visual side, we design a hierarchical vision encoder with cascaded group attention, which integrates spatial and temporal information through multi-stage token interaction and coarse-to-fine attention refinement. We validate DREAM through comprehensive evaluations on the widely-used MSRVTT, MSVD and LSMDC benchmark datasets, where it achieves new state-of-the-art R1 scores of 49.4%, 49.7% and 27.3%, respectively. Qualitative analyses further show the model's ability to maintain coherent attention across frames and align complex queries with dynamic video content. These findings underscore the effectiveness of hierarchical attention and dual-objective textual modeling in enabling robust, context-aware video retrieval, and pave the way for future research in advancing cross-modal representation learning.","authors":["Kaleem Ullah","Altaf Hussain","Muhammad Munsif","Sung Wook Baik"],"published":"2026-06-17T13:35:50Z","updated":"2026-06-17T13:35:50Z","abstract_url":"https://arxiv.org/abs/2606.19062v1","html_url":"https://arxiv.org/html/2606.19062v1","pdf_url":"https://arxiv.org/pdf/2606.19062v1.pdf","matched_keywords":["video","retrieval","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19053v1","title":"Benchmarking Large Vision-Language Models on Fine-Grained Image Tasks: From Evaluation to Diagnosis","abstract":"Recent advancements in Large Vision-Language Models (LVLMs) have demonstrated remarkable multimodal perception and reasoning capabilities. While numerous benchmarks have evaluated LVLMs from holistic or task-specific perspectives, their capabilities on fine-grained image tasks-fundamental to computer vision-remain insufficiently understood. To address this gap, we introduce FG-BMK, a comprehensive fine-grained evaluation benchmark containing 1.01 million questions and 0.28 million images, covering diverse scenarios from common object-centric domains to specialized domains. FG-BMK jointly evaluates dialogue-level fine-grained semantic recognition and feature-level visual discriminability through human-oriented and machine-oriented paradigms, enabling diagnostic analysis of whether LVLM failures arise from insufficient visual representations, weak visual-to-semantic grounding, or limited fine-grained knowledge. Through extensive experiments on a diverse set of representative LVLMs/VLMs, we find that current LVLMs remain inadequate fine-grained recognizers, with failures arising from intertwined bottlenecks in visual representations, semantic grounding, modality alignment, and category-level knowledge. We further analyze training design factors for improving fine-grained capabilities and examine how visual and linguistic perturbations affect LVLM predictions. These findings provide diagnostic insights into the limitations of current LVLMs and offer guidance for future data construction and model design in developing more reliable LVLMs for fine-grained visual tasks. Our code is open-source and available at https://fg-bmk.github.io/.","authors":["Hong-Tao Yu","Chen-Wei Xie","Yuxin Peng","Serge Belongie","Xiu-Shen Wei"],"published":"2026-06-17T13:23:26Z","updated":"2026-06-17T13:23:26Z","abstract_url":"https://arxiv.org/abs/2606.19053v1","html_url":"https://arxiv.org/html/2606.19053v1","pdf_url":"https://arxiv.org/pdf/2606.19053v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19019v1","title":"FlowObject: Flow Steering for Bridging Generative Priors and Reconstruction Fidelity","abstract":"Recovering complete 3D representations of objects from few casual image captures remains a significant challenge. Recent 3D generative models, particularly those based on Flow-Matching (FM), can synthesize high-quality textured assets; however, they often suffer from ''synthetic bias'' where learned priors override observational evidence, alongside a lack of alignment with the observed instance. Conversely, optimization-based methods like 3D Gaussian Splatting (3DGS) provide high fidelity on visible surfaces but fail to reason about unobserved geometry. In this paper, we present FlowObject, a framework that reformulates sparse-view 3D reconstruction as a training-free, guided inverse problem. Our approach applies a dual-space guidance strategy to steer the Ordinary Differential Equation (ODE) trajectory of a flow-matching model, enabling the completion of unseen regions through learned generative priors while enforcing strict consistency with real-world observations. By integrating a 3DGS refinement stage, FlowObject further bridges the gap between ''synthetic-looking'' generative outputs and photorealistic reconstructions. Comprehensive benchmarks on synthetic and real-world datasets demonstrate that current state-of-the-art methods often struggle to achieve geometric completeness and observational consistency simultaneously, especially under severe occlusions. In contrast, our method significantly outperforms state-of-the-art generative models and optimization-based frameworks in both geometric completeness and view-dependent appearance fidelity.","authors":["Yuchen Rao","Xuqian Ren","Yinyu Nie","Sayan Deb Sarkar","Biao Zhang","Vincent Lepetit","Friedrich Fraundorfer"],"published":"2026-06-17T12:42:09Z","updated":"2026-06-17T12:42:09Z","abstract_url":"https://arxiv.org/abs/2606.19019v1","html_url":"https://arxiv.org/html/2606.19019v1","pdf_url":"https://arxiv.org/pdf/2606.19019v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18992v1","title":"Show, Don't Ask: Generative Visual Disambiguation for Composed Image Retrieval with Turn-Valid Coverage","abstract":"Composed image retrieval (CIR) uses a reference image and a text modification to search for a target image. However, such queries often describe several possible images rather than one exact target, making the user's intent ambiguous. Recent methods address this by using conformal prediction to estimate ambiguity and by asking users clarifying text questions. However, these methods have two limitations: their coverage guarantee only holds at the first interaction, and text questions are often insufficient for resolving fine-grained visual differences such as appearance, attributes, or viewpoint. We propose CLARA, a clarification framework that resolves ambiguity by showing users a small panel of visual alternatives. Instead of answering text questions, the user simply selects the prototype image closest to the intended target. This provides a direct visual signal and avoids relying on a model to predict the user's answer. To maintain valid conformal guarantees across multiple interaction rounds, CLARA reweights calibration using the likelihood ratio induced by the user's selection. The displayed prototypes are also constrained to represent the current candidate set and are snapped to real corpus images, ensuring that generated images cannot artificially improve coverage. Experiments on open-domain and fashion benchmarks show that CLARA matches single-turn state-of-the-art retrieval performance, maintains nominal coverage across interaction rounds, and finds the intended target in fewer rounds than strong text-question baselines. Its advantage is especially clear when ambiguity involves viewpoint or fine-grained attributes, where visual clarification is more effective than textual questioning.","authors":["Amsisan Tran","Baogh Le","Tuan Kiet Pham","Sui Yang Guang"],"published":"2026-06-17T12:13:57Z","updated":"2026-06-17T12:13:57Z","abstract_url":"https://arxiv.org/abs/2606.18992v1","html_url":"https://arxiv.org/html/2606.18992v1","pdf_url":"https://arxiv.org/pdf/2606.18992v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18974v1","title":"Visual-OPSD: Cross-Modal On-Policy Self-Distillation for Efficient Unified Multimodal Reasoning","abstract":"Unified multimodal models (UMMs) interleave generated ''visual thoughts'' (VTs) with text reasoning to improve spatial tasks. This incurs roughly an order-of-magnitude inference cost from multi-step diffusion. We find this cost yields limited direct benefit. On ThinkMorph, removing or noising VTs barely changes accuracy across nine benchmarks. Once rendered, attention concentrates on the VT regardless of content. Yet a KL diagnostic shows that conditioning on a privileged VT trace shifts the model's completion distribution. This suggests the generation pathway encodes useful reasoning beyond the rendered pixels. Motivated by this gap, we propose Visual On-Policy Self-Distillation(Visual-OPSD). Teacher and student share identical weights but differ in context: the teacher sees privileged VTs while the student sees only the question. Token-level JSD distillation on on-policy student trajectories transfers the teacher's reasoning to a text-only student. Across nine benchmarks, Visual-OPSD improves over its generative teacher by $+3.40$pp with $14.3\\times$ speedup (10.0s vs. 142.8s per sample) and outperforms same-scale VLMs by $+63.83$pp on VSP. A Gaussian-noise control ($+0.40$pp vs. $+10.28$pp for real VTs) and $58.4\\%$ closure of the KL gap confirm that gains come from the semantic content of the generation pathway.","authors":["Pengyu Li","Zhitao Gao","Lingling Zhang","Muye Huang","Yuanming Li","Fangzhi Xu","Jun Liu"],"published":"2026-06-17T11:59:15Z","updated":"2026-06-17T11:59:15Z","abstract_url":"https://arxiv.org/abs/2606.18974v1","html_url":"https://arxiv.org/html/2606.18974v1","pdf_url":"https://arxiv.org/pdf/2606.18974v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18960v1","title":"Mem-World: Memory-Augmented Action-Conditioned World Models for Persistent Robot Manipulation","abstract":"Action-conditioned world models have emerged as a promising paradigm for robot learning, offering a scalable alternative to costly real-world experimentation by generating action-consistent video rollouts. However, persistent world modeling remains challenging in manipulation: frequent end-effector occlusions and rapid wrist-camera motion make the current observation insufficient for predicting future views, causing models to forget or hallucinate scene details seen in earlier frames. Existing memory retrieval strategies often fail to identify informative history in dynamic manipulation scenarios. To address this limitation, we propose Mem-World, a memory-augmented multi-view action-conditioned world model. At its core, we present W-VMem, a 4D wrist-view-centered surfel-indexed memory that anchors historical observations to temporally evolving surface elements. By explicitly modeling when and where scene elements are observed, W-VMem enables geometry-aware retrieval of relevant history frames conditioned on future actions. During generation, relevant history frames are selected via surfel-based rendering and scoring, providing informative and non-redundant context for prediction. Extensive experiments show that Mem-World generates persistent rollouts in complex manipulation scenarios, enables more reliable policy evaluation than Ctrl-World, improving the Pearson correlation with real-world performance by 14.5\\%, and supports effective policy improvement through synthetic data generation, increasing success rates from 58\\% to 72\\% on long-horizon tasks.","authors":["Zirui Zheng","Jiaqian Yu","Xiongfeng Peng","jun shi","Mingyi Li","Chao Zhang","Weiming Li","Dong Wang","Huchuan Lu","Xu Jia"],"published":"2026-06-17T11:42:00Z","updated":"2026-06-17T11:42:00Z","abstract_url":"https://arxiv.org/abs/2606.18960v1","html_url":"https://arxiv.org/html/2606.18960v1","pdf_url":"https://arxiv.org/pdf/2606.18960v1.pdf","matched_keywords":["video","retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18955v1","title":"Motion-Focused Latent Action Enables Cross-Embodiment VLA Training from Human EgoVideos","abstract":"Training generalist Vision-Language-Action(VLA) models typically requires massive, diverse robotic datasets with high-fidelity action annotations. While egocentric human manipulation videos are abundant and capture significant environmental diversity, the absence of action labels makes them difficult to use in conventional training paradigms. To address this, we propose a latent-action-based framework designed to extract general action priors from unlabeled human videos. The architecture features a Hybrid Disentangled VQ-VAE that decouples motion dynamics from environmental backgrounds through physical masks, enabling the construction of a cross-embodiment action codebook. By pre-training on human videos with the codebook, the VLM backbone learns deep representations of action intent. For adaptation to specific embodiments, we introduce an intent-perception decoupling strategy where the VLM predicts the action intent while a separate frozen visual encoder provides state-specific features to the action expert, thereby reducing action hallucinations. Results in simulation and real-world environments show that our method, pre-trained exclusively on unlabeled human videos, performs competitively with state-of-the-art VLA models trained on massive annotated datasets, requiring only 50 trajectories for downstream adaptation.","authors":["Runze Xu","Yiluo Zhang","Jian Wang","Yu Wang","Jincheng Yu"],"published":"2026-06-17T11:37:59Z","updated":"2026-06-17T11:37:59Z","abstract_url":"https://arxiv.org/abs/2606.18955v1","html_url":"https://arxiv.org/html/2606.18955v1","pdf_url":"https://arxiv.org/pdf/2606.18955v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18943v1","title":"Physics-IQ Verified","abstract":"Video generative models ( VGMs) have become a new frontier that can be used not just for video generation but for a multitude of downstream tasks, including world modeling. To advance these tasks, a good video model must understand the physical reality of the world. Evaluating this understanding is an emerging field and has led to the Physics-IQ benchmark, which quantifies this explicitly by comparing model-generated videos to real-world videos of physical experiments. In this work, we present a systematic audit of the Physics-IQ benchmark, expose shortcomings and propose three solutions that sharpen how we can measure physical understanding of VGMs. Specifically, we improve prompt and ground-truth quality to reduce the influence of confounding factors and further introduce a sample-level scoring system that weights each sample and metric equally. Our resulting benchmark, Physics-IQ Verified, refines 57.6\\% of all samples and improves over 34.8\\% of prompts. In a comparison study using six image-to-video generative models, we observe moderate but meaningful ranking changes (Kendall's $τ= 0.46$). We hope Physics-IQ Verified advances the community by providing a more reliable signal toward physically accurate VGMs. The code for the benchmark can be accessed at https://github.com/google-deepmind/physics-iq-benchmark","authors":["Tim Rädsch","Yuki M Asano","Hilde Kuehne","Stefan Bauer","Priyank Jaini","Robert Geirhos","Carsten T. Lüth"],"published":"2026-06-17T11:23:52Z","updated":"2026-06-17T11:23:52Z","abstract_url":"https://arxiv.org/abs/2606.18943v1","html_url":"https://arxiv.org/html/2606.18943v1","pdf_url":"https://arxiv.org/pdf/2606.18943v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18906v1","title":"BindEdit: Taming Attention Leakage for Precise Multi-Object Image Editing","abstract":"Real image editing enables precise manipulation of visual content, yet existing methods often fail in complex multi-object scenarios, causing semantic blending, object duplication, or incomplete edits. We attribute these failures to attention leakage, where signals across spatial regions and text tokens become entangled during the denoising process. Specifically, we identify two distinct forms of leakage: Edit-Token Leakage, where ambiguous token-region alignment leads to object blending, and Source Dominance Leakage, where tokens of unchanged source objects overwhelm the attention intended for target entities. To resolve these leakages, we propose \\textbf{BindEdit}, which enforces attention-level constraints within a single diffusion trajectory. To suppress Edit-Token Leakage, BindEdit jointly regularizes cross- and self-attention so that each target token group is bound to its corresponding spatial region while maintaining instance-level separation. To suppress Source Dominance Leakage, a cross-attention re-balancing mechanism amplifies target token influence and attenuates residual source semantics within editable regions. Moreover, a region fidelity term ensures that each target concept is expressed coherently across the entire editing mask. Additionally, we propose a comprehensive multi-object benchmark encompassing diverse object counts and categories. Extensive experiments demonstrate that BindEdit consistently outperforms existing methods within a single diffusion trajectory, maintaining robust performance across both single- and multi-object editing scenarios.","authors":["Chaewon Park","Soyoon Lee","Naeun Lee","Minjung Shin","Seogkyu Jeon","Kibeom Hong"],"published":"2026-06-17T10:32:14Z","updated":"2026-06-17T10:32:14Z","abstract_url":"https://arxiv.org/abs/2606.18906v1","html_url":"https://arxiv.org/html/2606.18906v1","pdf_url":"https://arxiv.org/pdf/2606.18906v1.pdf","matched_keywords":["instance","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18894v1","title":"Automatic ply-specific analyses of CFRP micrographs using shortest-path-based ply distinction","abstract":"We present an automated approach to distinguish between ply instances in semantic segmentation masks of high-resolution carbon-fiber reinforced polymer micrographs. Interpreting the segmentation mask as a graph with pixels as vertices, enables us to use a shortest-path algorithm yielding the ply-separating paths. Thereby, we bridge the gap between semantic segmentation and ply instance segmentation using global information. We successfully apply our approach on high-resolution micrographs featuring a broad range of characteristics like artificially added gaps in single or multiple plies, different stacking sequences and ply traversing cracks. Assigning each fiber pixel to a ply based on the calculated paths, allows for a comprehensive, quantitative ply analysis with respect to its microstructural properties like the local fiber volume fraction as well as locally resolved ply and interleaf layer thickness. These insights help to reveal manufacturing-induced inhomogeneities, draw conclusions on manufacturing parameters and link mechanical properties to underlying microstructural imperfections.","authors":["Jonas Naumann","Jonas P. Appels","Julius Biermann","Christopher Gorsky","Timo de Wolff","Christoph Brauer"],"published":"2026-06-17T10:12:21Z","updated":"2026-06-17T10:12:21Z","abstract_url":"https://arxiv.org/abs/2606.18894v1","html_url":"https://arxiv.org/html/2606.18894v1","pdf_url":"https://arxiv.org/pdf/2606.18894v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18886v1","title":"DINO-Med3D: Bridging Dimension and Domain Gaps in Volumetric Segmentation via Progressive Adaptation","abstract":"Although DINOv3 has demonstrated remarkable semantic discrimination in natural imagery, its direct application to volumetric medical segmentation is hindered by inherent dimension and domain disparities. To resolve these issues, we propose DINO-Med3D, a two-stage progressive framework that repurpose the pre-trained DINOv3 encoder for 3D medical tasks. In the first stage, we mitigate the dimension gap by introducing a multi-slice embedding module that incorporates pseudo-3D context, while simultaneously employing a segmentation proxy task to adapt representations learned from natural scenes to the medical domain. Subsequently, we further enhance volumetric understanding by adding lightweight 3D adapters into the frozen backbone to enforce global inter-slice continuity. Finally, to compensate for the spatial information loss inherent in the embedding process, we design a parallel detail recovery stream to explicitly preserve high-frequency boundary cues. Extensive experiments on five public datasets demonstrate that our approach successfully adapts DINOv3 to the medical domain and significantly outperforms state-of-the-art baselines.","authors":["Haoyu Hu","Xiyao Ma","Shiqi Liu","Linsen Zhang","Xiaoliang Xie","Xiaohu Zhou","Zeng-Guang Hou"],"published":"2026-06-17T10:04:43Z","updated":"2026-06-17T10:04:43Z","abstract_url":"https://arxiv.org/abs/2606.18886v1","html_url":"https://arxiv.org/html/2606.18886v1","pdf_url":"https://arxiv.org/pdf/2606.18886v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18885v1","title":"LARE: Low-Attention Region Encoding for Text-Image Retrieval","abstract":"Image retrieval in crowded scenes is particularly challenging due to the salience bias of conventional visual encoders, which tend to focus on dominant objects while neglecting low-attention regions that are often crucial for fine-grained retrieval. We propose LARE (Low-Attention Region Encoding), a framework that explicitly models these overlooked regions. LARE adopts a dual-encoding strategy that encodes low-attention regions of an image and the full image in parallel, leading to more diverse and informative image embeddings. To evaluate image retrieval performance in challenging crowded scenes, we introduce Dense-Set, a challenging subset derived from COCO and Flickr30K. In this subset, images are re-captioned to provide richer descriptions of low-attention or previously overlooked regions. This dataset highlights the limitations of existing retrieval models and enables a more rigorous evaluation under densely crowded scene conditions. Experimental results demonstrate that the proposed framework improves retrieval performance by preserving subtle, non-dominant visual cues within the shared latent space.","authors":["Abdulmalik Alquwayfili","Faisal Almeshal","Jumanah Almajnouni","Leena Alotaibi","Faisal Alhajari","Mohammed Alkhrashi","Alreem Almuhrij","Abdullah Aldwyish","Raied Aljadaany","Huda Alamri","Muhammad Kamran J. Khan"],"published":"2026-06-17T10:00:33Z","updated":"2026-06-17T10:00:33Z","abstract_url":"https://arxiv.org/abs/2606.18885v1","html_url":"https://arxiv.org/html/2606.18885v1","pdf_url":"https://arxiv.org/pdf/2606.18885v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18884v1","title":"Performance Gap Analysis between Latin and Arabic Scripts HTR","abstract":"Recent studies have shown that handwritten text recognition (HTR) systems perform worse on Arabic-script datasets than on Latin-script data. However, the reasons for this gap are still not well understood due to the lack of controlled comparisons. In this work, we present a comprehensive study of Arabic and Latin scripts HTR using a unified CRNN model for line-level HTR across nine datasets (including KHATT (Arabic), Muharaf (Arabic), NUST-UHWR (Urdu), PHTD (Persian), IAM (English), READ-2016 (German), and others) and di ferent training sizes (K in {100, 500, 1000, 2000, ..., Kfull}). Our results show the performance gap remains: it is large in low-resource settings, decreases with more data, but remains even at full scale, with a consistent difference of 5-7 CER points. We show that annotation quality matters, as many datasets contain labeling errors. Cleaning reduces error rates and narrows the gap, but does not eliminate it. In addition, we find that a fixed number of training samples provides less effective coverage in Arabic due to higher visual variability, requiring more data to learn similar representations. We compare recognition across datasets in terms of the number of text lines and the number of characters, showing an equivalence trade-off. We compare character frequency distributions across scripts and show that Arabic is significantly more heavy-tailed than Latin. Our error analysis reveals that around 30 percent of substitution errors in Arabic datasets (e.g., KHATT) are caused by confusion between visually similar characters, compared to about 15 percent in Latin-script datasets such as IAM.","authors":["Sana Al-azzawi","Elisa Barney","Marcus Liwicki"],"published":"2026-06-17T10:00:22Z","updated":"2026-06-17T10:00:22Z","abstract_url":"https://arxiv.org/abs/2606.18884v1","html_url":"https://arxiv.org/html/2606.18884v1","pdf_url":"https://arxiv.org/pdf/2606.18884v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18872v1","title":"Bridging Single Distortion Artifacts and Mmultifactorial Clinical Quality: Few-shot Biparametric MRI Quality Assessment via Distortion-trained Prototypical Networks","abstract":"Clinical prostate multi-parametric MRI relies heavily on high-quality diffusion-weighted imaging (DWI), yet reading DWI is frequently compromised by geometric distortion, often caused by rectal air. Assessing quality via the PI-QUAL scoring system is an emerging clinical standard, but it is subjective, time-consuming and suffers from a class imbalance where low-quality cases are diverse and relatively scarce. Using the PRIME clinical trial as an example, there are $6\\%$ images with PI-QUAL scores lower than 4, $87\\%$ of DWI issues are due to distortion. Many of the other clinical quality issues are under-represented. To address this common dual-scarcity of annotated clinical data, we propose a few-shot biparametric prototypical network for automated image quality assessment (IQA). Our framework utilizes a dual-branch 3D ResNet to fuse T2-weighted and DWI features, providing anatomical context to distinguish true morphology from distortion. To handle real-world heterogeneity, we introduce feature-wise linear modulation (FiLM) and a gradient reversal layer (GRL) to align feature distributions conditioned on varying b-values while suppressing acquisition-related biases. We demonstrate that a model meta-trained solely on comparatively objective, readily obtainable distortion labels can effectively adapt to predicting complex, multi-factorial clinical quality scores such as PI-QUAL using only five representative samples. Experimental results on two datasets show that our method significantly outperforms few-shot learning baselines for this challenging IQA task, offering a practically feasible and data-efficient solution for standardizing prostate MRI quality control in clinical workflows.","authors":["Yuheng Tang","Alexander Ng","Wen Yan","Natasha Thorley","Pawel Rajwa","Yipei Wang","Aqua Asif","Clare Allen","Louise Dickinson","Francesco Giganti","Shonit Punwani","Daniel Alexander","Veeru Kasivisvanathan","Yipeng Hu"],"published":"2026-06-17T09:50:45Z","updated":"2026-06-17T09:50:45Z","abstract_url":"https://arxiv.org/abs/2606.18872v1","html_url":"https://arxiv.org/html/2606.18872v1","pdf_url":"https://arxiv.org/pdf/2606.18872v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18869v1","title":"Learning to Distort: Weakly-Supervised Image Quality Transfer for Prostate DWI Correction","abstract":"Single-shot echo-planar prostate diffusion-weighted imaging (DWI) is frequently complicated by geometric distortions, which impact the ability to derive reliable diagnoses from such images. Developing automated correction methods is challenged by the absence of paired distorted and undistorted clinical scans. In this paper, we first propose a novel weakly-supervised image quality transfer (IQT) framework from undistorted to distorted images that utilizes image quality assessment (IQA) signals to supervise the transfer process. Unlike traditional methods that require expensive, voxel-wise paired data or resort to developing unpaired algorithms, our approach utilizes image-level quality labels (here, distorted vs. undistorted) to establish latent quality prototypes within a pre-trained feature space. Recognizing that simulating realistic distortions is more reliable than direct unpaired correction, we describe a weakly-supervised prototype flow matching algorithm to explicitly regularize generative trajectories towards distorted prototypes, producing realistic susceptibility artifacts that mimic clinical degradations. By synthesizing these realistic pairs, we enable a second IQT model to be trained in the forward direction for distortion correction. Experimental results demonstrate that our generated images successfully mimic the diagnostic interference of real-world artifacts, which leads to more capable distortion correction IQT models. In addition to qualitative comparisons, we also conduct exhaustive quantitative evaluations that compare our approach with existing unpaired approaches (e.g., CycleGAN, UNIT-DDPM, and OT-FM) - as either forward or reverse alternatives - by assessing clinical downstream task performance in PI-RADS and Gleason score classification, using both in-distribution and external data sets.","authors":["YuCheng Tang","Wen Yan","Alexander Ng","Natasha Thorley","Pawel Rajwa","Yipei Wang","Aqua Asif","Clare Allen","Louise Dickinson","Francesco Giganti","David Atkinson","Shonit Punwani","Daniel Alexander","Shaheer Ullah Saeed","Veeru Kasivisvanathan","Yipeng Hu"],"published":"2026-06-17T09:47:53Z","updated":"2026-06-17T09:47:53Z","abstract_url":"https://arxiv.org/abs/2606.18869v1","html_url":"https://arxiv.org/html/2606.18869v1","pdf_url":"https://arxiv.org/pdf/2606.18869v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18846v1","title":"From Bounding Boxes to Visual Reasoning: An On-Policy Data Annotation Tool for Vision-Language Models","abstract":"Vision-language models (VLMs) are rapidly advancing toward sophisticated grounded structured visual reasoning. Training models for such advanced capabilities demands a new genre of data that seamlessly unifies spatial coordinates, open-vocabulary descriptions, structured attributes, and topological relationships into a singular representation. However, existing data annotation tools fundamentally fail to meet these intricate demands, suffering from three systematic bottlenecks: limited expressiveness, severe annotation-training decoupling, and poor data reusability. To bridge this infrastructure gap, we introduce an open-source annotation tool, ScreenAnnotator. First, we define a unified annotation atom schema that binds spatial, semantic, and structural primitives into a single unit. Second, we implement an on-policy annotation loop embedded with a Bayesian Annotation Verifier (BAV). Finally, we design a template-driven multi-task data synthesis process dynamically transforms static atoms into diverse multi-dimensional reasoning tasks, eliminating redundant re-annotation. The on-policy loop drives the annotation accept rate to nearly 100% on flowcharts and 77% on GUI screenshots, while steadily reducing per-image annotation time as labeled data accumulate. In the flowchart scenario, fine-tuning a VLM yields 76.1% average accuracy, which is a 35.1% point absolute gain. Our code is available at: https://github.com/WnQinm/Annotator.","authors":["Like Zhang","Runliang Niu","Shiqi Wang","Xiyu Hu","Qianli Xing","Pan Wang","Qingzu He","Qi Wang"],"published":"2026-06-17T09:25:59Z","updated":"2026-06-17T09:25:59Z","abstract_url":"https://arxiv.org/abs/2606.18846v1","html_url":"https://arxiv.org/html/2606.18846v1","pdf_url":"https://arxiv.org/pdf/2606.18846v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18841v1","title":"Rethinking Air-Ground Collaboration: A Progressive Cross-Task Benchmark and Socialized Learning Framework","abstract":"Air-ground collaborative perception is crucial for robust visual understanding in real-world dynamic environments. However, existing studies typically formulate collaboration as single-task cross-view fusion, overlooking the functional dependencies among localization, target association, and fine-grained parsing. In addition, the heterogeneous nature of aerial and ground views introduces substantial geometric, scale, and occlusion discrepancies, making uniform feature sharing vulnerable to negative transfer. To tackle these issues, we model air-ground perception as a progressive cross-task collaboration task and construct the Air-Ground Progressive Collaboration (AGPC) benchmark, a spatio-temporally aligned benchmark comprising more than 745K raw video frames. Built upon this benchmark, we propose Socialized Co-Perception (SCP), a coarse-to-fine framework that organizes collaboration progressively from aerial global localization to ground target association and identity-aware parsing. Its core module, the Dual-Layer Router (DLR), decouples input-side multi-scale expert selection from output-side task-conditioned modulation, enabling selective cross-view and cross-task interaction while suppressing harmful interference. Extensive experiments demonstrate the effectiveness of SCP. It achieves a 3.73\\% coevolutionary gain and a 7.86\\% improvement in average downstream performance. These results show that task-conditioned collaboration is more effective than uniform fusion for heterogeneous air-ground perception. The code is available at https://github.com/g1136639260-spec/AGSCP.","authors":["Zhoupeng Guo","Yunqi Zhu","Zhihe Fan","Xinjie Yao","Ruipu Zhao","Boan Tao","Yiming Sun","Zhen Wang","Pengfei Zhu"],"published":"2026-06-17T09:17:55Z","updated":"2026-06-17T09:17:55Z","abstract_url":"https://arxiv.org/abs/2606.18841v1","html_url":"https://arxiv.org/html/2606.18841v1","pdf_url":"https://arxiv.org/pdf/2606.18841v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18826v1","title":"EDoF-NeRF: extended depth-of-field neural radiance fields using a coded aperture camera","abstract":"We propose a method for extending the depth-of-field (DoF) to construct high-fidelity neural radiance fields (NeRF) -- an emerging technique for rendering photorealistic novel views from a dataset of images captured at different viewpoints, based on implicit neural representations. The trade-off between DoF and light quantity is inherent not only in conventional cameras but also in NeRF, since the datasets used by NeRF are captured by these cameras. To address this issue, we introduce a coded aperture placed at the camera pupil, preserving spatial frequency components under defocused conditions. We develop a camera model incorporating coded apertures into NeRF, allowing direct input of coded images and enabling the generation of novel views with an extended DoF. We validate the proposed method, termed extended DoF-NeRF (EDoF-NeRF), through simulations and experiments, demonstrating its superior performance compared to conventional aperture cameras.","authors":["Yoshiyuki Shirasaki","Ryoichi Horisaki"],"published":"2026-06-17T08:56:50Z","updated":"2026-06-17T08:56:50Z","abstract_url":"https://arxiv.org/abs/2606.18826v1","html_url":"https://arxiv.org/html/2606.18826v1","pdf_url":"https://arxiv.org/pdf/2606.18826v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18825v1","title":"DreamReg: Belief-Driven World Model for 2D-3D Ultrasound Registration","abstract":"Ultrasound (US) is widely used for surgical navigation, yet real-time registration between intraoperative 2D slices and preoperative 3D volumes remains challenging due to partial observability, speckle noise, and the action-dependent US acquisition. Existing methods are one-shot or short-horizon, making it hard for them to gather evidence over time or capture how surgeons adjust probe motion based on on-screen feedback. We propose DreamReg, a belief-driven world-model framework that formulates 2D-3D registration as belief updating over rigid transformations. DreamReg maintains a latent belief state that summarizes past observations and poses information, and continuously refines the transformation through learned dynamics as new slices arrive. During training, DreamReg is exposed to probe-motion trajectories that mimic clinical scanning behavior and learns to update its belief by conditioning pose refinement on the current US observation. During inference, DreamReg refines registration via internal imagination: it rolls out the learned world model to simulate candidate probe motions and their predicted observations, and integrates these imagined outcomes to converge to an accurate rigid transformation. Experiments on CAMUS and u-RegPro datasets demonstrate improved robustness and competitive registration accuracy for real-time guidance compared with state-of-the-art methods.","authors":["Luoyao Kang","Yuelin Zhang","Jiwei Shan","Haifan Gong","Qingpeng Ding","Shing Shin Cheng"],"published":"2026-06-17T08:56:03Z","updated":"2026-06-17T08:56:03Z","abstract_url":"https://arxiv.org/abs/2606.18825v1","html_url":"https://arxiv.org/html/2606.18825v1","pdf_url":"https://arxiv.org/pdf/2606.18825v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18824v1","title":"Where Will They Go? Modelling Multimodal Pedestrian Manoeuvres from Ego-centric Videos","abstract":"Pedestrian trajectory prediction from an ego-centric camera is challenging since it depends on complex interactions with vehicles and scene context, as well as the intention of the pedestrian. By modelling correlation and intent from the historical and future trajectories of the pedestrian, it will usually result in a multimodal (i.e. multiple modes) distribution. Existing stochastic predictors often sample multiple futures from a single unimodal distribution, which can yield sub-optimal 'mixed-mode' trajectories that lie between distinct motion patterns and become implausible in real scenes. In this paper, we propose MMPM, a mode-aware framework that separately models future trajectory distributions into semantically meaningful modes based on the pedestrian's crossing behavior. MMPM consists of two modules: behavior-aware Pedestrian Interaction Module (PIM) that jointly captures pedestrian-vehicle and pedestrian-environment interactions by introducing gaze, head and hand gesture, and a CVAE-based Mode-aware Trajectory Predictor (MTP) module to model the future trajectory distributions on two modes, crossing and non-crossing the road, separately. A query-based decoder further enforces mode consistency during decoding. Experiments on PIE and JAAD datasets show that our method surpasses state-of-the-art baselines. Our proposed MTP is model-agnostic, which can be integrated into existing frameworks such as BiTrap-NP and SGNet-ED to further improve future trajectory prediction performance. We additionally introduce a data-driven validation protocol that matches predictions to spatio-temporally consistent ground-truth trajectories, demonstrating improved frame-wise displacement errors over previous work.","authors":["Yuxuan Xie","Nicolas Pugeault","Chongfeng Wei","Hubert P. H. Shum","Edmond S. L. Ho"],"published":"2026-06-17T08:55:01Z","updated":"2026-06-17T08:55:01Z","abstract_url":"https://arxiv.org/abs/2606.18824v1","html_url":"https://arxiv.org/html/2606.18824v1","pdf_url":"https://arxiv.org/pdf/2606.18824v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18788v1","title":"HandwritingAgent: Language-Driven Handwriting Synthesis in Scalable Vector Space","abstract":"Teaching machines to emulate natural handwriting styles remains an open challenge, as it requires synthesizing stroke sequences that dynamically vary in shape, texture, pressure and script - not only across individuals, but also within a single person's handwriting. Attempts at this challenge have largely explored deep learning methods in both online and offline settings. However, these approaches are often constrained by style-specific architectural choices, heavy reliance on large datasets, high compute costs, and a lack of flexible control over writing styles through natural language. To this end, we introduce HandwritingAgent, a language-driven agent that can synthesize natural handwriting sequences directly in Scalable Vector Graphics (SVG) format with no need for style-specific training. The agent leverages a large reasoning model to geometrically analyse and autoregressively generate target handwritten glyphs as stroke sequences in a discrete grid canvas environment. Generation is conditioned on texts provided in either conversational or non-conversational mode, along with a reference handwriting-style image. Experiments on diverse handwriting tasks spanning imitation, recognition, multi-lingual handwriting synthesis, and generation of complex handwritten maths and science expressions indicate substantial improvement in performance, with HandwritingAgent matching or surpassing state-of-the-art generative handwriting models, while providing a more efficient, controllable, and generalizable synthesis method.","authors":["Jaward Sesay","Yue Yu","Börje F. Karlsson"],"published":"2026-06-17T08:02:19Z","updated":"2026-06-17T08:02:19Z","abstract_url":"https://arxiv.org/abs/2606.18788v1","html_url":"https://arxiv.org/html/2606.18788v1","pdf_url":"https://arxiv.org/pdf/2606.18788v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18787v1","title":"Learned Radius Estimation for UDF-Based Point Cloud Reconstruction","abstract":"Surface reconstruction from point clouds is important for consumer-grade 3D capture, including AR/VR and indoor scanning. Local-patch Unsigned Distance Field (UDF) methods are lightweight and generalizable, but their accuracy depends on the support radius, traditionally fixed or selected by a one-dimensional curvature heuristic that cannot capture heterogeneous local geometry. We propose a learned per-query radius selector that predicts a continuous support radius and plugs into a frozen LoSF-UDF backbone. The selector is trained using off-grid target radii obtained by parabolic interpolation of cached UDF error curves. Experiments show improved fine-scale reconstruction accuracy.","authors":["Eito Ogawa","Hiroshi Watanabe"],"published":"2026-06-17T07:59:18Z","updated":"2026-06-17T07:59:18Z","abstract_url":"https://arxiv.org/abs/2606.18787v1","html_url":"https://arxiv.org/html/2606.18787v1","pdf_url":"https://arxiv.org/pdf/2606.18787v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18780v1","title":"SAMA: Semantic Anchor-aligned Augmentation for Unified Low-Resource Multimodal Information Extraction","abstract":"Multimodal Information Extraction (MIE)-covering tasks such as Multimodal Named Entity Recognition (MNER), Relation Extraction (MRE), and Event Extraction (MEE)-is essential for understanding multimedia content but remains constrained by severe data scarcity. Although data augmentation is a promising remedy, existing approaches are impeded by coarse cross-modal alignment and fragmented, task-specific designs that fail to exploit shared semantic knowledge. To overcome these limitations, we introduce Semantic Anchor-aligned Multimodal Augmentation (SAMA), a unified framework for generating high-fidelity, task-aware synthetic data. SAMA constructs structured semantic anchors from ground-truth labels to guide a Collaborative Multi-Experts Multimodal Large Language Model (CME-MLLM), which integrates a Universal Adapter for shared semantics with Task-Specific Adapters to produce diverse yet constraint-compliant textual samples. For image synthesis, SAMA employs an Anchor-Preserving Diffusion mechanism that uses anchor-weighted prompts and latent conditioning to maintain critical semantic anchors while diversifying visual contexts. To eliminate the need for manual verification, SAMA further introduces a Dual-Constraint Filtering module that selects synthetic samples based on both cross-modal consistency and anchor fidelity. Extensive experiments across benchmark datasets for MNER, MRE, and MEE demonstrate that SAMA consistently outperforms state-of-the-art augmentation baselines under both fully supervised and low-resource settings, underscoring its versatility, robustness, and effectiveness.","authors":["Quanjiang Guo","Chong Mu","Jiazhou Pan","Ming Jia","Ling Tian","Hui Gao","Zhao Kang"],"published":"2026-06-17T07:43:33Z","updated":"2026-06-17T07:43:33Z","abstract_url":"https://arxiv.org/abs/2606.18780v1","html_url":"https://arxiv.org/html/2606.18780v1","pdf_url":"https://arxiv.org/pdf/2606.18780v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18765v1","title":"SpectralDiT: Timestep-Conditioned Spectral Residual Correction for Flow-Matching DiTs","abstract":"We propose SpectralDiT, a lightweight modification to flow-matching Diffusion Transformers that adds timestep-conditioned spectral correction to the MLP residual branch. The module decomposes each residual update into low- and high-frequency components on the patch-token grid, then learns a zero-initialized additive gate so the model initially matches the baseline DiT. On CIFAR-10 pixel-space generation, SpectralDiT improves FID from 20.78 to 19.71 at patch size 1 and reduces the radial Fourier spectrum gap. Furthermore, we scale our method to latent diffusion on ImageNet-100. With 0.6% additional theoretical FLOPs and 1.36% additional parameters, SpectralDiT improves latent flow-matching, achieving an 8.7% relative FID reduction under classifier-free guidance (CFG 2.0). All reported results are averaged over five seeds. Ablations and gate visualizations on CIFAR-10 reveal stable block-specific spectral correction patterns.","authors":["Jiayu Tian"],"published":"2026-06-17T07:25:24Z","updated":"2026-06-17T07:25:24Z","abstract_url":"https://arxiv.org/abs/2606.18765v1","html_url":"https://arxiv.org/html/2606.18765v1","pdf_url":"https://arxiv.org/pdf/2606.18765v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18753v1","title":"SMART: A Flexible, Interpretable, and Scalable Spatio-temporal Brain Atlas from High-Resolution Imaging Data","abstract":"We introduce SMART, a framework for learning a flexible, interpretable, and scalable spatio-temporal brain atlas from longitudinal high-resolution 3D medical images. Existing approaches to spatio-temporal atlas construction rely on black-box generative models that lack flexibility, limit interpretability, and struggle to scale to high-dimensional data. SMART addresses these challenges by learning a continuous disease-time atlas that decouples global group-wise disease dynamics from their patient-specific anatomical manifestation. Guided by anatomically inspired priors, SMART models interpretable global trajectories of regional progression along a shared disease timeline through region-specific differential equations. Global trajectories are further personalized to individual anatomies via dense diffeomorphic displacements parameterized by a flexible and scalable multi-scale Neural Cellular Automata. Evaluated on five longitudinal MRI datasets in Alzheimer's disease (ADNI-1/GO/2, OASIS-3, AIBL; > 1,300 subjects), SMART produces anatomically meaningful predictions of disease progression and achieves state-of-the-art forecasting accuracy and improved temporal consistency over adversarial and diffusion baselines. Our approach establishes a new paradigm for flexible, interpretable, and scalable modeling of spatio-temporal change in high-dimensional medical image time-series.","authors":["John Kalkhof","Boris Gutman","Emile d'Angremont","Daniel C. Alexander","Marco Lorenzi"],"published":"2026-06-17T06:57:22Z","updated":"2026-06-17T06:57:22Z","abstract_url":"https://arxiv.org/abs/2606.18753v1","html_url":"https://arxiv.org/html/2606.18753v1","pdf_url":"https://arxiv.org/pdf/2606.18753v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18749v1","title":"Toward Training-Free Zero-Shot Anomaly Detection in 3D Medical Images: A Batch-Based Approach Using 2D Foundation Models","abstract":"Zero-shot anomaly detection (ZSAD) is attractive for medical imaging because clinical systems must handle heterogeneous acquisition protocols, changing patient populations, and pathologies for which annotated training data may be unavailable. Most existing zero-shot anomaly detection methods are designed for 2D images, and their direct extension to 3D medical volumes is limited by the scarcity of large-scale volumetric foundation models or by the difficulty of utilizing volumetric context. We propose CS3F, a training-free batch-based framework for ZSAD in 3D medical images using 2D foundation models. Each volume is decomposed along multiple anatomical axes and encoded slice-wise by a 2D vision transformer. These are then converted into localized volumetric tokens by pooling neighboring slice features. Anomaly scores are obtained from cross-subject mutual similarity: tokens that lack close analogues in other subjects are assigned higher anomaly scores. To reduce the attenuation of focal lesion signals caused by depth pooling, we introduce a coarse-to-fine tokenization strategy that enables fine-resolution volumetric scoring without exhaustive matching. CS3F is evaluated on brain MRI across metastases, glioma, and stroke, as well as validated on lung CT to test generalizability beyond atlas-aligned brain MRI. The results show that frozen 2D foundation models can support anomaly localization in 3D medical images, and that the benefit of fine tokenization depends strongly on lesion contrast and imaging modality.","authors":["Tai Le-Gia"],"published":"2026-06-17T06:52:07Z","updated":"2026-06-17T06:52:07Z","abstract_url":"https://arxiv.org/abs/2606.18749v1","html_url":"https://arxiv.org/html/2606.18749v1","pdf_url":"https://arxiv.org/pdf/2606.18749v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18732v1","title":"Low-Cost Neuromorphic Fall Detection Using Synthetic Event Data and Hybrid SNNs","abstract":"This work presents the development of hybrid models that integrate spiking neural networks (SNNs) with components of convolutional neural networks (CNNs) to learn from simulated event-based camera data (Dynamic Vision Sensor, DVS) generated from conventional smartphone videos. Aimed primarily at human fall detection, the approach leverages the energy efficiency and spatio-temporal processing capabilities of SNNs by converting video frames into event-based data. The proposed models are evaluated through simulations on multiple datasets, comparing their performance to that of traditional machine learning models. Results demonstrate significant gains in efficiency without sacrificing accuracy, underscoring the potential of combining SNNs and DVS technology for complex tasks in real-world environments.","authors":["Guillermo Rojas","Gonzalo Soto","Daniel Yunge"],"published":"2026-06-17T06:21:13Z","updated":"2026-06-17T06:21:13Z","abstract_url":"https://arxiv.org/abs/2606.18732v1","html_url":"https://arxiv.org/html/2606.18732v1","pdf_url":"https://arxiv.org/pdf/2606.18732v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18702v1","title":"UniTemp: Unlocking Video Generation in Any Temporal Order via Bidirectional Distillation","abstract":"Autoregressive video diffusion models have emerged as a promising approach for long video generation, achieving strong performance in streaming settings. However, existing methods are restricted to forward temporal generation, whereas practical video creation often requires flexible generation order, e.g., conditioning on future context to extend backward, or on both past and future context for inbetween generation. We bridge this gap by training an autoregressive model that supports generation in arbitrary temporal directions. A key technical challenge arises from the Causal 3D VAE widely used in video diffusion models, which encodes latents strictly conditioned on past context. While suited for forward generation, this causal structure causes inter-block discontinuities when generation proceeds backward. To address this, we introduce blockwise anchor latents, a set of auxiliary latents that restore the missing past context at block boundaries during backward generation. Built on this design, we propose UniTemp, a bidirectional distillation framework that trains a single autoregressive student model for any-direction video generation. At inference time, UniTemp conditions on arbitrary past and/or future frames, improving controllability for both bidirectional and inbetween generation. Experiments show that UniTemp maintains competitive performance on short and long video generation compared to forward-only methods, while enabling diverse workflows such as bidirectional video extension, inbetween generation, looping video generation, scene transition, and visual story generation. Project website: https://lzhangbj.github.io/projects/unitemp/","authors":["Lin Zhang","Sicheng Mo","Zefan Cai","Jinhong Lin","Zihao Lin","Jiuxiang Gu","Krishna Kumar Singh","Yuheng Li","Yin Li"],"published":"2026-06-17T05:27:19Z","updated":"2026-06-17T05:27:19Z","abstract_url":"https://arxiv.org/abs/2606.18702v1","html_url":"https://arxiv.org/html/2606.18702v1","pdf_url":"https://arxiv.org/pdf/2606.18702v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18687v1","title":"Spatially Stratified Distillation for Heterogeneous Radar Place Recognition","abstract":"Scalable, all-weather place recognition increasingly relies on heterogeneous radar place recognition to bridge diverse hardware platforms. A notable application is matching queries from cost-effective 4D automotive radars against high-fidelity reference maps built by dense spinning radars. This process is fundamentally limited by the extreme sparsity (and narrow field-of-view) of the 4D sensor, which captures only a fraction of the structural density present in the spinning radar database. Prior efforts address this issue by unifying different radar signals. That is, projecting both signals into a common representational space. Yet, they suffer performance degradation in multi-session environments. In this paper, we propose spatially-stratified distillation (SSD); a strategy that replaces standard uniform distillation with an asymmetric spatial alignment derived directly from physical radar returns. In regions where both radars exhibit overlapping returns, SSD enforces strong feature alignment. Crucially, in sparse regions where the 4D student lacks returns but the teacher contains valid structure within the shared field of view, SSD applies heavily discounted distillation weights. Extensive evaluations of the recent HeRCULES dataset demonstrate that SSD significantly outperforms prior place recognition methods, achieving state-of-the-art results on its challenging dynamic sequences.","authors":["Sagun Singh Shrestha","Samuel Harding","Abdelwahed Khamis","Saimunur Rahman","Peyman Moghadam"],"published":"2026-06-17T04:55:42Z","updated":"2026-06-17T04:55:42Z","abstract_url":"https://arxiv.org/abs/2606.18687v1","html_url":"https://arxiv.org/html/2606.18687v1","pdf_url":"https://arxiv.org/pdf/2606.18687v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18681v1","title":"Moving Beyond Diversity: Visual Token Pruning as Subspace Reconstruction for Efficient VLMs","abstract":"Despite their remarkable performance, Vision Language Models (VLMs) incur substantial computational overhead due to the large number of visual tokens. While diversity maximization has become a dominant strategy for token reduction, existing methods rely on cosine-based normalized similarity that discards magnitude information, failing to faithfully approximate the original feature representation and leading to suboptimal performance, particularly on compositional multi-skill reasoning tasks. In this paper, we introduce SPARE, a subspace reconstruction method that reformulates token pruning as a column subset selection problem and explicitly minimizes reconstruction error. By iteratively selecting tokens with large projection residuals, SPARE performs reconstruction-driven pruning beyond angular diversity. Moreover, we reveal a counterintuitive anti-relevance phenomenon: tokens with lower image-text relevance score can better preserve contextual information. Based on this finding, we incorporate anti-relevance into SPARE as an additional selection criterion to promote context-aware token selection. Extensive experiments across multiple VLMs and benchmarks demonstrate that SPARE consistently achieves state-of-the-art performance, with strong gains on compositional tasks. When applied to LLaVA, SPARE removes up to 94% of visual tokens while retaining 95% of the baseline performance, all in a fully training-free manner.","authors":["Jaeyeon Lee","Shunjie Wen","Dong-Wan Choi"],"published":"2026-06-17T04:45:10Z","updated":"2026-06-17T04:45:10Z","abstract_url":"https://arxiv.org/abs/2606.18681v1","html_url":"https://arxiv.org/html/2606.18681v1","pdf_url":"https://arxiv.org/pdf/2606.18681v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18676v1","title":"InTrain: Intrinsic Trainability for Zero-Cost Neural Architecture Search","abstract":"Training-free neural architecture search promises efficient discovery of high-performance networks without costly training. However, existing zero-cost proxies rely on fragmented heuristics that fail to capture the fundamental question: what makes an architecture trainable? This paper introduces Intrinsic Trainability (InTrain), a unified theoretical proxy that formalizes trainability as an architectural invariant emerging from two synergistic components: geometric capacity and optimization resilience. We operationalize intrinsic trainability through analysis of neural information processing. Geometric capacity is quantified via the participation ratio of activation covariance eigenspectrum, capturing the effective dimensionality of representation manifolds. Optimization resilience is measured through cumulative gradient health, assessing the robustness of backpropagation across network depth. InTrain synthesizes these dimensions through a scale-invariant multiplicative coupling, which we hypothesize is essential for capturing their synergistic, non-additive relationship. Extensive experiments on standard NAS benchmarks and search spaces demonstrate that InTrain achieves ranking correlations on par with state-of-the-art ensemble-based proxies and outperforms other single-metric methods.","authors":["Qinqin Zhou","Fuhai Chen","Jipeng Wu","Zhiwei Chen","Zhikai Hu","Weiwei Cai"],"published":"2026-06-17T04:22:00Z","updated":"2026-06-17T04:22:00Z","abstract_url":"https://arxiv.org/abs/2606.18676v1","html_url":"https://arxiv.org/html/2606.18676v1","pdf_url":"https://arxiv.org/pdf/2606.18676v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18661v1","title":"LandslideAgent with Multimodal LandslideBench: A Domain-Rule-Augmented Agent for Autonomous Landslide Identification and Analysis","abstract":"Intelligent landslide hazard interpretation is critical for disaster prevention, yet current paradigms struggle to simultaneously extract visual features and high-level geoscientific semantics, while general-purpose vision-language models (VLMs) suffer from perceptual limitations and domain hallucinations in complex geological scenarios. To address these challenges, we propose an instruction-driven agentic framework comprising three components. First, LandslideBench, a multimodal fine-grained dataset with seven subtype labels, high-resolution imagery, pixel-level masks, and high-quality textual descriptions, is constructed via multi-VLM cross-validation and interactive annotation. Then, LandslideVLM, a landslide-oriented VLM, is fine-tuned via LoRA on LandslideBench to enhance geological semantic understanding. Finally, LandslideAgent, a domain rule-enhanced agent taking LandslideVLM as its cognitive backbone, employs a dual-rule controller incorporating structured report metadata constraints and cross-validation identification constraints to regulate automated tool invocation. Experiments demonstrate that LandslideBench provides effective baselines across five mainstream models on fine-grained classification and semantic segmentation. LandslideVLM achieves accuracy improvements of 10.96%, 32.87%, and 15.91% on landslide discrimination, fine-grained classification, and semantic description quality, respectively. LandslideAgent further enables autonomous multi-source spatial data inference, realizing full-process intelligence for landslide identification and analysis.","authors":["Chengfu Liu","Dongyang Hou","Junwu Xiang","Cheng Yang","Xuezhi Cui","Zeyuan Wang","Liangtian Liu","Zelang Miao"],"published":"2026-06-17T04:00:59Z","updated":"2026-06-17T04:00:59Z","abstract_url":"https://arxiv.org/abs/2606.18661v1","html_url":"https://arxiv.org/html/2606.18661v1","pdf_url":"https://arxiv.org/pdf/2606.18661v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18658v1","title":"On-Manifold Variational Learning with Heat-Kernel Priors","abstract":"Learning unsupervised representations of medical imaging cohorts can reveal clinically meaningful prototypes without expert labels, which are often noisy and fail to capture true pathological heterogeneity. However, existing deep latent-variable models estimate Gaussian mixture priors via Euclidean averaging, producing prototypes that drift off the curved data manifold and degenerate as the number of sub-populations grows. We propose a manifold-anchored variational framework built on a geometry-aware Expectation-Maximization (EM) algorithm, whose M-step selects each sub-population prototype as the graph medoid with the highest diffusion centrality on a heat-kernel-weighted latent graph, ensuring that every prototype remains on-manifold. A Dirichlet energy regularizer enforces geometric smoothness of the latent space, and a per-sub-population uncertainty score enables label-free quality assessment. \\rev{The manifold-anchored EM is a general-purpose geometric tool that extends standard EM and applies readily to other latent-variable models beyond this setting.} On cardiac scar and brain MRI benchmarks, our framework attains the highest accuracy among all compared methods, produces the sharpest prototypes reported to date, and remains stable at large sub-population counts where all baselines degenerate.","authors":["Jiarui Xing","Tal Zeevi","Nian Wu","Jian Wang"],"published":"2026-06-17T03:55:16Z","updated":"2026-06-17T03:55:16Z","abstract_url":"https://arxiv.org/abs/2606.18658v1","html_url":"https://arxiv.org/html/2606.18658v1","pdf_url":"https://arxiv.org/pdf/2606.18658v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18623v1","title":"Intrinsic 4D Gaussian Segmentation from Scene Cues","abstract":"Dynamic 4D Gaussian Splatting reconstructs deforming scenes with high fidelity and is increasingly adopted as a representation for dynamic 3D scenes. Putting such a scene to use, for editing, manipulation or motion analysis, first requires segmenting it: grouping the Gaussian primitives into coherent objects. Current pipelines obtain this grouping by importing 2D masks from foundation models such as SAM and lifting or distilling them into the Gaussian representation. In dynamic scenes these masks must be generated across many frames and views, which is costly, and the resulting segmentation can depend strongly on the quality and consistency of those external masks. We ask how much object-level structure can instead be recovered from the Gaussians themselves, and propose Intrinsic-GS, a training-free, mask-free method that builds a sparse affinity graph over Gaussian primitives from appearance, orientation, scale, deformation-trajectory and non-learned rendered-boundary cues. The graph is partitioned with Leiden community detection, requiring no foundation model and no learned feature field. On the standard 4D Gaussian segmentation benchmarks, Neu3D and HyperNeRF, Intrinsic-GS recovers substantial object structure without mask supervision, reaching 0.746 mIoU on Neu3D and 0.575 on HyperNeRF; on Neu3D, a geometry-only variant reaches 0.902 mIoU, matching SAM-supervised TRASE. On HyperNeRF, Intrinsic-GS runs 12.5x faster than the mask-generation and feature-rendering stages used by mask-supervised pipelines. These results suggest that much of the segmentation signal is already encoded in the Gaussians themselves, offering a fast, mask-free direction for 3D and 4D Gaussian segmentation that may also point toward more generalizable, robust segmentation in settings where external masks are unreliable or expensive.","authors":["Hasan Yazar","Mohamed Rayan Barhdadi","Erchin Serpedin","Mehmet Tuncel","Hasan Kurban"],"published":"2026-06-17T02:40:35Z","updated":"2026-06-17T02:40:35Z","abstract_url":"https://arxiv.org/abs/2606.18623v1","html_url":"https://arxiv.org/html/2606.18623v1","pdf_url":"https://arxiv.org/pdf/2606.18623v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18610v1","title":"SC3-Eval: Evaluating Robot Foundation Models via Self-Consistent Video Generation","abstract":"Evaluating generalist robot manipulation policies in the real world is expensive, slow, and difficult to scale. Action-conditioned video world models offer a scalable alternative by simulating policy rollouts. Autoregressive rollouts accumulate compounding errors, observations across multiple camera views must remain mutually consistent, and the evaluator must generalize to policies whose behaviors lie outside the training distribution. We address these challenges with SC3-Eval, a self-consistent video generation recipe that adapts a pre-trained video foundation model into an accurate policy evaluator by enforcing three complementary forms of consistency. First, forward-inverse dynamics consistency jointly trains the model to predict frames from actions and to recover actions from frames, anchoring generated rollouts to a physically plausible action manifold and counteracting the drift a forward-only model cannot penalize. Second, cross-view consistency trains the model to inpaint each camera view from the other, keeping the multi-camera observation coherent over long rollouts without any explicit memory mechanism. Third, test-time consistency reuses the inverse dynamics mode at inference as a per-action-chunk uncertainty signal that terminates rollouts whose generated frames drift away from the requested actions. We also demonstrate SC3-Eval rollouts reproduce the failure modes that policies exhibit in real-world rollouts, supporting fine-grained diagnostic comparison rather than aggregate ranking alone. Across seven real-world vision-language-action policies, SC3-Eval attains a closed-loop Pearson correlation of $0.929$ and MMRV of $0.119$, outperforming three strong prior video-model-based baselines, and generalizes to new tasks.","authors":["Wei-Cheng Tseng","Gashon Hussein","Yuzhu Dong","Allen Z. Ren","Lucy X. Shi","XuDong Wang","Sergey Levine","Zhaoshuo Li","Jinwei Gu","Florian Shkurti","Ming-Yu Liu","Quan Vuong"],"published":"2026-06-17T02:15:46Z","updated":"2026-06-17T02:15:46Z","abstract_url":"https://arxiv.org/abs/2606.18610v1","html_url":"https://arxiv.org/html/2606.18610v1","pdf_url":"https://arxiv.org/pdf/2606.18610v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18591v1","title":"Bridging Creative Intent and Visual Quality: Creator-Driven Recurrent Video Generation with Agentic Feedback Loops","abstract":"Generative AI has made content creation increasingly accessible, but many AI-generated videos lack narrative coherence and creative direction, issues that become more substantial at longer durations. Unlike coding, where AI generation benefits from reliable feedback and techniques such as recurrent self-improvement, video generation requires subjective feedback about plot, scenes, and narrative, which naturally motivates approaches that incorporate human creative direction. We introduce CHIEF, a human-AI co-creation video generation framework that places the creator at the center of human-in-the-loop iterative video refinement, and supports them by providing automatic subjective feedback. The creator incorporates their creative direction by driving each iteration, while their revisions are incorporated by a specialized refiner agent. The feedback loop is generated by persona-conditioned multimodal LLMs that watch generated videos and produce subjective critique from the audience perspectives, providing feedback that self-evaluation alone cannot capture. To test the effectiveness of our proposed framework, we work with high school and college students with no prior filmmaking experience to create videos, from short 1-minute videos to a complete short 10-minute film with a complicated plot.","authors":["Denis Savytski","Aiden Lei","Heding Liu","Warren Yang","Sihan Liang","Alexander Liu","Zhe Zhao"],"published":"2026-06-17T01:39:30Z","updated":"2026-06-17T01:39:30Z","abstract_url":"https://arxiv.org/abs/2606.18591v1","html_url":"https://arxiv.org/html/2606.18591v1","pdf_url":"https://arxiv.org/pdf/2606.18591v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18588v1","title":"Splaxel: Efficient Distributed Training of 3D Gaussian Splatting for Large-scale Scene Reconstruction via Pixel-level Communication","abstract":"3D Gaussian Splatting (3DGS) enables high-fidelity and real-time 3D scene reconstruction, but scaling training to large-scale scenes requires optimizing hundreds of millions of Gaussians across multiple GPUs. Existing distributed approaches either partition scenes into isolated regions, causing global inconsistency, or rely on global Gaussian-level exchanges, which lead to substantial growth in inter-GPU communication and quickly dominate iteration time. We propose Splaxel, a communication-efficient distributed 3DGS training framework based on pixel-level local rendering and global composition. Instead of synchronizing Gaussians, each GPU renders its local subset and exchanges only partial pixel values, maintaining mathematical consistency while keeping communication cost stable as the scene size increases. Splaxel further reduces pixel-level redundancy through geometric and transmittance visibility prediction and improves GPU utilization via conflict-free camera-view consolidation. Evaluated on large-scale datasets with up to 120M Gaussians, Splaxel achieves up to 7.6$\\times$ speedup over the state-of-the-art distributed 3DGS framework while preserving high reconstruction quality.","authors":["Wenqi Jia","Zhewen Hu","Ying Huang","Yu Gong","Stavros Kalafatis","Yuke Wang","Wei Niu","Chengming Zhang","Ang Li","Sheng Di","Yuede Ji","Bo Fang","Miao Yin"],"published":"2026-06-17T01:27:41Z","updated":"2026-06-17T01:27:41Z","abstract_url":"https://arxiv.org/abs/2606.18588v1","html_url":"https://arxiv.org/html/2606.18588v1","pdf_url":"https://arxiv.org/pdf/2606.18588v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18586v1","title":"APT: Atomic Physical Transitions for Causal Video-Language Understanding","abstract":"Physical events are not understood by their names alone, but by the causal state changes that compose them. A clip-level label such as \"bounce\" can be correct while hiding the process that makes the event physically valid, from support loss and contact onset to rebound and settling. To make this hidden process explicit, we introduce Atomic Physical Transitions (APTs): minimal, temporally localized state changes that bind a visible cue to an active physical mechanism and before/after dynamical regimes. An APT chain represents a video as an ordered causal transition sequence rather than a single aggregate event label: event labels tell what happened; APT chains explain why it happened. To make APTs learnable by VLMs, we construct mixed-source APT data from human annotations and simulator ground truth, covering 14 transition types across contact, gravity, friction, and rotation/stability, with 27,303 timed instances over 1,246 trials. Using this data, we find that current VLMs miss transition-level physics, with zero-shot recall at most 14% and errors dominated by missed transitions. Direct fine-tuning on APT chains improves transition detection but causes event-level forgetting, indicating that the model learns a specialized answer format rather than a reusable physical representation. We therefore propose APT-Tune, a parameter-efficient recipe that teaches VLMs to use causal transitions without forgetting how to answer video questions. It combines image-pad-aware supervision, format-conditional co-training, and mechanism-conditioned domain-to-type decoding to make APT learning format-robust and physically grounded. With only 11 M LoRA parameters on Qwen3-VL-2B, APT-Tune substantially improves APT recall while also improving event-level video transfer. These results show that APTs are not a new answer format, but a human-aligned causal supervision signal for physical video understanding.","authors":["Shang Wu","Haoran Lu","Songling Liu","Chenwei Xu","Lie Lu","Pranav Maneriker","Fan Du","Manling Li","Zhaoran Wang","Han Liu"],"published":"2026-06-17T01:26:50Z","updated":"2026-06-17T01:26:50Z","abstract_url":"https://arxiv.org/abs/2606.18586v1","html_url":"https://arxiv.org/html/2606.18586v1","pdf_url":"https://arxiv.org/pdf/2606.18586v1.pdf","matched_keywords":["video","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18583v1","title":"Aerial-ground LiDAR place recognition with patch-level self-supervised learning and expanded reciprocal re-ranking","abstract":"LiDAR place recognition determines one's position on a prior point cloud map. The most studied ground-level LiDAR place recognition suffers from pre-visit requirements, incomplete coverage, and limited perspectives. Using pre-acquired, full-coverage Airborne Laser Scanning (ALS) data as an aerial prior map overcomes these drawbacks, making cross-view place recognition necessary and advantageous. However, aerial-ground LiDAR place recognition faces significant challenges, including the domain gap between aerial and ground point clouds, and false positives during initial retrieval. To address these challenges, we present a novel retrieval and re-ranking framework for aerial-ground LiDAR place recognition. Based on the priors that neighboring point cloud patches share similar semantics with anchor patch, our retrieval network introduces patch-level self-supervised learning modules at multiple scales and integrates with scene-level learning to improve global feature discriminativeness between aerial and ground point clouds. Furthermore, leveraging the structured spatial distribution of ALS point clouds, we introduce an Expanded Reciprocal (ER) re-ranking algorithm to exploit neighborhood information maximally and refine each feature based on neighbor features, which are then used to update the similarity matrix for final ranking. Extensive experiments demonstrate that our retrieval network outperforms existing state-of-the-art (SOTA) methods, achieving a 9.8\\% improvement in average Recall@1 and a 3.2\\% improvement in average Recall@1\\% on the CS-Urban-Scenes, while also showing the best performance on the CS-Campus3D dataset. Additionally, our ER re-ranking algorithm further boosts the average Recall@1 by 4.9\\% on CS-Campus3D and 10.2\\% on CS-Urban-Scenes without additional training.","authors":["Yandi Yang","Xianghong Zou","Jianping Li","Haofeng Xie","Saurav Uprety","Hongzhou Yang","Naser El-Sheimy"],"published":"2026-06-17T01:22:27Z","updated":"2026-06-17T01:22:27Z","abstract_url":"https://arxiv.org/abs/2606.18583v1","html_url":"https://arxiv.org/html/2606.18583v1","pdf_url":"https://arxiv.org/pdf/2606.18583v1.pdf","matched_keywords":["retrieval","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18566v1","title":"Multi-Modal Hyper-Graph Fusion for Low-Light Crowd Counting","abstract":"Crowd counting is a fundamental task in computer vision. However, crowd counting in low-light environments remains largely underexplored, despite its practical importance in the real world. Existing methods mainly focus on well-lit scenes or rely on single-modality Red-Green-Blue (RGB) representations, which often become unreliable under extreme darkness and complex non-uniform illumination. To handle this problem, we construct three new low-light crowd counting benchmarks, which consist of two synthetic datasets, SHA\\_Dark and SHB\\_Dark, and a real-world benchmark LC-Crowd (Low-light Crowd Dataset). Inspired by Retinex-based physical modeling, we introduce depth and Canny edge cues as complementary geometric and structural priors to enhance the intrinsic reflectance representation under low-light conditions. We propose a Multi-Modal Hyper-Graph Fusion module, which formulates RGB appearance, depth geometry, and edge structure cues as nodes in a unified hyper-graph and explicitly captures their high-order complementary relationships via dynamic hyperedge construction and message passing. Furthermore, to adaptively allocate computation in dense prediction, we propose a Deformable Rectangular Sparse Attention (DRSA) module, which concentrates computation on informative regions through anchor-aware estimation and adaptive rectangular window modeling. Based on these designs, we develop a unified Low-Light Counting Network (LCNet) for robust low-light crowd counting. Extensive experiments on three benchmarks demonstrate that the proposed method achieves the best overall performance against existing state-of-the-art (SOTA) methods. The code is in the supplementary material. The datasets will be made public upon acceptance.","authors":["Hao-Yuan Ma","Li Zhang","Yushi Qiu","Jie Gao","Yan Zhang","Bangjun Wang"],"published":"2026-06-17T00:38:14Z","updated":"2026-06-17T00:38:14Z","abstract_url":"https://arxiv.org/abs/2606.18566v1","html_url":"https://arxiv.org/html/2606.18566v1","pdf_url":"https://arxiv.org/pdf/2606.18566v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18565v1","title":"Experimental Analysis of Neural Network-Based Image Classification on the CIFAR-10 Dataset","abstract":"An experimental investigation of neural image classification on the CIFAR-10 benchmark is presented through fully connected and convolutional network formulations. The analysis emphasizes the complete learning pipeline: image vectorization, normalization, one-hot class encoding, supervised loss minimization, learning-rate selection, mini-batch training, convolutional feature extraction, max-pooling, and validation-based generalization assessment. A convolutional architecture with six convolutional layers and three max-pooling stages is evaluated for ten training epochs using a batch size of 128 and an Adam optimizer with a learning rate of 0.001. The validation accuracy reaches approximately 74.77%, while the validation loss begins to increase after the middle of training despite continued reduction in training loss. The resulting behavior illustrates the practical difference between representation learning and memorization, and it provides a compact experimental baseline for future studies on regularization, data augmentation, deeper architectures, and reproducible image-classification education.","authors":["Necati Kagan Erkek","Emre Balci","Berkin Halay"],"published":"2026-06-17T00:35:27Z","updated":"2026-06-17T00:35:27Z","abstract_url":"https://arxiv.org/abs/2606.18565v1","html_url":"https://arxiv.org/html/2606.18565v1","pdf_url":"https://arxiv.org/pdf/2606.18565v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18558v1","title":"MolmoMotion: Forecasting Point Trajectories in 3D with Language Instruction","abstract":"Motion forecasting is central to visual intelligence: agents must anticipate how objects will move in order to plan actions, reason about physical interactions, and synthesize realistic futures. We argue that 3D points in world coordinates provide a general representation that is class-agnostic, view-stable, compact, and directly useful for downstream tasks. We formalize the task of goal-conditioned 3D point motion forecasting: given a short visual history, a set of 3D query points on an object of interest, and a language description of the intended goal, the model predicts the future 3D trajectory of each point. We introduce a full stack to study this task at scale: (1) MolmoMotion-1M is a large corpus of action-described, object-grounded 3D point trajectories annotated from 1.16M unconstrained videos; (2) PointMotionBench is a human-verified benchmark spanning 111 object categories and 61 motion types; and (3) MolmoMotion is a general motion forecasting model that supports both autoregressive coordinate prediction and flow-matching-based trajectory generation. MolmoMotion accurately predicts diverse motion patterns with different language instructions, and significantly outperforms existing motion prediction baselines on PointMotionBench. Finally, we show that the learned 3D motion prior transfers well to downstream applications: it improves training efficiency and generalization for robot manipulation, and its predicted trajectories provide effective motion guidance for generative models to synthesize videos with more realistic object motion.","authors":["Jianing Zhang","Chenhao Zheng","Yajun Yang","Max Argus","Rustin Soraki","Winson Han","Taira Anderson","Chun-Liang Li","Shuo Liu","Jiafei Duan","Zhongzheng Ren","Jieyu Zhang","Ranjay Krishna"],"published":"2026-06-17T00:19:00Z","updated":"2026-06-17T00:19:00Z","abstract_url":"https://arxiv.org/abs/2606.18558v1","html_url":"https://arxiv.org/html/2606.18558v1","pdf_url":"https://arxiv.org/pdf/2606.18558v1.pdf","matched_keywords":["video","3d","agent","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18555v1","title":"Rethinking Text-to-Image as Semantic-Aware Data Augmentation for Indoor Scene Recognition","abstract":"In the realm of computer vision, indoor image recognition presents challenges due to the intricate interplay of lighting conditions, occlusions, and diverse object arrangements within confined spaces. To address the lacks of training indoor images, we introduce a novel approach leveraging Stable Diffusion (SD) for the generation of synthetic images, which serve as a powerful data augmentation tool. The utilization of SD offers a principled framework for synthesizing diverse and realistic indoor scenes, thereby enriching the training data pool for robust indoor image recognition models. Experimental findings on the MIT Indoor Scene dataset reveal the potential of our proposed approach in enhancing the training of deep models when authentic data is limited. Furthermore, to prevent the misuse of SD synthetic images, we introduce a counter measure based on DIffusion Reconstruction Error (DIRE). The powerful DIRE presentation enables training robust classifiers only using lightweight deep models. Experiments show that our approach can perfectly recognize SD generated images with the accuracy of 100% using MobilenetV3.","authors":["Trong-Vu Hoang","Quang-Binh Nguyen","Dinh-Khoi Vo","Hoai-Danh Vo","Minh-Triet Tran","Trung-Nghia Le"],"published":"2026-06-17T00:08:56Z","updated":"2026-06-17T00:08:56Z","abstract_url":"https://arxiv.org/abs/2606.18555v1","html_url":"https://arxiv.org/html/2606.18555v1","pdf_url":"https://arxiv.org/pdf/2606.18555v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18554v1","title":"Forged Calamity: Benchmark for Cross-Domain Synthetic Disaster Detection in the Age of Diffusion","abstract":"The rapid advancement of text-to-image diffusion models has enabled the creation of highly photorealistic synthetic images that closely resemble real photographs, making it increasingly difficult to distinguish authentic content from AI-generated fabrications. This poses challenges for cybersecurity, digital forensics, and disaster response, where fake imagery of floods, fires, or earthquakes can spread misinformation or disrupt emergency operations. To address this, we introduce Forged Calamity, a benchmark dataset for synthetic disaster detection containing 30,000 images, including 6,000 real and 24,000 synthetic samples generated by four diffusion models. Comprehensive experiments across fine-tuned and zero-shot settings reveal consistent weaknesses in current forensic approaches. Fine-tuned detectors perform well in-distribution but lose up to 50\\% accuracy on unseen generators or disaster types, showing overfitting to model-specific artifacts. Zero-shot generalized detectors also struggle to maintain stable accuracy, with only limited resilience in a few representation-robust models. These findings highlight persistent generalization gaps and the urgent need for domain- and model-agnostic detection methods to ensure visual authenticity in the diffusion era.","authors":["Duc-Manh Phan","Quoc-Duy Tran","Duy-Khang Do","Anh-Tuan Vo","Hai-Dang Nguyen","Trong Le Do","Mai-Khiem Tran","Vinh-Tiep Nguyen","Tam V. Nguyen","Isao Echizen","Minh-Triet Tran","Trung-Nghia Le"],"published":"2026-06-17T00:08:35Z","updated":"2026-06-17T00:08:35Z","abstract_url":"https://arxiv.org/abs/2606.18554v1","html_url":"https://arxiv.org/html/2606.18554v1","pdf_url":"https://arxiv.org/pdf/2606.18554v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18553v1","title":"Hierarchical Multi-Modal Retrieval for Knowledge-Grounded News Image Captioning","abstract":"Traditional image captioning methods often struggle to generate comprehensive, context-rich descriptions, especially for details not directly observable from visual cues. To overcome this, we propose a novel retrieval-augmented image captioning framework that generates captions with deeper insights, such as object attributes, event context, and underlying significance, by leveraging external knowledge. Our approach features a hierarchical multi-modal article retrieval mechanism that moves beyond monolithic text entities. This retrieval considers article structure-aware features, including weighted textual components (e.g., headlines, body sections) and visual placement patterns, alongside multi-faceted similarity computations (content--visual, visual--visual, and discourse positioning). A subsequent contextual relevance refinement stage further enhances the retrieved information. The retrieved articles then serve as the knowledge base for caption generation: first, a VLM generates a concise image description; second, we segment relevant information from the retrieved articles based on this description; and finally, an LLM utilizes both the description and extracted knowledge to generate a comprehensive, contextually detailed caption. We participated in the ACM Multimedia EVENTA 2025 Challenge and achieved 5th place with an overall score of 0.2824 on the private test set of the OpenEvent-V1 dataset. Source code is publicly released at https://github.com/mf0212/EVENTA-Challange.","authors":["Minh-Loi Nguyen","Xuan-Vu Le","Long-Bao Nguyen","Hoang-Bach Ngo","Trung-Nghia Le"],"published":"2026-06-17T00:08:17Z","updated":"2026-06-17T00:08:17Z","abstract_url":"https://arxiv.org/abs/2606.18553v1","html_url":"https://arxiv.org/html/2606.18553v1","pdf_url":"https://arxiv.org/pdf/2606.18553v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-06-18T05:51:51+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":65,"new_or_recent_papers":[{"id":"2606.19341v1","title":"Native Active Perception as Reasoning for Omni-Modal Understanding","abstract":"Passive models for long video understanding typically rely on a \"watch-it-all\" paradigm, processing frames uniformly regardless of query difficulty, causing computational cost to grow with video duration. Although interactive frameworks have emerged, they often rely on global pre-scanning, and their context cost still scales with video length. We propose OmniAgent, the first native omni-modal agent that formulates video understanding as a POMDP-based iterative Observation-Thought-Action cycle. OmniAgent executes on-demand actions to selectively distill audio-visual cues into a persistent textual memory, effectively decoupling reasoning complexity from raw video duration. To operationalize this, we introduce (1) Agentic Supervised Fine-Tuning to bootstrap native active perception via best-of-N trajectory synthesis with dual-stage quality control, and (2) Agentic Reinforcement Learning with TAURA (Turn-aware Adaptive Uncertainty Rescaled Advantage), which leverages turn-level entropy to steer credit assignment toward pivotal discovery turns. Crucially, OmniAgent exhibits positive test-time scaling, where performance improves as the number of reasoning turns increases, validating the efficacy of active perception. Empirical results across ten benchmarks (e.g., VideoMME, LVBench) demonstrate that OmniAgent achieves state-of-the-art performance among open-source models. Notably, on LVBench, our 7B agent outperforms the 10$\\times$ larger Qwen2.5-VL-72B (50.5% vs. 47.3%).","authors":["Zhenghao Xing","Ruiyang Xu","Yuxuan Wang","Jinzheng He","Ziyang Ma","Qize Yang","Yunfei Chu","Jin Xu","Junyang Lin","Chi-Wing Fu","Pheng-Ann Heng"],"published":"2026-06-17T17:59:56Z","updated":"2026-06-17T17:59:56Z","abstract_url":"https://arxiv.org/abs/2606.19341v1","html_url":"https://arxiv.org/html/2606.19341v1","pdf_url":"https://arxiv.org/pdf/2606.19341v1.pdf","matched_keywords":["video","agent"],"source_used":"html","source_text_chars":90455,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent 相关；摘要显示其主要贡献为：Passive models for long video understanding typically rely on a \"watch-it-all\" paradigm, processing frames uniformly regardless of query difficulty, causing computational cost to grow with video duration. Although interactive frameworks have emerged, they oft...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:52+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19338v1","title":"Beyond the Current Observation: Evaluating Multimodal Large Language Models in Controllable Non-Markov Games","abstract":"Deploying multimodal foundation models as closed-loop policies increasingly requires conditioning actions on observations that are no longer visible. However, existing benchmarks either expose the full state, conflate hidden-state reconstruction with other agent skills, or test recall only after an episode has ended. We introduce RNG-Bench (Reconstructive Non-Markov Games), a benchmark suite designed to isolate a base model's ability to reconstruct past observations and act on them during multi-step interaction. RNG-Bench includes two complementary games: Matching Pairs, where card identities briefly revealed at specific locations must later be recalled, and 3D Maze, where egocentric views must be integrated into a spatial map. Both games are evaluated under a unified harness with three controlled difficulty axes: grid size, visual pattern, and observation modality. The benchmark further introduces a head-to-head duel protocol to control for instance-level variance and a Memory Gap metric that disentangles forgetting from poor action selection. The hardest configurations require contexts of roughly 128K tokens and 350 image inputs per episode, and remain far from saturated by frontier MLLMs. Memory Gap analysis shows that most residual errors stem from forgetting earlier observations rather than from suboptimal decision making. Finally, fine-tuning Qwen3.5-9B on optimal-policy rollouts and filtered model demonstrations improves performance on RNG-Bench and transfers to existing benchmarks without degrading general multimodal capability.","authors":["Shengyuan Ding","Xilin Wei","Xinyu Fang","Haodong Duan","Dahua Lin","Jiaqi Wang","Yuhang Zang"],"published":"2026-06-17T17:59:34Z","updated":"2026-06-17T17:59:34Z","abstract_url":"https://arxiv.org/abs/2606.19338v1","html_url":"https://arxiv.org/html/2606.19338v1","pdf_url":"https://arxiv.org/pdf/2606.19338v1.pdf","matched_keywords":["3d","agent","instance","multimodal"],"source_used":"html","source_text_chars":97802,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, agent, instance, multimodal 相关；摘要显示其主要贡献为：Deploying multimodal foundation models as closed-loop policies increasingly requires conditioning actions on observations that are no longer visible. However, existing benchmarks either expose the full state, conflate hidden-state reconstruction with other ag...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:52+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19333v1","title":"Do as I Do: Dexterous Manipulation Data from Everyday Human Videos","abstract":"How can we scalably generate data for robotic manipulation, especially on human-like platforms such as dexterous multi-fingered hands? Learning from human videos has recently emerged as a likely answer to this question. However, difficulties in estimating hand-object interaction and crossing the human-to-robot embodiment gap have hindered the adoption of abundant monocular RGB-only human videos as the primary source of robot manipulation data. In this work, we present DO AS I DO, an algorithm to reconstruct and retarget monocular RGB human videos to multi-fingered dexterous robotic hands. DO AS I DO reconstructs hand-object interactions from various egocentric and exocentric in-the-wild video sources. The algorithm then retargets these hand-object interaction estimates into a sequence of actions executable in the real world, yielding robot-complete manipulation data from disparate human videos. Overall, DO AS I DO outperforms previous state of the art in estimating hand-object interactions and extracting dexterous manipulation trajectories from RGB videos, as we show in experiments on datasets with ground truths and on a dataset of video clips collected online. Our experiments enable us to propose an efficacy playbook for practitioners collecting human data for manipulation.","authors":["Bhawna Paliwal","Haritheja Etukuru","William Liang","Pieter Abbeel","Nur Muhammad Mahi Shafiullah","Jitendra Malik"],"published":"2026-06-17T17:57:34Z","updated":"2026-06-17T17:57:34Z","abstract_url":"https://arxiv.org/abs/2606.19333v1","html_url":"https://arxiv.org/html/2606.19333v1","pdf_url":"https://arxiv.org/pdf/2606.19333v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":64866,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：How can we scalably generate data for robotic manipulation, especially on human-like platforms such as dexterous multi-fingered hands? Learning from human videos has recently emerged as a likely answer to this question. However, difficulties in estimating han...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:52+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19316v1","title":"NeuMesh++: Towards Versatile and Efficient Volumetric Editing with Disentangled Neural Mesh-based Implicit Field","abstract":"Recently neural implicit rendering techniques have evolved rapidly and demonstrated significant advantages in novel view synthesis and 3D scene reconstruction. However, existing neural rendering methods for editing purposes offer limited functionalities, e.g., rigid transformation and category-specific editing. In this paper, we present a novel mesh-based representation by encoding the neural radiance field with disentangled geometry, texture, and semantic codes on mesh vertices, which empowers a set of efficient and comprehensive editing functionalities, including mesh-guided geometry editing, designated texture editing with texture swapping, filling and painting operations, and semantic-guided editing. To this end, we develop several techniques including a novel local space parameterization to enhance rendering quality and training stability, a learnable modification color on vertex to improve the fidelity of texture editing, a spatial-aware optimization strategy to realize precise texture editing, and a semantic-aided region selection to ease the laborious annotation of implicit field editing. Extensive experiments and editing examples on both real and synthetic datasets demonstrate the superiority of our method on representation quality and editing ability. Project page: https://zju3dv.github.io/neumeshplusplus/","authors":["Chong Bao","Yuan Li","Bangbang Yang","Yujun Shen","Hujun Bao","Zhaopeng Cui","Yinda Zhang","Guofeng Zhang"],"published":"2026-06-17T17:39:21Z","updated":"2026-06-17T17:39:21Z","abstract_url":"https://arxiv.org/abs/2606.19316v1","html_url":"https://arxiv.org/html/2606.19316v1","pdf_url":"https://arxiv.org/pdf/2606.19316v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":96651,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Recently neural implicit rendering techniques have evolved rapidly and demonstrated significant advantages in novel view synthesis and 3D scene reconstruction. However, existing neural rendering methods for editing purposes offer limited functionalities, e.g....","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19277v1","title":"A Unified Framework for Efficient Remote Sensing Visual Question Answering: Adapting Dual, Hybrid, and Encoder-Decoder Architectures","abstract":"Visual Question Answering (VQA) in the Remote Sensing (RS) domain presents unique challenges due to the high resolution, multi scale object distribution, and semantic complexity of aerial imagery. While general domain Foundation Models have achieved remarkable success, their direct application to RSVQA is hindered by massive domain shifts and the computationally prohibitive nature of full fine tuning. This study presents a comparative analysis of RS Adapter, a Parameter Efficient Fine Tuning (PEFT) strategy, applied across three distinct Vision Language Model (VLM) architectures: the Dual Encoder CLIP, the Encoder Decoder BLIP, and the Hybrid FLAVA. We introduce a unified architectural surgery pipeline that injects lightweight bottleneck adapters into the attention and MLP layers of frozen backbones, enabling rapid adaptation with less than 5 percent of trainable parameters. Experimental results on the high resolution RSVQA x dataset demonstrate that while all adapted models achieve convergence, the Hybrid FLAVA architecture offers a superior balance of multimodal reasoning and retrieval capabilities compared to its unimodal counterparts. Our findings establish a new baseline for resource efficient VQA in disaster assessment and urban monitoring.","authors":["Timothy Agboada","Shikha Chandel","Yadav Raj Ghimire","Leila Hashemi-Beni"],"published":"2026-06-17T16:52:26Z","updated":"2026-06-17T16:52:26Z","abstract_url":"https://arxiv.org/abs/2606.19277v1","html_url":"https://arxiv.org/html/2606.19277v1","pdf_url":"https://arxiv.org/pdf/2606.19277v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"html","source_text_chars":23606,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 retrieval, multimodal 相关；摘要显示其主要贡献为：Visual Question Answering (VQA) in the Remote Sensing (RS) domain presents unique challenges due to the high resolution, multi scale object distribution, and semantic complexity of aerial imagery. While general domain Foundation Models have achieved remarkabl...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19259v1","title":"A Multi-Domain Benchmark for Detecting AI-Generated Text-Rich Images from GPT-Image-2","abstract":"Text-rich images often contain privacy-sensitive, transactional, or decision-relevant information. As recent multimodal image generation models become increasingly capable of synthesizing realistic textual content and structured visual designs, detecting AI-generated text-rich images has become an important challenge for digital trust and content authenticity. Existing benchmarks, however, largely focus on object-centric images and provide limited coverage of scenarios where textual semantics and layout organization are central. In this paper, we introduce a multi-domain benchmark for detecting text-rich images generated by OpenAI's GPT Image 2. The benchmark contains 8,602 images across six representative categories: commercial posters, infographics, academic posters, receipts, tables, and UI screenshots. Using this benchmark, we evaluate five representative AI-generated image detectors in a zero-shot setting and analyze their overall, category-wise, and post-processing robustness. Our results show that detector performance is highly domain-dependent: methods that perform well in some categories often fail on others, and even the strongest conventional detector exhibits severe sensitivity to JPEG compression. We further conduct an exploratory evaluation with a multimodal vision-language model, revealing both its promise and its limitations on structured formats. These findings highlight the need for text- and layout-aware detection methods for modern AI-generated images. Our dataset is released at XXX.","authors":["Yijin Wang","Shuyi Wang","Wenhan Zhang","Yuqi Ouyang"],"published":"2026-06-17T16:37:16Z","updated":"2026-06-17T16:37:16Z","abstract_url":"https://arxiv.org/abs/2606.19259v1","html_url":"https://arxiv.org/html/2606.19259v1","pdf_url":"https://arxiv.org/pdf/2606.19259v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":44268,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Text-rich images often contain privacy-sensitive, transactional, or decision-relevant information. As recent multimodal image generation models become increasingly capable of synthesizing realistic textual content and structured visual designs, detecting AI-g...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19258v1","title":"CABLE: Cloud-Assisted Bandwidth-efficient LMM-based Encoding for V2X Systems","abstract":"Cloud-hosted large multimodal models (LMMs) can provide strong open-vocabulary perception for Vehicle-to-Everything systems, but naively transmitting full-resolution frames from edge to cloud causes severe communication overhead and high cloud-side prefill latency. We present CABLE, a cloud-assisted bandwidth-efficient LMM-based encoding framework for edge-cloud perception. CABLE propagates the previous cloud segmentation mask on the edge using ego-motion compensation, refines it with residual-motion cues, and consolidates disconnected regions via a corridor envelope to form a robust region of interest (ROI). Only ROI-masked images are uploaded, while the cloud segmentation output is fed back as the prior for the next frame, forming a mask-to-ROI-to-LMM feedback loop. Experiments on five datasets (nuScenes, WOD-ZB, Waymo, KITTI, and CADC) show consistent communication savings while largely preserving perception, achieving $73$--$87\\%$ ROI pixel-coverage reduction with $5$--$8\\times$ estimated LMM prefill speedup at a modest detection-quality trade-off relative to full-frame inference.","authors":["Haohua Que","Zhipeng Bao","Qianyi Wu","Handong Yao"],"published":"2026-06-17T16:35:23Z","updated":"2026-06-17T16:35:23Z","abstract_url":"https://arxiv.org/abs/2606.19258v1","html_url":"https://arxiv.org/html/2606.19258v1","pdf_url":"https://arxiv.org/pdf/2606.19258v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":46790,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Cloud-hosted large multimodal models (LMMs) can provide strong open-vocabulary perception for Vehicle-to-Everything systems, but naively transmitting full-resolution frames from edge to cloud causes severe communication overhead and high cloud-side prefill la...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19253v1","title":"OneCanvas: 3D Scene Understanding via Panoramic Reprojection","abstract":"Existing approaches to 3D scene understanding in Vision-Language Models (VLMs) either rely on complex, model-specific geometry encoders or large training budgets in pursuit of spatial reasoning. Instead, OneCanvas aggregates patch features from all views onto a single equirectangular panoramic canvas. Namely, each patch is unprojected to a 3D world coordinate using its depth and camera pose, then placed on the canvas at the continuous longitude and latitude of that point as seen from the canvas origin, with no rasterization or aggregation across overlapping views. A 3D position embedding of the patch's metric coordinates is added to its feature, restoring the depth lost when collapsing the world position to an angular canvas coordinate. Patches from all frames thus share one spatial coordinate system with no fusion or major architectural modifications of the backbone. The pretrained VLM consumes this representation as if it were an ordinary image. Because the canvas can be centered on any pose of interest, the same representation directly supports situated reasoning from a specific viewpoint, a common requirement in robotics and embodied AI. Thanks to this representation, we can also introduce a spatial pretraining curriculum: by procedurally placing patch features of objects, drawn from real images, at chosen 3D world positions on an otherwise empty canvas, we generate on-the-fly supervision spanning a broad range of spatial reasoning tasks, with answer distributions controlled to reduce spatial reasoning shortcuts. OneCanvas achieves state-of-the-art accuracy on SQA3D and VSI-Bench, and generalizes to out-of-distribution data on SPBench, using an order of magnitude less training compute than the strongest competing methods.","authors":["Bartłomiej Baranowski","Dave Zhenyu Chen","Matthias Nießner"],"published":"2026-06-17T16:29:19Z","updated":"2026-06-17T16:29:19Z","abstract_url":"https://arxiv.org/abs/2606.19253v1","html_url":"https://arxiv.org/html/2606.19253v1","pdf_url":"https://arxiv.org/pdf/2606.19253v1.pdf","matched_keywords":["3d","representation"],"source_used":"html","source_text_chars":67342,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Existing approaches to 3D scene understanding in Vision-Language Models (VLMs) either rely on complex, model-specific geometry encoders or large training budgets in pursuit of spatial reasoning. Instead, OneCanvas aggregates patch features from all views onto...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19249v1","title":"Transformer Geometry Observatory TGO-I: Spectral Geometry Observatory","abstract":"Despite the widespread adoption of Vision Transformers (ViTs) and their success across numerous computer vision applications, the fundamental understanding of their dimensional and representational geometry remains relatively underexplored. To address this gap, we introduce Transformer Geometry Observatory (TGO), a systematic framework of experiments and analysis pipelines designed to investigate the representational geometry and dynamics of Vision Transformers. TGO-I, the first installment of the framework, focuses on the spectral geometry of ViT representations. Using a ViT-Small/16 model trained on ImageNet-100, we analyze Effective Rank, Stable Rank, Participation Ratio, Spectral Entropy, Spectral Flatness, Spectral Anisotropy, covariance structure, eigenspectra, and singular value spectra throughout training. Our results reveal a consistent increase in dimensional utilization, accompanied by decreasing anisotropy, increasing spectral entropy, increasing participation ratio, and progressively flatter eigenspectra. Contrary to the common intuition that training should concentrate information into a small number of dominant directions, we observe a progressive redistribution of variance across representational dimensions. This phenomenon is particularly pronounced in the final CLS token representation, which exhibits the highest effective dimensionality and lowest anisotropy within the network.","authors":["Kaustubh Kapil","Kishor P. Upla"],"published":"2026-06-17T16:26:59Z","updated":"2026-06-17T16:26:59Z","abstract_url":"https://arxiv.org/abs/2606.19249v1","html_url":"https://arxiv.org/html/2606.19249v1","pdf_url":"https://arxiv.org/pdf/2606.19249v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":33638,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Despite the widespread adoption of Vision Transformers (ViTs) and their success across numerous computer vision applications, the fundamental understanding of their dimensional and representational geometry remains relatively underexplored. To address this ga...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19215v1","title":"GUMP-Net: An interpretable model-data-driven intelligent algorithm for multi-class pelvic segmentation","abstract":"Pelvic segmentation is one of the most important and fundamental research problems in precise and intelligent diagnosis and treatment, as well as surgical planning and navigation for pelvic fractures. By combining an improved geodesic active contour model with deep neural networks, we propose GUMP-Net, an interpretable model-data-driven intelligent algorithm for multi-class pelvic segmentation, in which three network modules are designed to constitute the overall segmentation framework together: the object detection module for automatic level set initialization, the edge detector module for learning an anatomy-aware edge detector function and the iteration module for deep level set evolution. Leveraging the advantages of level set representation and deep learning, GUMP-Net shows more accurate, robust and consistent segmentation performance, especially in small training data situation, compared to the state-of-the-art methods. Extensive experiments on pelvic datasets demonstrate the rationality and effectiveness of the proposed algorithm. Further experiments extended to ankle dataset indicate broader applications to other anatomies. The proposed algorithm not only provides an efficient segmentation method for complex fracture reduction, but also gives an interpretable geometric perspective for understanding deep learning segmentation.","authors":["Liheng Wang","Yinghui Zhang","Licheng Zhang","Hailin Xu","Qiyong Cao","Chong Chen"],"published":"2026-06-17T15:52:34Z","updated":"2026-06-17T15:52:34Z","abstract_url":"https://arxiv.org/abs/2606.19215v1","html_url":"https://arxiv.org/html/2606.19215v1","pdf_url":"https://arxiv.org/pdf/2606.19215v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":64519,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Pelvic segmentation is one of the most important and fundamental research problems in precise and intelligent diagnosis and treatment, as well as surgical planning and navigation for pelvic fractures. By combining an improved geodesic active contour model wit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19195v1","title":"Moebius: 0.2B Lightweight Image Inpainting Framework with 10B-Level Performance","abstract":"While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; however, extreme structural compression inevitably triggers a severe representation bottleneck. To conquer this, we propose Moebius, a highly efficient lightweight inpainting framework. We systematically reconstruct the diffusion backbone by introducing the Local-$λ$ Mix Interaction ($LλMI$) block. Comprising Local-$λ$ and Interactive-$λ$ modules, it elegantly summarizes spatial contexts and global semantic priors into fixed-size linear matrices, preserving complex latent interactions while drastically shedding parameters. Furthermore, to unlock the full representational capacity of this highly compact architecture, we synergistically pair it with an adaptive multi-granularity distillation strategy. Operating strictly within the latent space to avoid expensive pixel-space decoding, this strategy dynamically balances multiple gradient-based losses to achieve high-fidelity alignment. Extensive experiments across natural and portrait benchmarks demonstrate that this optimal synergy enables Moebius to rival or even surpass the generation quality of the 10B-level industrial generalist FLUX.1-Fill-Dev. Remarkably, Moebius achieves this using less than 2\\% of the parameters (0.22B vs. 11.9B) while delivering a $>15\\times$ acceleration in total inference time, setting a new efficiency standard for high-fidelity inpainting. Project page at https://hustvl.github.io/Moebius.","authors":["Kangsheng Duan","Ziyang Xu","Wenyu Liu","Xiaohu Ruan","Xiaoxin Chen","Xinggang Wang"],"published":"2026-06-17T15:35:38Z","updated":"2026-06-17T15:35:38Z","abstract_url":"https://arxiv.org/abs/2606.19195v1","html_url":"https://arxiv.org/html/2606.19195v1","pdf_url":"https://arxiv.org/pdf/2606.19195v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":90871,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：While 10B-level industrial foundation models have pushed the boundaries of image inpainting, their prohibitive computational costs severely hinder practical deployment. Constructing a highly optimized task-specific specialist offers a promising solution; howe...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:53+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19184v1","title":"When AUC Misleads: Polarization-Aware Evaluation of Deepfake Detectors under Domain Shift","abstract":"Recent advances in generative AI, such as diffusion models and face-swapping tools, have enabled the creation of highly realistic deepfakes, leading to real-world harms including financial fraud and non-consensual explicit content. In response, deepfake detection has become an active research area, with recent methods increasingly focusing on improving generalization to unseen manipulations. This is typically evaluated using the Area Under the ROC Curve (AUC) measured separately across multiple datasets. However, such an evaluation fails to reflect real-world scenarios where detectors face a mixture of data sources and varying artifact types. To address this limitation, we introduce a novel metric, Cross-dataset AUC (Cross-AUC) that averages per-domain AUCs with a measure of prediction polarization for taking into account the robustness to domain shift. The polarization extent is quantified by the Wasserstein Distance between class score distributions. Cross-AUC not only assesses the generalization capabilities of deepfake detectors under domain shifts more realistically, but it is also interpretable as it better explains the reason behind a drop in performance. Experiments performed on seven benchmark datasets demonstrate its practical relevance.","authors":["Dat Nguyen","Cosmin Radoi","Romain Hermary","Marcella Astrid","Nesryne Mejri","Enjie Ghorbel","Djamila Aouada"],"published":"2026-06-17T15:24:06Z","updated":"2026-06-17T15:24:06Z","abstract_url":"https://arxiv.org/abs/2606.19184v1","html_url":"https://arxiv.org/html/2606.19184v1","pdf_url":"https://arxiv.org/pdf/2606.19184v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":90580,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Recent advances in generative AI, such as diffusion models and face-swapping tools, have enabled the creation of highly realistic deepfakes, leading to real-world harms including financial fraud and non-consensual explicit content. In response, deepfake detec...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19162v1","title":"The Reward Was in Your Data All Along: Correcting Flow Matching with Discriminator-Guided RL","abstract":"Score- and flow-matching models often rely on preference-based reinforcement learning for two purposes: aligning with subjective preferences and, surprisingly, recovering properties such as visual realism and coherent object structure that matching-based training is intended to learn from the data itself. We argue that this reflects a structural mismatch. Matching losses measure $\\ell_2$ regression error on the velocity or score field under training-time marginals, a proxy poorly aligned with the visual and semantic properties that determine sample quality at inference. Given a reward aligned with these properties, RL sidesteps the mismatch by evaluating the model on its own samples and following the reward landscape directly. The challenge is to obtain such a reward without relying on human preferences, which are expensive and conflate data realism with annotator inclinations. We propose Discriminator-Guided RL (DRL). DRL trains a discriminator to separate data from base-model samples in a pretrained representation space and uses its logit as the reward in KL-regularized RL. The pretrained space restricts the discriminator to perceptually meaningful directions, and the logit estimates the log-likelihood ratio between data and model, which is the optimal reward for targeting the data distribution. Across SiT, JiT, REPA, and RAE, DRL reduces guidance-free FID (e.g., $9.38 \\to 2.62$ on SiT) and semantic-space FD (e.g., $88.2 \\to 19.3$ on DINOv3 for SiT), with consistent gains across all backbones, and improves human-preference rewards without training on them. It also yields a better Pareto frontier between preference reward and image fidelity under subsequent preference-based post-training, increasing alignment while reducing low-level artifacts such as oversaturation and excessive brightness.","authors":["Nicolas Beltran-Velez","Felix Friedrich","Zhang Xiaofeng","Reyhane Askari-Hemmat","Xiaochuang Han","Adriana Romero-Soriano","Michal Drozdzal"],"published":"2026-06-17T15:01:33Z","updated":"2026-06-17T15:01:33Z","abstract_url":"https://arxiv.org/abs/2606.19162v1","html_url":"https://arxiv.org/html/2606.19162v1","pdf_url":"https://arxiv.org/pdf/2606.19162v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":261555,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Score- and flow-matching models often rely on preference-based reinforcement learning for two purposes: aligning with subjective preferences and, surprisingly, recovering properties such as visual realism and coherent object structure that matching-based trai...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19156v1","title":"Hand-4DGS: Feed-Forward 3D Gaussian Splatting for 4D Hand Reconstruction from Egocentric Videos","abstract":"Dynamic 3D hand reconstruction from egocentric videos is essential for next-generation computing platforms such as AR/VR and AI glasses. Despite its importance, most prior works focus either on multi-view 3D hand reconstruction or on 4D human body reconstruction. Egocentric 4D hand reconstruction remains challenging due to fast head motion, rapid hand dynamics, severe occlusions, and inherent ambiguity from single-view observations. To address these challenges, we introduce Hand-4DGS, the first feed-forward framework for reconstructing dynamic 4D hands directly from egocentric videos, enabling both fast (~60 FPS) inference and strong generalization. Our approach incorporates a mesh-guided representation for structural priors and temporal convolutions to model dynamic motion. We evaluate our framework on two challenging egocentric datasets, H2O and ARCTIC, and demonstrate significant improvements over baselines. Our method benefits from the generalization capability of feed-forward networks and effective 2D image supervision through Gaussian splatting, without requiring expensive 3D hand pose ground-truth annotations.","authors":["Jeongmin Bae","Seoha Kim","Marc Pollefeys","Mahdi Rad","Youngjung Uh","Taein Kwon"],"published":"2026-06-17T14:58:37Z","updated":"2026-06-17T14:58:37Z","abstract_url":"https://arxiv.org/abs/2606.19156v1","html_url":"https://arxiv.org/html/2606.19156v1","pdf_url":"https://arxiv.org/pdf/2606.19156v1.pdf","matched_keywords":["video","3d","representation"],"source_used":"html","source_text_chars":58874,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, representation 相关；摘要显示其主要贡献为：Dynamic 3D hand reconstruction from egocentric videos is essential for next-generation computing platforms such as AR/VR and AI glasses. Despite its importance, most prior works focus either on multi-view 3D hand reconstruction or on 4D human body reconstruct...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19151v1","title":"The Market in the Model: Latent Diffusion as Neural Economy","abstract":"Valuable critique of generative image models within visual culture and the humanities has emphasized the role of datasets in shaping the images they produce. Yet, close studies of the ideological positions embedded into the mechanism of the models have been neglected, leaving them imagined as \"black boxes.\" In a bid to expand, rather than replace, dataset critique, this paper examines the mechanisms of the latent diffusion model in terms of the problems they were brought in to solve on behalf of computer vision engineers, and the decisions each component was tasked with automating. I interpret that ensemble through the histories of its parts and the theory of vision the system inscribes into every generated image. Drawing on Impett and Offert's notion of neural exchange value, I offer this analysis to argue that the model operates as a neural economy: a contained symbolic system that abstracts social communication into commensurable vectors as it transfers the social sphere into parcels for sale. Tracing the training and generation pipelines component by component reveals what each operation displaces, and how it further entrenches the logics of platform and attention economies over social communication. The paper warns that any critique fixated exclusively on copyright and commodity defenses risks reaffirming the very fetishism the model produces, and argues instead for centering social exchange.","authors":["Eryk Salvaggio"],"published":"2026-06-17T14:56:42Z","updated":"2026-06-17T14:56:42Z","abstract_url":"https://arxiv.org/abs/2606.19151v1","html_url":"https://arxiv.org/html/2606.19151v1","pdf_url":"https://arxiv.org/pdf/2606.19151v1.pdf","matched_keywords":["diffusion"],"source_used":"html","source_text_chars":65106,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 diffusion 相关；摘要显示其主要贡献为：Valuable critique of generative image models within visual culture and the humanities has emphasized the role of datasets in shaping the images they produce. Yet, close studies of the ideological positions embedded into the mechanism of the models have been n...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19120v1","title":"Seeing Before Reasoning: Decoupling Perception and Reasoning for Shortcut-Resilient Multimodal On-Policy Self-Distillation","abstract":"On-policy self-distillation (OPSD) trains a model on its own rollouts and uses a frozen copy to provide dense token-level targets conditioned on a reference target. This works well for LLM reasoning, but a direct extension to multimodal large language models (MLLMs) can create a shortcut: the privileged target may guide tokens mainly based on the text reference target rather than the image. We propose ViGOS, a visually grounded OPSD framework for MLLM post-training. The student first writes a visual description and then reasons toward the final answer. For valid rollouts, an image-only perception teacher supervises the description, while a privileged reasoning teacher supervises the reasoning and final answer on the same student prefix. A reference teacher is used only for invalid rollouts to recover the output format. Across general vision-language, expert reasoning, visual math, spatial grounding, and visual-language-prior benchmarks, ViGOS keeps the main benefits of OPSD and improves image-grounded behavior in shortcut-prone settings.","authors":["Sihan Wang","Xiyao Liu","Lianqing Liu","Zhi Han"],"published":"2026-06-17T14:33:38Z","updated":"2026-06-17T14:33:38Z","abstract_url":"https://arxiv.org/abs/2606.19120v1","html_url":"https://arxiv.org/html/2606.19120v1","pdf_url":"https://arxiv.org/pdf/2606.19120v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":82387,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：On-policy self-distillation (OPSD) trains a model on its own rollouts and uses a frozen copy to provide dense token-level targets conditioned on a reference target. This works well for LLM reasoning, but a direct extension to multimodal large language models...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19100v1","title":"AMALIA-VL: A Native European Portuguese Open-Source Vision and Language Model","abstract":"Large Vision and Language Models (LVLMs) have advanced rapidly, yet European Portuguese (pt-PT) remains systematically underserved by existing open-source multimodal models, which either conflate it with Brazilian Portuguese or severely under-represent it in their training data mixes. We introduce AMALIA-VL, the first open-source instruction-tuned LVLM built natively for pt-PT, pairing a high-resolution vision encoder with dynamic image tiling and a fully open pt-PT-optimized language model via a learned connector. We contribute with a purposefully designed three-stage training process - vision-language alignment, general visual instruction tuning, and preference optimization - together with a pt-PT-centric multimodal data mix combining curated and translated public datasets with novel datasets that address the near-total absence of European Portuguese multimodal resources. Our evaluation shows that AMALIA-VL establishes a strong baseline for open-source pt-PT LVLMs.We will release model weights, training data, and construction pipelines along with machine-translated pt-PT evaluation benchmarks to help democratize pt-PT LVLM development.","authors":["Diogo Glória-Silva","João Cardeira","Manuel Letras da Luz","Afonso Simplício","Gonçalo Vinagre","Diogo Tavares","Rafael Ferreira","Inês Calvo","Inês Vieira","David Semedo","João Magalhães"],"published":"2026-06-17T14:11:41Z","updated":"2026-06-17T14:11:41Z","abstract_url":"https://arxiv.org/abs/2606.19100v1","html_url":"https://arxiv.org/html/2606.19100v1","pdf_url":"https://arxiv.org/pdf/2606.19100v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":41743,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Large Vision and Language Models (LVLMs) have advanced rapidly, yet European Portuguese (pt-PT) remains systematically underserved by existing open-source multimodal models, which either conflate it with Brazilian Portuguese or severely under-represent it in...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19097v1","title":"DVANet: Degradation-aware Visual-prior Alignment Network for Image Restoration","abstract":"All-in-One image restoration aims to develop a unified restoration framework for handling diverse degradation types. Existing end-to-end methods usually regard the restoration process as a black-box mapping, lacking an explicit optimization interpretation. Although deep unfolding provides an interpretable iterative modeling paradigm for image restoration, existing methods mostly rely on fixed degradation assumptions or predefined degradation information, making them difficult to adapt to unified restoration requirements under complex degradations and locally damaged content. This limitation restricts their performance in degradation suppression and structural detail recovery. To address these issues, this paper proposes DVANet, a deep unfolding network inspired by the half-quadratic splitting optimization algorithm, which formulates unified image restoration under complex degradations as a collaborative unfolding process between degradation-aware observation consistency and visual-prior-guided reconstruction. Specifically, in the degradation-aware observation consistency branch, a degradation representation module is employed to extract global degradation attributes and local degradation cues, and degradation-conditioned mapping is used to enhance the model's adaptability to different degradation types. In the visual-prior-guided reconstruction branch, DINOv3 is introduced to provide structural and semantic information as hierarchical visual priors, thereby complementing the missing structural information in damaged regions and improving detail recovery. Extensive experiments demonstrate that DVANet achieves superior or competitive performance on multi-scenario degradation and cross-domain image restoration tasks, showing favorable degradation adaptability and generalization ability.","authors":["Yanjie Tu","Qingsen Yan","Axi Niu","Tao Hu","Haokui Zhang","Jiantao Zhou"],"published":"2026-06-17T14:09:39Z","updated":"2026-06-17T14:09:39Z","abstract_url":"https://arxiv.org/abs/2606.19097v1","html_url":"https://arxiv.org/html/2606.19097v1","pdf_url":"https://arxiv.org/pdf/2606.19097v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":85225,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：All-in-One image restoration aims to develop a unified restoration framework for handling diverse degradation types. Existing end-to-end methods usually regard the restoration process as a black-box mapping, lacking an explicit optimization interpretation. Al...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19073v1","title":"Taming I2V models for Image HOI Editing: A Cognitive Benchmark and Agentic Self-Correcting Framework","abstract":"Current image editing methods excel at static attributes but fail at complex Human-Object Interactions (HOI), a critical challenge unaddressed by existing benchmarks that conflate HOI with static attributes, relying on global metrics incapable of simultaneously assessing dynamic interaction validity and entangled human-object pair preservation. Thus, we first introduce HOI-Edit, a comprehensive benchmark with three progressive cognitive levels, which features an automated metric HOI-Eval that reliably evaluates instance-level interaction by letting VLM Q&A after thinking with images containing grounded Human-Object pairs. Considering the task's essence of remodeling dynamic relationships, we benchmark Image-to-Video (I2V) models, finding them inherently suited for dynamic editing due to their temporal generation capabilities. Crucially, beyond superior performance, this capability provides a \"replay of the failure process,\" offering unique diagnosability into why errors occur. We thus propose SCPE (Self-Correcting Process Editing), a novel, agentic self-correcting framework that constrains the generation of I2V models through iteratively refined prompts, enabling the generated videos to more accurately present the target HOI. Extracted frames from these videos are the final editing results. On HOI-Edit, SCPE achieves performance competitive with state-of-the-art (SOTA) editing models like Nano Banana on interaction. Code is available at https://github.com/oceanflowlab/HOI-Edit.","authors":["Jiayi Gao","Qingchao Chen","Yuxin Peng","Yang Liu"],"published":"2026-06-17T13:44:26Z","updated":"2026-06-17T13:44:26Z","abstract_url":"https://arxiv.org/abs/2606.19073v1","html_url":"https://arxiv.org/html/2606.19073v1","pdf_url":"https://arxiv.org/pdf/2606.19073v1.pdf","matched_keywords":["video","agent","instance"],"source_used":"html","source_text_chars":75750,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, instance 相关；摘要显示其主要贡献为：Current image editing methods excel at static attributes but fail at complex Human-Object Interactions (HOI), a critical challenge unaddressed by existing benchmarks that conflate HOI with static attributes, relying on global metrics incapable of simultaneous...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19067v1","title":"Sensor Configuration Matters: A Systematic Evaluation of Multimodal SLAM on Quadruped Robots","abstract":"Autonomous navigation of quadrupedal robots in diverse environments fundamentally relies on resilient Simultaneous Localization and Mapping (SLAM). While visual-inertial SLAM has matured across wheeled, handheld, and aerial platforms, a critical evaluation gap remains regarding how hardware-level sensor configurations affect performance under the aggressive dynamics of legged locomotion. Quadrupeds introduce distinct embodiment-induced sensory challenges, including foot-impact shocks, high-frequency mechanical vibrations, and rapid angular rotations, which degrade standard perception pipelines. To address this gap, we present a systematic evaluation of state-of-the-art visual, visual-inertial, and LiDAR-visual-inertial SLAM methods using the GrandTour dataset recorded on an ANYmal D quadruped. We isolate and quantify the impacts of camera modalities, shutter techniques, and inertial sensor tiers, analyzing their trade-offs across localization accuracy, algorithmic robustness, and computational resource utilization. Our empirical findings demonstrate that hardware selection has substantial influence on system resilience: stereo configurations consistently outperform monocular and RGB-D modalities, global shutter cameras significantly mitigate motion-induced tracking failures compared to rolling shutter cameras, and, crucially, standard inertial integration can degrade the performance of primarily vision-based frameworks under harsh legged locomotion. These insights additionally offer concrete design guidelines for tailoring custom sensor payloads to achieve dependable perception on agile legged systems.","authors":["Roberto Corlito","Fabian Schmidt","Nils Seibert","Markus Enzweiler","Abhinav Valada","Arne Roennau"],"published":"2026-06-17T13:41:07Z","updated":"2026-06-17T13:41:07Z","abstract_url":"https://arxiv.org/abs/2606.19067v1","html_url":"https://arxiv.org/html/2606.19067v1","pdf_url":"https://arxiv.org/pdf/2606.19067v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":47961,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：Autonomous navigation of quadrupedal robots in diverse environments fundamentally relies on resilient Simultaneous Localization and Mapping (SLAM). While visual-inertial SLAM has matured across wheeled, handheld, and aerial platforms, a critical evaluation ga...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-06-18T05:51:54+00:00","status":"fallback"},"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19062v1","title":"DREAM: Extending Vision-Language Models with Dual-Objective Encoding for Cross-Modal Retrieval","abstract":"In today's media-driven world, the exponential growth of video content across domains such as surveillance, education, and entertainment has made retrieving semantically relevant videos via natural language queries increasingly critical. Early video retrieval systems relied on handcrafted features or shallow cross-modal mappings, limiting their ability to capture complex semantics and temporal dynamics. While large-scale vision-language models have improved cross-modal alignment, challenges remain in modeling fine-grained temporal dependencies and nuanced linguistic structures. In this paper, we introduce DREAM: Dual-path Representation Enhancement and Alignment Model, a novel multimodal framework that addresses these limitations through enhanced visual and textual encoding. DREAM incorporates a hybrid language modeling strategy that combines masked and permuted language modeling objectives to capture both local and global linguistic semantics. On the visual side, we design a hierarchical vision encoder with cascaded group attention, which integrates spatial and temporal information through multi-stage token interaction and coarse-to-fine attention refinement. We validate DREAM through comprehensive evaluations on the widely-used MSRVTT, MSVD and LSMDC benchmark datasets, where it achieves new state-of-the-art R1 scores of 49.4%, 49.7% and 27.3%, respectively. Qualitative analyses further show the model's ability to maintain coherent attention across frames and align complex queries with dynamic video content. These findings underscore the effectiveness of hierarchical attention and dual-objective textual modeling in enabling robust, context-aware video retrieval, and pave the way for future research in advancing cross-modal representation learning.","authors":["Kaleem Ullah","Altaf Hussain","Muhammad Munsif","Sung Wook Baik"],"published":"2026-06-17T13:35:50Z","updated":"2026-06-17T13:35:50Z","abstract_url":"https://arxiv.org/abs/2606.19062v1","html_url":"https://arxiv.org/html/2606.19062v1","pdf_url":"https://arxiv.org/pdf/2606.19062v1.pdf","matched_keywords":["video","retrieval","representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19053v1","title":"Benchmarking Large Vision-Language Models on Fine-Grained Image Tasks: From Evaluation to Diagnosis","abstract":"Recent advancements in Large Vision-Language Models (LVLMs) have demonstrated remarkable multimodal perception and reasoning capabilities. While numerous benchmarks have evaluated LVLMs from holistic or task-specific perspectives, their capabilities on fine-grained image tasks-fundamental to computer vision-remain insufficiently understood. To address this gap, we introduce FG-BMK, a comprehensive fine-grained evaluation benchmark containing 1.01 million questions and 0.28 million images, covering diverse scenarios from common object-centric domains to specialized domains. FG-BMK jointly evaluates dialogue-level fine-grained semantic recognition and feature-level visual discriminability through human-oriented and machine-oriented paradigms, enabling diagnostic analysis of whether LVLM failures arise from insufficient visual representations, weak visual-to-semantic grounding, or limited fine-grained knowledge. Through extensive experiments on a diverse set of representative LVLMs/VLMs, we find that current LVLMs remain inadequate fine-grained recognizers, with failures arising from intertwined bottlenecks in visual representations, semantic grounding, modality alignment, and category-level knowledge. We further analyze training design factors for improving fine-grained capabilities and examine how visual and linguistic perturbations affect LVLM predictions. These findings provide diagnostic insights into the limitations of current LVLMs and offer guidance for future data construction and model design in developing more reliable LVLMs for fine-grained visual tasks. Our code is open-source and available at https://fg-bmk.github.io/.","authors":["Hong-Tao Yu","Chen-Wei Xie","Yuxin Peng","Serge Belongie","Xiu-Shen Wei"],"published":"2026-06-17T13:23:26Z","updated":"2026-06-17T13:23:26Z","abstract_url":"https://arxiv.org/abs/2606.19053v1","html_url":"https://arxiv.org/html/2606.19053v1","pdf_url":"https://arxiv.org/pdf/2606.19053v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.19019v1","title":"FlowObject: Flow Steering for Bridging Generative Priors and Reconstruction Fidelity","abstract":"Recovering complete 3D representations of objects from few casual image captures remains a significant challenge. Recent 3D generative models, particularly those based on Flow-Matching (FM), can synthesize high-quality textured assets; however, they often suffer from ''synthetic bias'' where learned priors override observational evidence, alongside a lack of alignment with the observed instance. Conversely, optimization-based methods like 3D Gaussian Splatting (3DGS) provide high fidelity on visible surfaces but fail to reason about unobserved geometry. In this paper, we present FlowObject, a framework that reformulates sparse-view 3D reconstruction as a training-free, guided inverse problem. Our approach applies a dual-space guidance strategy to steer the Ordinary Differential Equation (ODE) trajectory of a flow-matching model, enabling the completion of unseen regions through learned generative priors while enforcing strict consistency with real-world observations. By integrating a 3DGS refinement stage, FlowObject further bridges the gap between ''synthetic-looking'' generative outputs and photorealistic reconstructions. Comprehensive benchmarks on synthetic and real-world datasets demonstrate that current state-of-the-art methods often struggle to achieve geometric completeness and observational consistency simultaneously, especially under severe occlusions. In contrast, our method significantly outperforms state-of-the-art generative models and optimization-based frameworks in both geometric completeness and view-dependent appearance fidelity.","authors":["Yuchen Rao","Xuqian Ren","Yinyu Nie","Sayan Deb Sarkar","Biao Zhang","Vincent Lepetit","Friedrich Fraundorfer"],"published":"2026-06-17T12:42:09Z","updated":"2026-06-17T12:42:09Z","abstract_url":"https://arxiv.org/abs/2606.19019v1","html_url":"https://arxiv.org/html/2606.19019v1","pdf_url":"https://arxiv.org/pdf/2606.19019v1.pdf","matched_keywords":["3d","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18992v1","title":"Show, Don't Ask: Generative Visual Disambiguation for Composed Image Retrieval with Turn-Valid Coverage","abstract":"Composed image retrieval (CIR) uses a reference image and a text modification to search for a target image. However, such queries often describe several possible images rather than one exact target, making the user's intent ambiguous. Recent methods address this by using conformal prediction to estimate ambiguity and by asking users clarifying text questions. However, these methods have two limitations: their coverage guarantee only holds at the first interaction, and text questions are often insufficient for resolving fine-grained visual differences such as appearance, attributes, or viewpoint. We propose CLARA, a clarification framework that resolves ambiguity by showing users a small panel of visual alternatives. Instead of answering text questions, the user simply selects the prototype image closest to the intended target. This provides a direct visual signal and avoids relying on a model to predict the user's answer. To maintain valid conformal guarantees across multiple interaction rounds, CLARA reweights calibration using the likelihood ratio induced by the user's selection. The displayed prototypes are also constrained to represent the current candidate set and are snapped to real corpus images, ensuring that generated images cannot artificially improve coverage. Experiments on open-domain and fashion benchmarks show that CLARA matches single-turn state-of-the-art retrieval performance, maintains nominal coverage across interaction rounds, and finds the intended target in fewer rounds than strong text-question baselines. Its advantage is especially clear when ambiguity involves viewpoint or fine-grained attributes, where visual clarification is more effective than textual questioning.","authors":["Amsisan Tran","Baogh Le","Tuan Kiet Pham","Sui Yang Guang"],"published":"2026-06-17T12:13:57Z","updated":"2026-06-17T12:13:57Z","abstract_url":"https://arxiv.org/abs/2606.18992v1","html_url":"https://arxiv.org/html/2606.18992v1","pdf_url":"https://arxiv.org/pdf/2606.18992v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18974v1","title":"Visual-OPSD: Cross-Modal On-Policy Self-Distillation for Efficient Unified Multimodal Reasoning","abstract":"Unified multimodal models (UMMs) interleave generated ''visual thoughts'' (VTs) with text reasoning to improve spatial tasks. This incurs roughly an order-of-magnitude inference cost from multi-step diffusion. We find this cost yields limited direct benefit. On ThinkMorph, removing or noising VTs barely changes accuracy across nine benchmarks. Once rendered, attention concentrates on the VT regardless of content. Yet a KL diagnostic shows that conditioning on a privileged VT trace shifts the model's completion distribution. This suggests the generation pathway encodes useful reasoning beyond the rendered pixels. Motivated by this gap, we propose Visual On-Policy Self-Distillation(Visual-OPSD). Teacher and student share identical weights but differ in context: the teacher sees privileged VTs while the student sees only the question. Token-level JSD distillation on on-policy student trajectories transfers the teacher's reasoning to a text-only student. Across nine benchmarks, Visual-OPSD improves over its generative teacher by $+3.40$pp with $14.3\\times$ speedup (10.0s vs. 142.8s per sample) and outperforms same-scale VLMs by $+63.83$pp on VSP. A Gaussian-noise control ($+0.40$pp vs. $+10.28$pp for real VTs) and $58.4\\%$ closure of the KL gap confirm that gains come from the semantic content of the generation pathway.","authors":["Pengyu Li","Zhitao Gao","Lingling Zhang","Muye Huang","Yuanming Li","Fangzhi Xu","Jun Liu"],"published":"2026-06-17T11:59:15Z","updated":"2026-06-17T11:59:15Z","abstract_url":"https://arxiv.org/abs/2606.18974v1","html_url":"https://arxiv.org/html/2606.18974v1","pdf_url":"https://arxiv.org/pdf/2606.18974v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18960v1","title":"Mem-World: Memory-Augmented Action-Conditioned World Models for Persistent Robot Manipulation","abstract":"Action-conditioned world models have emerged as a promising paradigm for robot learning, offering a scalable alternative to costly real-world experimentation by generating action-consistent video rollouts. However, persistent world modeling remains challenging in manipulation: frequent end-effector occlusions and rapid wrist-camera motion make the current observation insufficient for predicting future views, causing models to forget or hallucinate scene details seen in earlier frames. Existing memory retrieval strategies often fail to identify informative history in dynamic manipulation scenarios. To address this limitation, we propose Mem-World, a memory-augmented multi-view action-conditioned world model. At its core, we present W-VMem, a 4D wrist-view-centered surfel-indexed memory that anchors historical observations to temporally evolving surface elements. By explicitly modeling when and where scene elements are observed, W-VMem enables geometry-aware retrieval of relevant history frames conditioned on future actions. During generation, relevant history frames are selected via surfel-based rendering and scoring, providing informative and non-redundant context for prediction. Extensive experiments show that Mem-World generates persistent rollouts in complex manipulation scenarios, enables more reliable policy evaluation than Ctrl-World, improving the Pearson correlation with real-world performance by 14.5\\%, and supports effective policy improvement through synthetic data generation, increasing success rates from 58\\% to 72\\% on long-horizon tasks.","authors":["Zirui Zheng","Jiaqian Yu","Xiongfeng Peng","jun shi","Mingyi Li","Chao Zhang","Weiming Li","Dong Wang","Huchuan Lu","Xu Jia"],"published":"2026-06-17T11:42:00Z","updated":"2026-06-17T11:42:00Z","abstract_url":"https://arxiv.org/abs/2606.18960v1","html_url":"https://arxiv.org/html/2606.18960v1","pdf_url":"https://arxiv.org/pdf/2606.18960v1.pdf","matched_keywords":["video","retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18955v1","title":"Motion-Focused Latent Action Enables Cross-Embodiment VLA Training from Human EgoVideos","abstract":"Training generalist Vision-Language-Action(VLA) models typically requires massive, diverse robotic datasets with high-fidelity action annotations. While egocentric human manipulation videos are abundant and capture significant environmental diversity, the absence of action labels makes them difficult to use in conventional training paradigms. To address this, we propose a latent-action-based framework designed to extract general action priors from unlabeled human videos. The architecture features a Hybrid Disentangled VQ-VAE that decouples motion dynamics from environmental backgrounds through physical masks, enabling the construction of a cross-embodiment action codebook. By pre-training on human videos with the codebook, the VLM backbone learns deep representations of action intent. For adaptation to specific embodiments, we introduce an intent-perception decoupling strategy where the VLM predicts the action intent while a separate frozen visual encoder provides state-specific features to the action expert, thereby reducing action hallucinations. Results in simulation and real-world environments show that our method, pre-trained exclusively on unlabeled human videos, performs competitively with state-of-the-art VLA models trained on massive annotated datasets, requiring only 50 trajectories for downstream adaptation.","authors":["Runze Xu","Yiluo Zhang","Jian Wang","Yu Wang","Jincheng Yu"],"published":"2026-06-17T11:37:59Z","updated":"2026-06-17T11:37:59Z","abstract_url":"https://arxiv.org/abs/2606.18955v1","html_url":"https://arxiv.org/html/2606.18955v1","pdf_url":"https://arxiv.org/pdf/2606.18955v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18943v1","title":"Physics-IQ Verified","abstract":"Video generative models ( VGMs) have become a new frontier that can be used not just for video generation but for a multitude of downstream tasks, including world modeling. To advance these tasks, a good video model must understand the physical reality of the world. Evaluating this understanding is an emerging field and has led to the Physics-IQ benchmark, which quantifies this explicitly by comparing model-generated videos to real-world videos of physical experiments. In this work, we present a systematic audit of the Physics-IQ benchmark, expose shortcomings and propose three solutions that sharpen how we can measure physical understanding of VGMs. Specifically, we improve prompt and ground-truth quality to reduce the influence of confounding factors and further introduce a sample-level scoring system that weights each sample and metric equally. Our resulting benchmark, Physics-IQ Verified, refines 57.6\\% of all samples and improves over 34.8\\% of prompts. In a comparison study using six image-to-video generative models, we observe moderate but meaningful ranking changes (Kendall's $τ= 0.46$). We hope Physics-IQ Verified advances the community by providing a more reliable signal toward physically accurate VGMs. The code for the benchmark can be accessed at https://github.com/google-deepmind/physics-iq-benchmark","authors":["Tim Rädsch","Yuki M Asano","Hilde Kuehne","Stefan Bauer","Priyank Jaini","Robert Geirhos","Carsten T. Lüth"],"published":"2026-06-17T11:23:52Z","updated":"2026-06-17T11:23:52Z","abstract_url":"https://arxiv.org/abs/2606.18943v1","html_url":"https://arxiv.org/html/2606.18943v1","pdf_url":"https://arxiv.org/pdf/2606.18943v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18906v1","title":"BindEdit: Taming Attention Leakage for Precise Multi-Object Image Editing","abstract":"Real image editing enables precise manipulation of visual content, yet existing methods often fail in complex multi-object scenarios, causing semantic blending, object duplication, or incomplete edits. We attribute these failures to attention leakage, where signals across spatial regions and text tokens become entangled during the denoising process. Specifically, we identify two distinct forms of leakage: Edit-Token Leakage, where ambiguous token-region alignment leads to object blending, and Source Dominance Leakage, where tokens of unchanged source objects overwhelm the attention intended for target entities. To resolve these leakages, we propose \\textbf{BindEdit}, which enforces attention-level constraints within a single diffusion trajectory. To suppress Edit-Token Leakage, BindEdit jointly regularizes cross- and self-attention so that each target token group is bound to its corresponding spatial region while maintaining instance-level separation. To suppress Source Dominance Leakage, a cross-attention re-balancing mechanism amplifies target token influence and attenuates residual source semantics within editable regions. Moreover, a region fidelity term ensures that each target concept is expressed coherently across the entire editing mask. Additionally, we propose a comprehensive multi-object benchmark encompassing diverse object counts and categories. Extensive experiments demonstrate that BindEdit consistently outperforms existing methods within a single diffusion trajectory, maintaining robust performance across both single- and multi-object editing scenarios.","authors":["Chaewon Park","Soyoon Lee","Naeun Lee","Minjung Shin","Seogkyu Jeon","Kibeom Hong"],"published":"2026-06-17T10:32:14Z","updated":"2026-06-17T10:32:14Z","abstract_url":"https://arxiv.org/abs/2606.18906v1","html_url":"https://arxiv.org/html/2606.18906v1","pdf_url":"https://arxiv.org/pdf/2606.18906v1.pdf","matched_keywords":["instance","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18894v1","title":"Automatic ply-specific analyses of CFRP micrographs using shortest-path-based ply distinction","abstract":"We present an automated approach to distinguish between ply instances in semantic segmentation masks of high-resolution carbon-fiber reinforced polymer micrographs. Interpreting the segmentation mask as a graph with pixels as vertices, enables us to use a shortest-path algorithm yielding the ply-separating paths. Thereby, we bridge the gap between semantic segmentation and ply instance segmentation using global information. We successfully apply our approach on high-resolution micrographs featuring a broad range of characteristics like artificially added gaps in single or multiple plies, different stacking sequences and ply traversing cracks. Assigning each fiber pixel to a ply based on the calculated paths, allows for a comprehensive, quantitative ply analysis with respect to its microstructural properties like the local fiber volume fraction as well as locally resolved ply and interleaf layer thickness. These insights help to reveal manufacturing-induced inhomogeneities, draw conclusions on manufacturing parameters and link mechanical properties to underlying microstructural imperfections.","authors":["Jonas Naumann","Jonas P. Appels","Julius Biermann","Christopher Gorsky","Timo de Wolff","Christoph Brauer"],"published":"2026-06-17T10:12:21Z","updated":"2026-06-17T10:12:21Z","abstract_url":"https://arxiv.org/abs/2606.18894v1","html_url":"https://arxiv.org/html/2606.18894v1","pdf_url":"https://arxiv.org/pdf/2606.18894v1.pdf","matched_keywords":["instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18886v1","title":"DINO-Med3D: Bridging Dimension and Domain Gaps in Volumetric Segmentation via Progressive Adaptation","abstract":"Although DINOv3 has demonstrated remarkable semantic discrimination in natural imagery, its direct application to volumetric medical segmentation is hindered by inherent dimension and domain disparities. To resolve these issues, we propose DINO-Med3D, a two-stage progressive framework that repurpose the pre-trained DINOv3 encoder for 3D medical tasks. In the first stage, we mitigate the dimension gap by introducing a multi-slice embedding module that incorporates pseudo-3D context, while simultaneously employing a segmentation proxy task to adapt representations learned from natural scenes to the medical domain. Subsequently, we further enhance volumetric understanding by adding lightweight 3D adapters into the frozen backbone to enforce global inter-slice continuity. Finally, to compensate for the spatial information loss inherent in the embedding process, we design a parallel detail recovery stream to explicitly preserve high-frequency boundary cues. Extensive experiments on five public datasets demonstrate that our approach successfully adapts DINOv3 to the medical domain and significantly outperforms state-of-the-art baselines.","authors":["Haoyu Hu","Xiyao Ma","Shiqi Liu","Linsen Zhang","Xiaoliang Xie","Xiaohu Zhou","Zeng-Guang Hou"],"published":"2026-06-17T10:04:43Z","updated":"2026-06-17T10:04:43Z","abstract_url":"https://arxiv.org/abs/2606.18886v1","html_url":"https://arxiv.org/html/2606.18886v1","pdf_url":"https://arxiv.org/pdf/2606.18886v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18885v1","title":"LARE: Low-Attention Region Encoding for Text-Image Retrieval","abstract":"Image retrieval in crowded scenes is particularly challenging due to the salience bias of conventional visual encoders, which tend to focus on dominant objects while neglecting low-attention regions that are often crucial for fine-grained retrieval. We propose LARE (Low-Attention Region Encoding), a framework that explicitly models these overlooked regions. LARE adopts a dual-encoding strategy that encodes low-attention regions of an image and the full image in parallel, leading to more diverse and informative image embeddings. To evaluate image retrieval performance in challenging crowded scenes, we introduce Dense-Set, a challenging subset derived from COCO and Flickr30K. In this subset, images are re-captioned to provide richer descriptions of low-attention or previously overlooked regions. This dataset highlights the limitations of existing retrieval models and enables a more rigorous evaluation under densely crowded scene conditions. Experimental results demonstrate that the proposed framework improves retrieval performance by preserving subtle, non-dominant visual cues within the shared latent space.","authors":["Abdulmalik Alquwayfili","Faisal Almeshal","Jumanah Almajnouni","Leena Alotaibi","Faisal Alhajari","Mohammed Alkhrashi","Alreem Almuhrij","Abdullah Aldwyish","Raied Aljadaany","Huda Alamri","Muhammad Kamran J. Khan"],"published":"2026-06-17T10:00:33Z","updated":"2026-06-17T10:00:33Z","abstract_url":"https://arxiv.org/abs/2606.18885v1","html_url":"https://arxiv.org/html/2606.18885v1","pdf_url":"https://arxiv.org/pdf/2606.18885v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18884v1","title":"Performance Gap Analysis between Latin and Arabic Scripts HTR","abstract":"Recent studies have shown that handwritten text recognition (HTR) systems perform worse on Arabic-script datasets than on Latin-script data. However, the reasons for this gap are still not well understood due to the lack of controlled comparisons. In this work, we present a comprehensive study of Arabic and Latin scripts HTR using a unified CRNN model for line-level HTR across nine datasets (including KHATT (Arabic), Muharaf (Arabic), NUST-UHWR (Urdu), PHTD (Persian), IAM (English), READ-2016 (German), and others) and di ferent training sizes (K in {100, 500, 1000, 2000, ..., Kfull}). Our results show the performance gap remains: it is large in low-resource settings, decreases with more data, but remains even at full scale, with a consistent difference of 5-7 CER points. We show that annotation quality matters, as many datasets contain labeling errors. Cleaning reduces error rates and narrows the gap, but does not eliminate it. In addition, we find that a fixed number of training samples provides less effective coverage in Arabic due to higher visual variability, requiring more data to learn similar representations. We compare recognition across datasets in terms of the number of text lines and the number of characters, showing an equivalence trade-off. We compare character frequency distributions across scripts and show that Arabic is significantly more heavy-tailed than Latin. Our error analysis reveals that around 30 percent of substitution errors in Arabic datasets (e.g., KHATT) are caused by confusion between visually similar characters, compared to about 15 percent in Latin-script datasets such as IAM.","authors":["Sana Al-azzawi","Elisa Barney","Marcus Liwicki"],"published":"2026-06-17T10:00:22Z","updated":"2026-06-17T10:00:22Z","abstract_url":"https://arxiv.org/abs/2606.18884v1","html_url":"https://arxiv.org/html/2606.18884v1","pdf_url":"https://arxiv.org/pdf/2606.18884v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18872v1","title":"Bridging Single Distortion Artifacts and Mmultifactorial Clinical Quality: Few-shot Biparametric MRI Quality Assessment via Distortion-trained Prototypical Networks","abstract":"Clinical prostate multi-parametric MRI relies heavily on high-quality diffusion-weighted imaging (DWI), yet reading DWI is frequently compromised by geometric distortion, often caused by rectal air. Assessing quality via the PI-QUAL scoring system is an emerging clinical standard, but it is subjective, time-consuming and suffers from a class imbalance where low-quality cases are diverse and relatively scarce. Using the PRIME clinical trial as an example, there are $6\\%$ images with PI-QUAL scores lower than 4, $87\\%$ of DWI issues are due to distortion. Many of the other clinical quality issues are under-represented. To address this common dual-scarcity of annotated clinical data, we propose a few-shot biparametric prototypical network for automated image quality assessment (IQA). Our framework utilizes a dual-branch 3D ResNet to fuse T2-weighted and DWI features, providing anatomical context to distinguish true morphology from distortion. To handle real-world heterogeneity, we introduce feature-wise linear modulation (FiLM) and a gradient reversal layer (GRL) to align feature distributions conditioned on varying b-values while suppressing acquisition-related biases. We demonstrate that a model meta-trained solely on comparatively objective, readily obtainable distortion labels can effectively adapt to predicting complex, multi-factorial clinical quality scores such as PI-QUAL using only five representative samples. Experimental results on two datasets show that our method significantly outperforms few-shot learning baselines for this challenging IQA task, offering a practically feasible and data-efficient solution for standardizing prostate MRI quality control in clinical workflows.","authors":["Yuheng Tang","Alexander Ng","Wen Yan","Natasha Thorley","Pawel Rajwa","Yipei Wang","Aqua Asif","Clare Allen","Louise Dickinson","Francesco Giganti","Shonit Punwani","Daniel Alexander","Veeru Kasivisvanathan","Yipeng Hu"],"published":"2026-06-17T09:50:45Z","updated":"2026-06-17T09:50:45Z","abstract_url":"https://arxiv.org/abs/2606.18872v1","html_url":"https://arxiv.org/html/2606.18872v1","pdf_url":"https://arxiv.org/pdf/2606.18872v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18869v1","title":"Learning to Distort: Weakly-Supervised Image Quality Transfer for Prostate DWI Correction","abstract":"Single-shot echo-planar prostate diffusion-weighted imaging (DWI) is frequently complicated by geometric distortions, which impact the ability to derive reliable diagnoses from such images. Developing automated correction methods is challenged by the absence of paired distorted and undistorted clinical scans. In this paper, we first propose a novel weakly-supervised image quality transfer (IQT) framework from undistorted to distorted images that utilizes image quality assessment (IQA) signals to supervise the transfer process. Unlike traditional methods that require expensive, voxel-wise paired data or resort to developing unpaired algorithms, our approach utilizes image-level quality labels (here, distorted vs. undistorted) to establish latent quality prototypes within a pre-trained feature space. Recognizing that simulating realistic distortions is more reliable than direct unpaired correction, we describe a weakly-supervised prototype flow matching algorithm to explicitly regularize generative trajectories towards distorted prototypes, producing realistic susceptibility artifacts that mimic clinical degradations. By synthesizing these realistic pairs, we enable a second IQT model to be trained in the forward direction for distortion correction. Experimental results demonstrate that our generated images successfully mimic the diagnostic interference of real-world artifacts, which leads to more capable distortion correction IQT models. In addition to qualitative comparisons, we also conduct exhaustive quantitative evaluations that compare our approach with existing unpaired approaches (e.g., CycleGAN, UNIT-DDPM, and OT-FM) - as either forward or reverse alternatives - by assessing clinical downstream task performance in PI-RADS and Gleason score classification, using both in-distribution and external data sets.","authors":["YuCheng Tang","Wen Yan","Alexander Ng","Natasha Thorley","Pawel Rajwa","Yipei Wang","Aqua Asif","Clare Allen","Louise Dickinson","Francesco Giganti","David Atkinson","Shonit Punwani","Daniel Alexander","Shaheer Ullah Saeed","Veeru Kasivisvanathan","Yipeng Hu"],"published":"2026-06-17T09:47:53Z","updated":"2026-06-17T09:47:53Z","abstract_url":"https://arxiv.org/abs/2606.18869v1","html_url":"https://arxiv.org/html/2606.18869v1","pdf_url":"https://arxiv.org/pdf/2606.18869v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18846v1","title":"From Bounding Boxes to Visual Reasoning: An On-Policy Data Annotation Tool for Vision-Language Models","abstract":"Vision-language models (VLMs) are rapidly advancing toward sophisticated grounded structured visual reasoning. Training models for such advanced capabilities demands a new genre of data that seamlessly unifies spatial coordinates, open-vocabulary descriptions, structured attributes, and topological relationships into a singular representation. However, existing data annotation tools fundamentally fail to meet these intricate demands, suffering from three systematic bottlenecks: limited expressiveness, severe annotation-training decoupling, and poor data reusability. To bridge this infrastructure gap, we introduce an open-source annotation tool, ScreenAnnotator. First, we define a unified annotation atom schema that binds spatial, semantic, and structural primitives into a single unit. Second, we implement an on-policy annotation loop embedded with a Bayesian Annotation Verifier (BAV). Finally, we design a template-driven multi-task data synthesis process dynamically transforms static atoms into diverse multi-dimensional reasoning tasks, eliminating redundant re-annotation. The on-policy loop drives the annotation accept rate to nearly 100% on flowcharts and 77% on GUI screenshots, while steadily reducing per-image annotation time as labeled data accumulate. In the flowchart scenario, fine-tuning a VLM yields 76.1% average accuracy, which is a 35.1% point absolute gain. Our code is available at: https://github.com/WnQinm/Annotator.","authors":["Like Zhang","Runliang Niu","Shiqi Wang","Xiyu Hu","Qianli Xing","Pan Wang","Qingzu He","Qi Wang"],"published":"2026-06-17T09:25:59Z","updated":"2026-06-17T09:25:59Z","abstract_url":"https://arxiv.org/abs/2606.18846v1","html_url":"https://arxiv.org/html/2606.18846v1","pdf_url":"https://arxiv.org/pdf/2606.18846v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18841v1","title":"Rethinking Air-Ground Collaboration: A Progressive Cross-Task Benchmark and Socialized Learning Framework","abstract":"Air-ground collaborative perception is crucial for robust visual understanding in real-world dynamic environments. However, existing studies typically formulate collaboration as single-task cross-view fusion, overlooking the functional dependencies among localization, target association, and fine-grained parsing. In addition, the heterogeneous nature of aerial and ground views introduces substantial geometric, scale, and occlusion discrepancies, making uniform feature sharing vulnerable to negative transfer. To tackle these issues, we model air-ground perception as a progressive cross-task collaboration task and construct the Air-Ground Progressive Collaboration (AGPC) benchmark, a spatio-temporally aligned benchmark comprising more than 745K raw video frames. Built upon this benchmark, we propose Socialized Co-Perception (SCP), a coarse-to-fine framework that organizes collaboration progressively from aerial global localization to ground target association and identity-aware parsing. Its core module, the Dual-Layer Router (DLR), decouples input-side multi-scale expert selection from output-side task-conditioned modulation, enabling selective cross-view and cross-task interaction while suppressing harmful interference. Extensive experiments demonstrate the effectiveness of SCP. It achieves a 3.73\\% coevolutionary gain and a 7.86\\% improvement in average downstream performance. These results show that task-conditioned collaboration is more effective than uniform fusion for heterogeneous air-ground perception. The code is available at https://github.com/g1136639260-spec/AGSCP.","authors":["Zhoupeng Guo","Yunqi Zhu","Zhihe Fan","Xinjie Yao","Ruipu Zhao","Boan Tao","Yiming Sun","Zhen Wang","Pengfei Zhu"],"published":"2026-06-17T09:17:55Z","updated":"2026-06-17T09:17:55Z","abstract_url":"https://arxiv.org/abs/2606.18841v1","html_url":"https://arxiv.org/html/2606.18841v1","pdf_url":"https://arxiv.org/pdf/2606.18841v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18826v1","title":"EDoF-NeRF: extended depth-of-field neural radiance fields using a coded aperture camera","abstract":"We propose a method for extending the depth-of-field (DoF) to construct high-fidelity neural radiance fields (NeRF) -- an emerging technique for rendering photorealistic novel views from a dataset of images captured at different viewpoints, based on implicit neural representations. The trade-off between DoF and light quantity is inherent not only in conventional cameras but also in NeRF, since the datasets used by NeRF are captured by these cameras. To address this issue, we introduce a coded aperture placed at the camera pupil, preserving spatial frequency components under defocused conditions. We develop a camera model incorporating coded apertures into NeRF, allowing direct input of coded images and enabling the generation of novel views with an extended DoF. We validate the proposed method, termed extended DoF-NeRF (EDoF-NeRF), through simulations and experiments, demonstrating its superior performance compared to conventional aperture cameras.","authors":["Yoshiyuki Shirasaki","Ryoichi Horisaki"],"published":"2026-06-17T08:56:50Z","updated":"2026-06-17T08:56:50Z","abstract_url":"https://arxiv.org/abs/2606.18826v1","html_url":"https://arxiv.org/html/2606.18826v1","pdf_url":"https://arxiv.org/pdf/2606.18826v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18825v1","title":"DreamReg: Belief-Driven World Model for 2D-3D Ultrasound Registration","abstract":"Ultrasound (US) is widely used for surgical navigation, yet real-time registration between intraoperative 2D slices and preoperative 3D volumes remains challenging due to partial observability, speckle noise, and the action-dependent US acquisition. Existing methods are one-shot or short-horizon, making it hard for them to gather evidence over time or capture how surgeons adjust probe motion based on on-screen feedback. We propose DreamReg, a belief-driven world-model framework that formulates 2D-3D registration as belief updating over rigid transformations. DreamReg maintains a latent belief state that summarizes past observations and poses information, and continuously refines the transformation through learned dynamics as new slices arrive. During training, DreamReg is exposed to probe-motion trajectories that mimic clinical scanning behavior and learns to update its belief by conditioning pose refinement on the current US observation. During inference, DreamReg refines registration via internal imagination: it rolls out the learned world model to simulate candidate probe motions and their predicted observations, and integrates these imagined outcomes to converge to an accurate rigid transformation. Experiments on CAMUS and u-RegPro datasets demonstrate improved robustness and competitive registration accuracy for real-time guidance compared with state-of-the-art methods.","authors":["Luoyao Kang","Yuelin Zhang","Jiwei Shan","Haifan Gong","Qingpeng Ding","Shing Shin Cheng"],"published":"2026-06-17T08:56:03Z","updated":"2026-06-17T08:56:03Z","abstract_url":"https://arxiv.org/abs/2606.18825v1","html_url":"https://arxiv.org/html/2606.18825v1","pdf_url":"https://arxiv.org/pdf/2606.18825v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18824v1","title":"Where Will They Go? Modelling Multimodal Pedestrian Manoeuvres from Ego-centric Videos","abstract":"Pedestrian trajectory prediction from an ego-centric camera is challenging since it depends on complex interactions with vehicles and scene context, as well as the intention of the pedestrian. By modelling correlation and intent from the historical and future trajectories of the pedestrian, it will usually result in a multimodal (i.e. multiple modes) distribution. Existing stochastic predictors often sample multiple futures from a single unimodal distribution, which can yield sub-optimal 'mixed-mode' trajectories that lie between distinct motion patterns and become implausible in real scenes. In this paper, we propose MMPM, a mode-aware framework that separately models future trajectory distributions into semantically meaningful modes based on the pedestrian's crossing behavior. MMPM consists of two modules: behavior-aware Pedestrian Interaction Module (PIM) that jointly captures pedestrian-vehicle and pedestrian-environment interactions by introducing gaze, head and hand gesture, and a CVAE-based Mode-aware Trajectory Predictor (MTP) module to model the future trajectory distributions on two modes, crossing and non-crossing the road, separately. A query-based decoder further enforces mode consistency during decoding. Experiments on PIE and JAAD datasets show that our method surpasses state-of-the-art baselines. Our proposed MTP is model-agnostic, which can be integrated into existing frameworks such as BiTrap-NP and SGNet-ED to further improve future trajectory prediction performance. We additionally introduce a data-driven validation protocol that matches predictions to spatio-temporally consistent ground-truth trajectories, demonstrating improved frame-wise displacement errors over previous work.","authors":["Yuxuan Xie","Nicolas Pugeault","Chongfeng Wei","Hubert P. H. Shum","Edmond S. L. Ho"],"published":"2026-06-17T08:55:01Z","updated":"2026-06-17T08:55:01Z","abstract_url":"https://arxiv.org/abs/2606.18824v1","html_url":"https://arxiv.org/html/2606.18824v1","pdf_url":"https://arxiv.org/pdf/2606.18824v1.pdf","matched_keywords":["video","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18788v1","title":"HandwritingAgent: Language-Driven Handwriting Synthesis in Scalable Vector Space","abstract":"Teaching machines to emulate natural handwriting styles remains an open challenge, as it requires synthesizing stroke sequences that dynamically vary in shape, texture, pressure and script - not only across individuals, but also within a single person's handwriting. Attempts at this challenge have largely explored deep learning methods in both online and offline settings. However, these approaches are often constrained by style-specific architectural choices, heavy reliance on large datasets, high compute costs, and a lack of flexible control over writing styles through natural language. To this end, we introduce HandwritingAgent, a language-driven agent that can synthesize natural handwriting sequences directly in Scalable Vector Graphics (SVG) format with no need for style-specific training. The agent leverages a large reasoning model to geometrically analyse and autoregressively generate target handwritten glyphs as stroke sequences in a discrete grid canvas environment. Generation is conditioned on texts provided in either conversational or non-conversational mode, along with a reference handwriting-style image. Experiments on diverse handwriting tasks spanning imitation, recognition, multi-lingual handwriting synthesis, and generation of complex handwritten maths and science expressions indicate substantial improvement in performance, with HandwritingAgent matching or surpassing state-of-the-art generative handwriting models, while providing a more efficient, controllable, and generalizable synthesis method.","authors":["Jaward Sesay","Yue Yu","Börje F. Karlsson"],"published":"2026-06-17T08:02:19Z","updated":"2026-06-17T08:02:19Z","abstract_url":"https://arxiv.org/abs/2606.18788v1","html_url":"https://arxiv.org/html/2606.18788v1","pdf_url":"https://arxiv.org/pdf/2606.18788v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18787v1","title":"Learned Radius Estimation for UDF-Based Point Cloud Reconstruction","abstract":"Surface reconstruction from point clouds is important for consumer-grade 3D capture, including AR/VR and indoor scanning. Local-patch Unsigned Distance Field (UDF) methods are lightweight and generalizable, but their accuracy depends on the support radius, traditionally fixed or selected by a one-dimensional curvature heuristic that cannot capture heterogeneous local geometry. We propose a learned per-query radius selector that predicts a continuous support radius and plugs into a frozen LoSF-UDF backbone. The selector is trained using off-grid target radii obtained by parabolic interpolation of cached UDF error curves. Experiments show improved fine-scale reconstruction accuracy.","authors":["Eito Ogawa","Hiroshi Watanabe"],"published":"2026-06-17T07:59:18Z","updated":"2026-06-17T07:59:18Z","abstract_url":"https://arxiv.org/abs/2606.18787v1","html_url":"https://arxiv.org/html/2606.18787v1","pdf_url":"https://arxiv.org/pdf/2606.18787v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18780v1","title":"SAMA: Semantic Anchor-aligned Augmentation for Unified Low-Resource Multimodal Information Extraction","abstract":"Multimodal Information Extraction (MIE)-covering tasks such as Multimodal Named Entity Recognition (MNER), Relation Extraction (MRE), and Event Extraction (MEE)-is essential for understanding multimedia content but remains constrained by severe data scarcity. Although data augmentation is a promising remedy, existing approaches are impeded by coarse cross-modal alignment and fragmented, task-specific designs that fail to exploit shared semantic knowledge. To overcome these limitations, we introduce Semantic Anchor-aligned Multimodal Augmentation (SAMA), a unified framework for generating high-fidelity, task-aware synthetic data. SAMA constructs structured semantic anchors from ground-truth labels to guide a Collaborative Multi-Experts Multimodal Large Language Model (CME-MLLM), which integrates a Universal Adapter for shared semantics with Task-Specific Adapters to produce diverse yet constraint-compliant textual samples. For image synthesis, SAMA employs an Anchor-Preserving Diffusion mechanism that uses anchor-weighted prompts and latent conditioning to maintain critical semantic anchors while diversifying visual contexts. To eliminate the need for manual verification, SAMA further introduces a Dual-Constraint Filtering module that selects synthetic samples based on both cross-modal consistency and anchor fidelity. Extensive experiments across benchmark datasets for MNER, MRE, and MEE demonstrate that SAMA consistently outperforms state-of-the-art augmentation baselines under both fully supervised and low-resource settings, underscoring its versatility, robustness, and effectiveness.","authors":["Quanjiang Guo","Chong Mu","Jiazhou Pan","Ming Jia","Ling Tian","Hui Gao","Zhao Kang"],"published":"2026-06-17T07:43:33Z","updated":"2026-06-17T07:43:33Z","abstract_url":"https://arxiv.org/abs/2606.18780v1","html_url":"https://arxiv.org/html/2606.18780v1","pdf_url":"https://arxiv.org/pdf/2606.18780v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18765v1","title":"SpectralDiT: Timestep-Conditioned Spectral Residual Correction for Flow-Matching DiTs","abstract":"We propose SpectralDiT, a lightweight modification to flow-matching Diffusion Transformers that adds timestep-conditioned spectral correction to the MLP residual branch. The module decomposes each residual update into low- and high-frequency components on the patch-token grid, then learns a zero-initialized additive gate so the model initially matches the baseline DiT. On CIFAR-10 pixel-space generation, SpectralDiT improves FID from 20.78 to 19.71 at patch size 1 and reduces the radial Fourier spectrum gap. Furthermore, we scale our method to latent diffusion on ImageNet-100. With 0.6% additional theoretical FLOPs and 1.36% additional parameters, SpectralDiT improves latent flow-matching, achieving an 8.7% relative FID reduction under classifier-free guidance (CFG 2.0). All reported results are averaged over five seeds. Ablations and gate visualizations on CIFAR-10 reveal stable block-specific spectral correction patterns.","authors":["Jiayu Tian"],"published":"2026-06-17T07:25:24Z","updated":"2026-06-17T07:25:24Z","abstract_url":"https://arxiv.org/abs/2606.18765v1","html_url":"https://arxiv.org/html/2606.18765v1","pdf_url":"https://arxiv.org/pdf/2606.18765v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18753v1","title":"SMART: A Flexible, Interpretable, and Scalable Spatio-temporal Brain Atlas from High-Resolution Imaging Data","abstract":"We introduce SMART, a framework for learning a flexible, interpretable, and scalable spatio-temporal brain atlas from longitudinal high-resolution 3D medical images. Existing approaches to spatio-temporal atlas construction rely on black-box generative models that lack flexibility, limit interpretability, and struggle to scale to high-dimensional data. SMART addresses these challenges by learning a continuous disease-time atlas that decouples global group-wise disease dynamics from their patient-specific anatomical manifestation. Guided by anatomically inspired priors, SMART models interpretable global trajectories of regional progression along a shared disease timeline through region-specific differential equations. Global trajectories are further personalized to individual anatomies via dense diffeomorphic displacements parameterized by a flexible and scalable multi-scale Neural Cellular Automata. Evaluated on five longitudinal MRI datasets in Alzheimer's disease (ADNI-1/GO/2, OASIS-3, AIBL; > 1,300 subjects), SMART produces anatomically meaningful predictions of disease progression and achieves state-of-the-art forecasting accuracy and improved temporal consistency over adversarial and diffusion baselines. Our approach establishes a new paradigm for flexible, interpretable, and scalable modeling of spatio-temporal change in high-dimensional medical image time-series.","authors":["John Kalkhof","Boris Gutman","Emile d'Angremont","Daniel C. Alexander","Marco Lorenzi"],"published":"2026-06-17T06:57:22Z","updated":"2026-06-17T06:57:22Z","abstract_url":"https://arxiv.org/abs/2606.18753v1","html_url":"https://arxiv.org/html/2606.18753v1","pdf_url":"https://arxiv.org/pdf/2606.18753v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18749v1","title":"Toward Training-Free Zero-Shot Anomaly Detection in 3D Medical Images: A Batch-Based Approach Using 2D Foundation Models","abstract":"Zero-shot anomaly detection (ZSAD) is attractive for medical imaging because clinical systems must handle heterogeneous acquisition protocols, changing patient populations, and pathologies for which annotated training data may be unavailable. Most existing zero-shot anomaly detection methods are designed for 2D images, and their direct extension to 3D medical volumes is limited by the scarcity of large-scale volumetric foundation models or by the difficulty of utilizing volumetric context. We propose CS3F, a training-free batch-based framework for ZSAD in 3D medical images using 2D foundation models. Each volume is decomposed along multiple anatomical axes and encoded slice-wise by a 2D vision transformer. These are then converted into localized volumetric tokens by pooling neighboring slice features. Anomaly scores are obtained from cross-subject mutual similarity: tokens that lack close analogues in other subjects are assigned higher anomaly scores. To reduce the attenuation of focal lesion signals caused by depth pooling, we introduce a coarse-to-fine tokenization strategy that enables fine-resolution volumetric scoring without exhaustive matching. CS3F is evaluated on brain MRI across metastases, glioma, and stroke, as well as validated on lung CT to test generalizability beyond atlas-aligned brain MRI. The results show that frozen 2D foundation models can support anomaly localization in 3D medical images, and that the benefit of fine tokenization depends strongly on lesion contrast and imaging modality.","authors":["Tai Le-Gia"],"published":"2026-06-17T06:52:07Z","updated":"2026-06-17T06:52:07Z","abstract_url":"https://arxiv.org/abs/2606.18749v1","html_url":"https://arxiv.org/html/2606.18749v1","pdf_url":"https://arxiv.org/pdf/2606.18749v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18732v1","title":"Low-Cost Neuromorphic Fall Detection Using Synthetic Event Data and Hybrid SNNs","abstract":"This work presents the development of hybrid models that integrate spiking neural networks (SNNs) with components of convolutional neural networks (CNNs) to learn from simulated event-based camera data (Dynamic Vision Sensor, DVS) generated from conventional smartphone videos. Aimed primarily at human fall detection, the approach leverages the energy efficiency and spatio-temporal processing capabilities of SNNs by converting video frames into event-based data. The proposed models are evaluated through simulations on multiple datasets, comparing their performance to that of traditional machine learning models. Results demonstrate significant gains in efficiency without sacrificing accuracy, underscoring the potential of combining SNNs and DVS technology for complex tasks in real-world environments.","authors":["Guillermo Rojas","Gonzalo Soto","Daniel Yunge"],"published":"2026-06-17T06:21:13Z","updated":"2026-06-17T06:21:13Z","abstract_url":"https://arxiv.org/abs/2606.18732v1","html_url":"https://arxiv.org/html/2606.18732v1","pdf_url":"https://arxiv.org/pdf/2606.18732v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18702v1","title":"UniTemp: Unlocking Video Generation in Any Temporal Order via Bidirectional Distillation","abstract":"Autoregressive video diffusion models have emerged as a promising approach for long video generation, achieving strong performance in streaming settings. However, existing methods are restricted to forward temporal generation, whereas practical video creation often requires flexible generation order, e.g., conditioning on future context to extend backward, or on both past and future context for inbetween generation. We bridge this gap by training an autoregressive model that supports generation in arbitrary temporal directions. A key technical challenge arises from the Causal 3D VAE widely used in video diffusion models, which encodes latents strictly conditioned on past context. While suited for forward generation, this causal structure causes inter-block discontinuities when generation proceeds backward. To address this, we introduce blockwise anchor latents, a set of auxiliary latents that restore the missing past context at block boundaries during backward generation. Built on this design, we propose UniTemp, a bidirectional distillation framework that trains a single autoregressive student model for any-direction video generation. At inference time, UniTemp conditions on arbitrary past and/or future frames, improving controllability for both bidirectional and inbetween generation. Experiments show that UniTemp maintains competitive performance on short and long video generation compared to forward-only methods, while enabling diverse workflows such as bidirectional video extension, inbetween generation, looping video generation, scene transition, and visual story generation. Project website: https://lzhangbj.github.io/projects/unitemp/","authors":["Lin Zhang","Sicheng Mo","Zefan Cai","Jinhong Lin","Zihao Lin","Jiuxiang Gu","Krishna Kumar Singh","Yuheng Li","Yin Li"],"published":"2026-06-17T05:27:19Z","updated":"2026-06-17T05:27:19Z","abstract_url":"https://arxiv.org/abs/2606.18702v1","html_url":"https://arxiv.org/html/2606.18702v1","pdf_url":"https://arxiv.org/pdf/2606.18702v1.pdf","matched_keywords":["video","3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18687v1","title":"Spatially Stratified Distillation for Heterogeneous Radar Place Recognition","abstract":"Scalable, all-weather place recognition increasingly relies on heterogeneous radar place recognition to bridge diverse hardware platforms. A notable application is matching queries from cost-effective 4D automotive radars against high-fidelity reference maps built by dense spinning radars. This process is fundamentally limited by the extreme sparsity (and narrow field-of-view) of the 4D sensor, which captures only a fraction of the structural density present in the spinning radar database. Prior efforts address this issue by unifying different radar signals. That is, projecting both signals into a common representational space. Yet, they suffer performance degradation in multi-session environments. In this paper, we propose spatially-stratified distillation (SSD); a strategy that replaces standard uniform distillation with an asymmetric spatial alignment derived directly from physical radar returns. In regions where both radars exhibit overlapping returns, SSD enforces strong feature alignment. Crucially, in sparse regions where the 4D student lacks returns but the teacher contains valid structure within the shared field of view, SSD applies heavily discounted distillation weights. Extensive evaluations of the recent HeRCULES dataset demonstrate that SSD significantly outperforms prior place recognition methods, achieving state-of-the-art results on its challenging dynamic sequences.","authors":["Sagun Singh Shrestha","Samuel Harding","Abdelwahed Khamis","Saimunur Rahman","Peyman Moghadam"],"published":"2026-06-17T04:55:42Z","updated":"2026-06-17T04:55:42Z","abstract_url":"https://arxiv.org/abs/2606.18687v1","html_url":"https://arxiv.org/html/2606.18687v1","pdf_url":"https://arxiv.org/pdf/2606.18687v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18681v1","title":"Moving Beyond Diversity: Visual Token Pruning as Subspace Reconstruction for Efficient VLMs","abstract":"Despite their remarkable performance, Vision Language Models (VLMs) incur substantial computational overhead due to the large number of visual tokens. While diversity maximization has become a dominant strategy for token reduction, existing methods rely on cosine-based normalized similarity that discards magnitude information, failing to faithfully approximate the original feature representation and leading to suboptimal performance, particularly on compositional multi-skill reasoning tasks. In this paper, we introduce SPARE, a subspace reconstruction method that reformulates token pruning as a column subset selection problem and explicitly minimizes reconstruction error. By iteratively selecting tokens with large projection residuals, SPARE performs reconstruction-driven pruning beyond angular diversity. Moreover, we reveal a counterintuitive anti-relevance phenomenon: tokens with lower image-text relevance score can better preserve contextual information. Based on this finding, we incorporate anti-relevance into SPARE as an additional selection criterion to promote context-aware token selection. Extensive experiments across multiple VLMs and benchmarks demonstrate that SPARE consistently achieves state-of-the-art performance, with strong gains on compositional tasks. When applied to LLaVA, SPARE removes up to 94% of visual tokens while retaining 95% of the baseline performance, all in a fully training-free manner.","authors":["Jaeyeon Lee","Shunjie Wen","Dong-Wan Choi"],"published":"2026-06-17T04:45:10Z","updated":"2026-06-17T04:45:10Z","abstract_url":"https://arxiv.org/abs/2606.18681v1","html_url":"https://arxiv.org/html/2606.18681v1","pdf_url":"https://arxiv.org/pdf/2606.18681v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18676v1","title":"InTrain: Intrinsic Trainability for Zero-Cost Neural Architecture Search","abstract":"Training-free neural architecture search promises efficient discovery of high-performance networks without costly training. However, existing zero-cost proxies rely on fragmented heuristics that fail to capture the fundamental question: what makes an architecture trainable? This paper introduces Intrinsic Trainability (InTrain), a unified theoretical proxy that formalizes trainability as an architectural invariant emerging from two synergistic components: geometric capacity and optimization resilience. We operationalize intrinsic trainability through analysis of neural information processing. Geometric capacity is quantified via the participation ratio of activation covariance eigenspectrum, capturing the effective dimensionality of representation manifolds. Optimization resilience is measured through cumulative gradient health, assessing the robustness of backpropagation across network depth. InTrain synthesizes these dimensions through a scale-invariant multiplicative coupling, which we hypothesize is essential for capturing their synergistic, non-additive relationship. Extensive experiments on standard NAS benchmarks and search spaces demonstrate that InTrain achieves ranking correlations on par with state-of-the-art ensemble-based proxies and outperforms other single-metric methods.","authors":["Qinqin Zhou","Fuhai Chen","Jipeng Wu","Zhiwei Chen","Zhikai Hu","Weiwei Cai"],"published":"2026-06-17T04:22:00Z","updated":"2026-06-17T04:22:00Z","abstract_url":"https://arxiv.org/abs/2606.18676v1","html_url":"https://arxiv.org/html/2606.18676v1","pdf_url":"https://arxiv.org/pdf/2606.18676v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18661v1","title":"LandslideAgent with Multimodal LandslideBench: A Domain-Rule-Augmented Agent for Autonomous Landslide Identification and Analysis","abstract":"Intelligent landslide hazard interpretation is critical for disaster prevention, yet current paradigms struggle to simultaneously extract visual features and high-level geoscientific semantics, while general-purpose vision-language models (VLMs) suffer from perceptual limitations and domain hallucinations in complex geological scenarios. To address these challenges, we propose an instruction-driven agentic framework comprising three components. First, LandslideBench, a multimodal fine-grained dataset with seven subtype labels, high-resolution imagery, pixel-level masks, and high-quality textual descriptions, is constructed via multi-VLM cross-validation and interactive annotation. Then, LandslideVLM, a landslide-oriented VLM, is fine-tuned via LoRA on LandslideBench to enhance geological semantic understanding. Finally, LandslideAgent, a domain rule-enhanced agent taking LandslideVLM as its cognitive backbone, employs a dual-rule controller incorporating structured report metadata constraints and cross-validation identification constraints to regulate automated tool invocation. Experiments demonstrate that LandslideBench provides effective baselines across five mainstream models on fine-grained classification and semantic segmentation. LandslideVLM achieves accuracy improvements of 10.96%, 32.87%, and 15.91% on landslide discrimination, fine-grained classification, and semantic description quality, respectively. LandslideAgent further enables autonomous multi-source spatial data inference, realizing full-process intelligence for landslide identification and analysis.","authors":["Chengfu Liu","Dongyang Hou","Junwu Xiang","Cheng Yang","Xuezhi Cui","Zeyuan Wang","Liangtian Liu","Zelang Miao"],"published":"2026-06-17T04:00:59Z","updated":"2026-06-17T04:00:59Z","abstract_url":"https://arxiv.org/abs/2606.18661v1","html_url":"https://arxiv.org/html/2606.18661v1","pdf_url":"https://arxiv.org/pdf/2606.18661v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18658v1","title":"On-Manifold Variational Learning with Heat-Kernel Priors","abstract":"Learning unsupervised representations of medical imaging cohorts can reveal clinically meaningful prototypes without expert labels, which are often noisy and fail to capture true pathological heterogeneity. However, existing deep latent-variable models estimate Gaussian mixture priors via Euclidean averaging, producing prototypes that drift off the curved data manifold and degenerate as the number of sub-populations grows. We propose a manifold-anchored variational framework built on a geometry-aware Expectation-Maximization (EM) algorithm, whose M-step selects each sub-population prototype as the graph medoid with the highest diffusion centrality on a heat-kernel-weighted latent graph, ensuring that every prototype remains on-manifold. A Dirichlet energy regularizer enforces geometric smoothness of the latent space, and a per-sub-population uncertainty score enables label-free quality assessment. \\rev{The manifold-anchored EM is a general-purpose geometric tool that extends standard EM and applies readily to other latent-variable models beyond this setting.} On cardiac scar and brain MRI benchmarks, our framework attains the highest accuracy among all compared methods, produces the sharpest prototypes reported to date, and remains stable at large sub-population counts where all baselines degenerate.","authors":["Jiarui Xing","Tal Zeevi","Nian Wu","Jian Wang"],"published":"2026-06-17T03:55:16Z","updated":"2026-06-17T03:55:16Z","abstract_url":"https://arxiv.org/abs/2606.18658v1","html_url":"https://arxiv.org/html/2606.18658v1","pdf_url":"https://arxiv.org/pdf/2606.18658v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18623v1","title":"Intrinsic 4D Gaussian Segmentation from Scene Cues","abstract":"Dynamic 4D Gaussian Splatting reconstructs deforming scenes with high fidelity and is increasingly adopted as a representation for dynamic 3D scenes. Putting such a scene to use, for editing, manipulation or motion analysis, first requires segmenting it: grouping the Gaussian primitives into coherent objects. Current pipelines obtain this grouping by importing 2D masks from foundation models such as SAM and lifting or distilling them into the Gaussian representation. In dynamic scenes these masks must be generated across many frames and views, which is costly, and the resulting segmentation can depend strongly on the quality and consistency of those external masks. We ask how much object-level structure can instead be recovered from the Gaussians themselves, and propose Intrinsic-GS, a training-free, mask-free method that builds a sparse affinity graph over Gaussian primitives from appearance, orientation, scale, deformation-trajectory and non-learned rendered-boundary cues. The graph is partitioned with Leiden community detection, requiring no foundation model and no learned feature field. On the standard 4D Gaussian segmentation benchmarks, Neu3D and HyperNeRF, Intrinsic-GS recovers substantial object structure without mask supervision, reaching 0.746 mIoU on Neu3D and 0.575 on HyperNeRF; on Neu3D, a geometry-only variant reaches 0.902 mIoU, matching SAM-supervised TRASE. On HyperNeRF, Intrinsic-GS runs 12.5x faster than the mask-generation and feature-rendering stages used by mask-supervised pipelines. These results suggest that much of the segmentation signal is already encoded in the Gaussians themselves, offering a fast, mask-free direction for 3D and 4D Gaussian segmentation that may also point toward more generalizable, robust segmentation in settings where external masks are unreliable or expensive.","authors":["Hasan Yazar","Mohamed Rayan Barhdadi","Erchin Serpedin","Mehmet Tuncel","Hasan Kurban"],"published":"2026-06-17T02:40:35Z","updated":"2026-06-17T02:40:35Z","abstract_url":"https://arxiv.org/abs/2606.18623v1","html_url":"https://arxiv.org/html/2606.18623v1","pdf_url":"https://arxiv.org/pdf/2606.18623v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18610v1","title":"SC3-Eval: Evaluating Robot Foundation Models via Self-Consistent Video Generation","abstract":"Evaluating generalist robot manipulation policies in the real world is expensive, slow, and difficult to scale. Action-conditioned video world models offer a scalable alternative by simulating policy rollouts. Autoregressive rollouts accumulate compounding errors, observations across multiple camera views must remain mutually consistent, and the evaluator must generalize to policies whose behaviors lie outside the training distribution. We address these challenges with SC3-Eval, a self-consistent video generation recipe that adapts a pre-trained video foundation model into an accurate policy evaluator by enforcing three complementary forms of consistency. First, forward-inverse dynamics consistency jointly trains the model to predict frames from actions and to recover actions from frames, anchoring generated rollouts to a physically plausible action manifold and counteracting the drift a forward-only model cannot penalize. Second, cross-view consistency trains the model to inpaint each camera view from the other, keeping the multi-camera observation coherent over long rollouts without any explicit memory mechanism. Third, test-time consistency reuses the inverse dynamics mode at inference as a per-action-chunk uncertainty signal that terminates rollouts whose generated frames drift away from the requested actions. We also demonstrate SC3-Eval rollouts reproduce the failure modes that policies exhibit in real-world rollouts, supporting fine-grained diagnostic comparison rather than aggregate ranking alone. Across seven real-world vision-language-action policies, SC3-Eval attains a closed-loop Pearson correlation of $0.929$ and MMRV of $0.119$, outperforming three strong prior video-model-based baselines, and generalizes to new tasks.","authors":["Wei-Cheng Tseng","Gashon Hussein","Yuzhu Dong","Allen Z. Ren","Lucy X. Shi","XuDong Wang","Sergey Levine","Zhaoshuo Li","Jinwei Gu","Florian Shkurti","Ming-Yu Liu","Quan Vuong"],"published":"2026-06-17T02:15:46Z","updated":"2026-06-17T02:15:46Z","abstract_url":"https://arxiv.org/abs/2606.18610v1","html_url":"https://arxiv.org/html/2606.18610v1","pdf_url":"https://arxiv.org/pdf/2606.18610v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18591v1","title":"Bridging Creative Intent and Visual Quality: Creator-Driven Recurrent Video Generation with Agentic Feedback Loops","abstract":"Generative AI has made content creation increasingly accessible, but many AI-generated videos lack narrative coherence and creative direction, issues that become more substantial at longer durations. Unlike coding, where AI generation benefits from reliable feedback and techniques such as recurrent self-improvement, video generation requires subjective feedback about plot, scenes, and narrative, which naturally motivates approaches that incorporate human creative direction. We introduce CHIEF, a human-AI co-creation video generation framework that places the creator at the center of human-in-the-loop iterative video refinement, and supports them by providing automatic subjective feedback. The creator incorporates their creative direction by driving each iteration, while their revisions are incorporated by a specialized refiner agent. The feedback loop is generated by persona-conditioned multimodal LLMs that watch generated videos and produce subjective critique from the audience perspectives, providing feedback that self-evaluation alone cannot capture. To test the effectiveness of our proposed framework, we work with high school and college students with no prior filmmaking experience to create videos, from short 1-minute videos to a complete short 10-minute film with a complicated plot.","authors":["Denis Savytski","Aiden Lei","Heding Liu","Warren Yang","Sihan Liang","Alexander Liu","Zhe Zhao"],"published":"2026-06-17T01:39:30Z","updated":"2026-06-17T01:39:30Z","abstract_url":"https://arxiv.org/abs/2606.18591v1","html_url":"https://arxiv.org/html/2606.18591v1","pdf_url":"https://arxiv.org/pdf/2606.18591v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18588v1","title":"Splaxel: Efficient Distributed Training of 3D Gaussian Splatting for Large-scale Scene Reconstruction via Pixel-level Communication","abstract":"3D Gaussian Splatting (3DGS) enables high-fidelity and real-time 3D scene reconstruction, but scaling training to large-scale scenes requires optimizing hundreds of millions of Gaussians across multiple GPUs. Existing distributed approaches either partition scenes into isolated regions, causing global inconsistency, or rely on global Gaussian-level exchanges, which lead to substantial growth in inter-GPU communication and quickly dominate iteration time. We propose Splaxel, a communication-efficient distributed 3DGS training framework based on pixel-level local rendering and global composition. Instead of synchronizing Gaussians, each GPU renders its local subset and exchanges only partial pixel values, maintaining mathematical consistency while keeping communication cost stable as the scene size increases. Splaxel further reduces pixel-level redundancy through geometric and transmittance visibility prediction and improves GPU utilization via conflict-free camera-view consolidation. Evaluated on large-scale datasets with up to 120M Gaussians, Splaxel achieves up to 7.6$\\times$ speedup over the state-of-the-art distributed 3DGS framework while preserving high reconstruction quality.","authors":["Wenqi Jia","Zhewen Hu","Ying Huang","Yu Gong","Stavros Kalafatis","Yuke Wang","Wei Niu","Chengming Zhang","Ang Li","Sheng Di","Yuede Ji","Bo Fang","Miao Yin"],"published":"2026-06-17T01:27:41Z","updated":"2026-06-17T01:27:41Z","abstract_url":"https://arxiv.org/abs/2606.18588v1","html_url":"https://arxiv.org/html/2606.18588v1","pdf_url":"https://arxiv.org/pdf/2606.18588v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18586v1","title":"APT: Atomic Physical Transitions for Causal Video-Language Understanding","abstract":"Physical events are not understood by their names alone, but by the causal state changes that compose them. A clip-level label such as \"bounce\" can be correct while hiding the process that makes the event physically valid, from support loss and contact onset to rebound and settling. To make this hidden process explicit, we introduce Atomic Physical Transitions (APTs): minimal, temporally localized state changes that bind a visible cue to an active physical mechanism and before/after dynamical regimes. An APT chain represents a video as an ordered causal transition sequence rather than a single aggregate event label: event labels tell what happened; APT chains explain why it happened. To make APTs learnable by VLMs, we construct mixed-source APT data from human annotations and simulator ground truth, covering 14 transition types across contact, gravity, friction, and rotation/stability, with 27,303 timed instances over 1,246 trials. Using this data, we find that current VLMs miss transition-level physics, with zero-shot recall at most 14% and errors dominated by missed transitions. Direct fine-tuning on APT chains improves transition detection but causes event-level forgetting, indicating that the model learns a specialized answer format rather than a reusable physical representation. We therefore propose APT-Tune, a parameter-efficient recipe that teaches VLMs to use causal transitions without forgetting how to answer video questions. It combines image-pad-aware supervision, format-conditional co-training, and mechanism-conditioned domain-to-type decoding to make APT learning format-robust and physically grounded. With only 11 M LoRA parameters on Qwen3-VL-2B, APT-Tune substantially improves APT recall while also improving event-level video transfer. These results show that APTs are not a new answer format, but a human-aligned causal supervision signal for physical video understanding.","authors":["Shang Wu","Haoran Lu","Songling Liu","Chenwei Xu","Lie Lu","Pranav Maneriker","Fan Du","Manling Li","Zhaoran Wang","Han Liu"],"published":"2026-06-17T01:26:50Z","updated":"2026-06-17T01:26:50Z","abstract_url":"https://arxiv.org/abs/2606.18586v1","html_url":"https://arxiv.org/html/2606.18586v1","pdf_url":"https://arxiv.org/pdf/2606.18586v1.pdf","matched_keywords":["video","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18583v1","title":"Aerial-ground LiDAR place recognition with patch-level self-supervised learning and expanded reciprocal re-ranking","abstract":"LiDAR place recognition determines one's position on a prior point cloud map. The most studied ground-level LiDAR place recognition suffers from pre-visit requirements, incomplete coverage, and limited perspectives. Using pre-acquired, full-coverage Airborne Laser Scanning (ALS) data as an aerial prior map overcomes these drawbacks, making cross-view place recognition necessary and advantageous. However, aerial-ground LiDAR place recognition faces significant challenges, including the domain gap between aerial and ground point clouds, and false positives during initial retrieval. To address these challenges, we present a novel retrieval and re-ranking framework for aerial-ground LiDAR place recognition. Based on the priors that neighboring point cloud patches share similar semantics with anchor patch, our retrieval network introduces patch-level self-supervised learning modules at multiple scales and integrates with scene-level learning to improve global feature discriminativeness between aerial and ground point clouds. Furthermore, leveraging the structured spatial distribution of ALS point clouds, we introduce an Expanded Reciprocal (ER) re-ranking algorithm to exploit neighborhood information maximally and refine each feature based on neighbor features, which are then used to update the similarity matrix for final ranking. Extensive experiments demonstrate that our retrieval network outperforms existing state-of-the-art (SOTA) methods, achieving a 9.8\\% improvement in average Recall@1 and a 3.2\\% improvement in average Recall@1\\% on the CS-Urban-Scenes, while also showing the best performance on the CS-Campus3D dataset. Additionally, our ER re-ranking algorithm further boosts the average Recall@1 by 4.9\\% on CS-Campus3D and 10.2\\% on CS-Urban-Scenes without additional training.","authors":["Yandi Yang","Xianghong Zou","Jianping Li","Haofeng Xie","Saurav Uprety","Hongzhou Yang","Naser El-Sheimy"],"published":"2026-06-17T01:22:27Z","updated":"2026-06-17T01:22:27Z","abstract_url":"https://arxiv.org/abs/2606.18583v1","html_url":"https://arxiv.org/html/2606.18583v1","pdf_url":"https://arxiv.org/pdf/2606.18583v1.pdf","matched_keywords":["retrieval","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18566v1","title":"Multi-Modal Hyper-Graph Fusion for Low-Light Crowd Counting","abstract":"Crowd counting is a fundamental task in computer vision. However, crowd counting in low-light environments remains largely underexplored, despite its practical importance in the real world. Existing methods mainly focus on well-lit scenes or rely on single-modality Red-Green-Blue (RGB) representations, which often become unreliable under extreme darkness and complex non-uniform illumination. To handle this problem, we construct three new low-light crowd counting benchmarks, which consist of two synthetic datasets, SHA\\_Dark and SHB\\_Dark, and a real-world benchmark LC-Crowd (Low-light Crowd Dataset). Inspired by Retinex-based physical modeling, we introduce depth and Canny edge cues as complementary geometric and structural priors to enhance the intrinsic reflectance representation under low-light conditions. We propose a Multi-Modal Hyper-Graph Fusion module, which formulates RGB appearance, depth geometry, and edge structure cues as nodes in a unified hyper-graph and explicitly captures their high-order complementary relationships via dynamic hyperedge construction and message passing. Furthermore, to adaptively allocate computation in dense prediction, we propose a Deformable Rectangular Sparse Attention (DRSA) module, which concentrates computation on informative regions through anchor-aware estimation and adaptive rectangular window modeling. Based on these designs, we develop a unified Low-Light Counting Network (LCNet) for robust low-light crowd counting. Extensive experiments on three benchmarks demonstrate that the proposed method achieves the best overall performance against existing state-of-the-art (SOTA) methods. The code is in the supplementary material. The datasets will be made public upon acceptance.","authors":["Hao-Yuan Ma","Li Zhang","Yushi Qiu","Jie Gao","Yan Zhang","Bangjun Wang"],"published":"2026-06-17T00:38:14Z","updated":"2026-06-17T00:38:14Z","abstract_url":"https://arxiv.org/abs/2606.18566v1","html_url":"https://arxiv.org/html/2606.18566v1","pdf_url":"https://arxiv.org/pdf/2606.18566v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18565v1","title":"Experimental Analysis of Neural Network-Based Image Classification on the CIFAR-10 Dataset","abstract":"An experimental investigation of neural image classification on the CIFAR-10 benchmark is presented through fully connected and convolutional network formulations. The analysis emphasizes the complete learning pipeline: image vectorization, normalization, one-hot class encoding, supervised loss minimization, learning-rate selection, mini-batch training, convolutional feature extraction, max-pooling, and validation-based generalization assessment. A convolutional architecture with six convolutional layers and three max-pooling stages is evaluated for ten training epochs using a batch size of 128 and an Adam optimizer with a learning rate of 0.001. The validation accuracy reaches approximately 74.77%, while the validation loss begins to increase after the middle of training despite continued reduction in training loss. The resulting behavior illustrates the practical difference between representation learning and memorization, and it provides a compact experimental baseline for future studies on regularization, data augmentation, deeper architectures, and reproducible image-classification education.","authors":["Necati Kagan Erkek","Emre Balci","Berkin Halay"],"published":"2026-06-17T00:35:27Z","updated":"2026-06-17T00:35:27Z","abstract_url":"https://arxiv.org/abs/2606.18565v1","html_url":"https://arxiv.org/html/2606.18565v1","pdf_url":"https://arxiv.org/pdf/2606.18565v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18558v1","title":"MolmoMotion: Forecasting Point Trajectories in 3D with Language Instruction","abstract":"Motion forecasting is central to visual intelligence: agents must anticipate how objects will move in order to plan actions, reason about physical interactions, and synthesize realistic futures. We argue that 3D points in world coordinates provide a general representation that is class-agnostic, view-stable, compact, and directly useful for downstream tasks. We formalize the task of goal-conditioned 3D point motion forecasting: given a short visual history, a set of 3D query points on an object of interest, and a language description of the intended goal, the model predicts the future 3D trajectory of each point. We introduce a full stack to study this task at scale: (1) MolmoMotion-1M is a large corpus of action-described, object-grounded 3D point trajectories annotated from 1.16M unconstrained videos; (2) PointMotionBench is a human-verified benchmark spanning 111 object categories and 61 motion types; and (3) MolmoMotion is a general motion forecasting model that supports both autoregressive coordinate prediction and flow-matching-based trajectory generation. MolmoMotion accurately predicts diverse motion patterns with different language instructions, and significantly outperforms existing motion prediction baselines on PointMotionBench. Finally, we show that the learned 3D motion prior transfers well to downstream applications: it improves training efficiency and generalization for robot manipulation, and its predicted trajectories provide effective motion guidance for generative models to synthesize videos with more realistic object motion.","authors":["Jianing Zhang","Chenhao Zheng","Yajun Yang","Max Argus","Rustin Soraki","Winson Han","Taira Anderson","Chun-Liang Li","Shuo Liu","Jiafei Duan","Zhongzheng Ren","Jieyu Zhang","Ranjay Krishna"],"published":"2026-06-17T00:19:00Z","updated":"2026-06-17T00:19:00Z","abstract_url":"https://arxiv.org/abs/2606.18558v1","html_url":"https://arxiv.org/html/2606.18558v1","pdf_url":"https://arxiv.org/pdf/2606.18558v1.pdf","matched_keywords":["video","3d","agent","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18555v1","title":"Rethinking Text-to-Image as Semantic-Aware Data Augmentation for Indoor Scene Recognition","abstract":"In the realm of computer vision, indoor image recognition presents challenges due to the intricate interplay of lighting conditions, occlusions, and diverse object arrangements within confined spaces. To address the lacks of training indoor images, we introduce a novel approach leveraging Stable Diffusion (SD) for the generation of synthetic images, which serve as a powerful data augmentation tool. The utilization of SD offers a principled framework for synthesizing diverse and realistic indoor scenes, thereby enriching the training data pool for robust indoor image recognition models. Experimental findings on the MIT Indoor Scene dataset reveal the potential of our proposed approach in enhancing the training of deep models when authentic data is limited. Furthermore, to prevent the misuse of SD synthetic images, we introduce a counter measure based on DIffusion Reconstruction Error (DIRE). The powerful DIRE presentation enables training robust classifiers only using lightweight deep models. Experiments show that our approach can perfectly recognize SD generated images with the accuracy of 100% using MobilenetV3.","authors":["Trong-Vu Hoang","Quang-Binh Nguyen","Dinh-Khoi Vo","Hoai-Danh Vo","Minh-Triet Tran","Trung-Nghia Le"],"published":"2026-06-17T00:08:56Z","updated":"2026-06-17T00:08:56Z","abstract_url":"https://arxiv.org/abs/2606.18555v1","html_url":"https://arxiv.org/html/2606.18555v1","pdf_url":"https://arxiv.org/pdf/2606.18555v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18554v1","title":"Forged Calamity: Benchmark for Cross-Domain Synthetic Disaster Detection in the Age of Diffusion","abstract":"The rapid advancement of text-to-image diffusion models has enabled the creation of highly photorealistic synthetic images that closely resemble real photographs, making it increasingly difficult to distinguish authentic content from AI-generated fabrications. This poses challenges for cybersecurity, digital forensics, and disaster response, where fake imagery of floods, fires, or earthquakes can spread misinformation or disrupt emergency operations. To address this, we introduce Forged Calamity, a benchmark dataset for synthetic disaster detection containing 30,000 images, including 6,000 real and 24,000 synthetic samples generated by four diffusion models. Comprehensive experiments across fine-tuned and zero-shot settings reveal consistent weaknesses in current forensic approaches. Fine-tuned detectors perform well in-distribution but lose up to 50\\% accuracy on unseen generators or disaster types, showing overfitting to model-specific artifacts. Zero-shot generalized detectors also struggle to maintain stable accuracy, with only limited resilience in a few representation-robust models. These findings highlight persistent generalization gaps and the urgent need for domain- and model-agnostic detection methods to ensure visual authenticity in the diffusion era.","authors":["Duc-Manh Phan","Quoc-Duy Tran","Duy-Khang Do","Anh-Tuan Vo","Hai-Dang Nguyen","Trong Le Do","Mai-Khiem Tran","Vinh-Tiep Nguyen","Tam V. Nguyen","Isao Echizen","Minh-Triet Tran","Trung-Nghia Le"],"published":"2026-06-17T00:08:35Z","updated":"2026-06-17T00:08:35Z","abstract_url":"https://arxiv.org/abs/2606.18554v1","html_url":"https://arxiv.org/html/2606.18554v1","pdf_url":"https://arxiv.org/pdf/2606.18554v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"},{"id":"2606.18553v1","title":"Hierarchical Multi-Modal Retrieval for Knowledge-Grounded News Image Captioning","abstract":"Traditional image captioning methods often struggle to generate comprehensive, context-rich descriptions, especially for details not directly observable from visual cues. To overcome this, we propose a novel retrieval-augmented image captioning framework that generates captions with deeper insights, such as object attributes, event context, and underlying significance, by leveraging external knowledge. Our approach features a hierarchical multi-modal article retrieval mechanism that moves beyond monolithic text entities. This retrieval considers article structure-aware features, including weighted textual components (e.g., headlines, body sections) and visual placement patterns, alongside multi-faceted similarity computations (content--visual, visual--visual, and discourse positioning). A subsequent contextual relevance refinement stage further enhances the retrieved information. The retrieved articles then serve as the knowledge base for caption generation: first, a VLM generates a concise image description; second, we segment relevant information from the retrieved articles based on this description; and finally, an LLM utilizes both the description and extracted knowledge to generate a comprehensive, contextually detailed caption. We participated in the ACM Multimedia EVENTA 2025 Challenge and achieved 5th place with an overall score of 0.2824 on the private test set of the OpenEvent-V1 dataset. Source code is publicly released at https://github.com/mf0212/EVENTA-Challange.","authors":["Minh-Loi Nguyen","Xuan-Vu Le","Long-Bao Nguyen","Hoang-Bach Ngo","Trung-Nghia Le"],"published":"2026-06-17T00:08:17Z","updated":"2026-06-17T00:08:17Z","abstract_url":"https://arxiv.org/abs/2606.18553v1","html_url":"https://arxiv.org/html/2606.18553v1","pdf_url":"https://arxiv.org/pdf/2606.18553v1.pdf","matched_keywords":["retrieval"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-06-18T05:51:51+00:00","last_seen_at":"2026-06-18T05:51:51+00:00"}],"tracked_paper_count":65,"storage_mode":"latest_overwrite"}};
